-- Poems batch 365
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('a302a0e8-e485-4808-9708-3d0da3febd02','客廬山道中寄中上座  其一','李彭','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','谿山軒豁逐時新，草樹欣欣雨後春。',32,'全唐诗/poet.song.80000.json','["谿山軒豁逐時新，草樹欣欣雨後春。", "弄水看山添野興，可憐魚鳥自相親。"]'),
('0939b6ce-23f6-41fe-b934-c9452a0496ba','客廬山道中寄中上座  其二','李彭','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','著行官柳拂人低，勾引風光挽客衣。',32,'全唐诗/poet.song.80000.json','["著行官柳拂人低，勾引風光挽客衣。", "正是斜川春事起，翻思戴月荷耡歸。"]'),
('2ac422ff-b011-4412-a2be-9a7526e7c910','客廬山道中寄中上座  其三','李彭','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','紫霄獨立冠遥岑，静愛雲無出岫心。',32,'全唐诗/poet.song.80000.json','["紫霄獨立冠遥岑，静愛雲無出岫心。", "見說危梁耿大壑，欲招惠遠與同尋。"]'),
('aed13fc5-ce5b-466e-9476-8d253c330d2d','顔魯公祠','李彭','宋','宋诗','song-poetry','','[]','心正能令筆不欹，銀鈎猶冠古今奇。',32,'全唐诗/poet.song.80000.json','["心正能令筆不欹，銀鈎猶冠古今奇。", "凜然一代英靈氣，猶似當年罵賊時。"]'),
('1997e9b5-79f1-4104-8b3a-fa95dc4001fa','鄰寺遣興三絕句  其一','李彭','宋','宋诗','song-poetry','','[]','蠻花簟冷春氣分，午醉醒尋野寺門。',32,'全唐诗/poet.song.80000.json','["蠻花簟冷春氣分，午醉醒尋野寺門。", "黄落遠林供倚杖，却疑殘照是朝暾。"]'),
('52c2d11b-5f94-4a35-ab39-44dc765c3ff7','鄰寺遣興三絕句  其二','李彭','宋','宋诗','song-poetry','','[]','映堦駮蘚漫層層，古柏連蜷上老藤。',32,'全唐诗/poet.song.80000.json','["映堦駮蘚漫層層，古柏連蜷上老藤。", "梵鼓粥魚今落莫，半歸官焙半殘僧。"]'),
('23775e49-2509-4d6d-a942-7bc3d03d96d1','鄰寺遣興三絕句  其三','李彭','宋','宋诗','song-poetry','','[]','修源一带碧灣環，上有江西淡竚山。',32,'全唐诗/poet.song.80000.json','["修源一带碧灣環，上有江西淡竚山。", "便覺心塵雙寂寞，不愁騎省鬢毛斑。"]'),
('831b8359-3e94-4d9d-b955-e670b815a3e9','遣興兼寄豫章二弟  其一','李彭','宋','宋诗','song-poetry','','[]','國士無雙有山谷，斗南獨步憶秦郎。',32,'全唐诗/poet.song.80000.json','["國士無雙有山谷，斗南獨步憶秦郎。", "鸚鵡洲前多勝日，古藤陰下夜何長。"]'),
('1684cacd-7edd-4afc-9fb7-b943a406e6bf','遣興兼寄豫章二弟  其二','李彭','宋','宋诗','song-poetry','','[]','獨持杯杓酹先酒，遺我此物忘百憂。',32,'全唐诗/poet.song.80000.json','["獨持杯杓酹先酒，遺我此物忘百憂。", "乞靈鮑謝共傾倒，况復隔窗懸玉鈎。"]'),
('44048fc3-470d-4bc4-8079-803564864567','遣興兼寄豫章二弟  其三','李彭','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','龍沙季子在原樂，不肯附書黄耳來。',32,'全唐诗/poet.song.80000.json','["龍沙季子在原樂，不肯附書黄耳來。", "滕王閣上覓佳句，鐡柱觀頭行幾迴。"]'),
('89edd725-9537-44d6-8ff9-7ace508809aa','即事  其一','李彭','宋','宋诗','song-poetry','','[]','倦聽戍鼓擊銅龍，卧待當軒葉底風。',32,'全唐诗/poet.song.80000.json','["倦聽戍鼓擊銅龍，卧待當軒葉底風。", "暝鳥忽穿明月去，直疑便面寫歸鴻。"]'),
('21fa8c2e-aeeb-46d9-b3dd-b376b227a1f5','即事  其二','李彭','宋','宋诗','song-poetry','','[]','左界明河夜未央，輕風灑面作微涼。',32,'全唐诗/poet.song.80000.json','["左界明河夜未央，輕風灑面作微涼。", "藏舟枉渚者誰子，欸乃歌聲短復長。"]'),
('0abc7bf1-bfc2-462f-9b3e-444a1135d49b','即事  其三','李彭','宋','宋诗','song-poetry','','[]','紛紛著作能上馬，衮衮紫微俱斵窗。',32,'全唐诗/poet.song.80000.json','["紛紛著作能上馬，衮衮紫微俱斵窗。", "韓侯遽綰銅章去，豈坐雙流带二江。"]'),
('687c2f5d-9302-49e3-a316-e2d5217e2039','即事  其四','李彭','宋','宋诗','song-poetry','','[]','我覯之子秉周禮，要使諸儒識漢儀。',32,'全唐诗/poet.song.80000.json','["我覯之子秉周禮，要使諸儒識漢儀。", "側席求賢天子聖，未容澤畔弔湘纍。"]'),
('d0600d81-c7b8-44d5-944a-51c27ab1e2c7','即事  其五','李彭','宋','宋诗','song-poetry','','[]','眼看花霧共衣霏，已有羣鶯窗上飛。',32,'全唐诗/poet.song.80000.json','["眼看花霧共衣霏，已有羣鶯窗上飛。", "心事但隨春事盡，鐘聲更伴鳥聲微。"]'),
('25107c3f-3bd0-4c60-8898-dfcfc97c4f0b','醉書  其一','李彭','宋','宋诗','song-poetry','','[]','酴醿奪目表春餘，閒雅雍容亦甚都。',32,'全唐诗/poet.song.80000.json','["酴醿奪目表春餘，閒雅雍容亦甚都。", "睥睨園林衆芳歇，持觴耐久作歡娛。"]'),
('31c208ae-3617-49c5-bcb1-d11b6ec1be24','醉書  其二','李彭','宋','宋诗','song-poetry','','[]','稚子滿林春笋生，殘花老境尚多情。',32,'全唐诗/poet.song.80000.json','["稚子滿林春笋生，殘花老境尚多情。", "瀟灑封侯真有自，奇姿未讓惑陽城。"]'),
('872951de-81c5-4fe5-a4ce-60755fff2b60','醉書  其三','李彭','宋','宋诗','song-poetry','','[]','湛湛胸中萬頃陂，翻疑淺器是牛醫。',32,'全唐诗/poet.song.80000.json','["湛湛胸中萬頃陂，翻疑淺器是牛醫。", "從來未許愁知處，顧肯因愁移面皮。"]'),
('18e7eeee-761d-4a8b-bd16-71ad126a3dda','送淳軾二上座  其一','李彭','宋','宋诗','song-poetry','','[]','密掩柴門斷還往，道人履迹破蒼苔。',32,'全唐诗/poet.song.80000.json','["密掩柴門斷還往，道人履迹破蒼苔。", "青燈相對語離夜，况復打窗風雨來。"]'),
('8aaa6806-4a4b-4c1a-a908-09314590eb5a','送淳軾二上座  其二','李彭','宋','宋诗','song-poetry','','[]','上人定自有佳處，眉宇翠氣連湖山。',32,'全唐诗/poet.song.80000.json','["上人定自有佳處，眉宇翠氣連湖山。", "烟邊候雁著行急，力挽不留相與還。"]'),
('8622322a-aed9-4dee-96cc-5b644de5c9a2','漫興  其一','李彭','宋','宋诗','song-poetry','','[]','真牧堂前花草新，舍南移就一番春。',32,'全唐诗/poet.song.80000.json','["真牧堂前花草新，舍南移就一番春。", "非關瘠魯欲肥杞，直恐强齊將弱秦。"]'),
('c335fc30-d991-4cee-bf6b-12eae66cc0c4','漫興  其二','李彭','宋','宋诗','song-poetry','','[]','梅花冷蘂發疏枝，雲斷天南放日暉。',32,'全唐诗/poet.song.80000.json','["梅花冷蘂發疏枝，雲斷天南放日暉。", "亂折寒柯有雙鵲，銜將綴作百家衣。"]'),
('b5d1a8a6-2d58-4938-8aa9-259756c329bd','翻經臺','李彭','宋','宋诗','song-poetry','','[]','五千餘卷在高臺，內史翻時臘屐来。',32,'全唐诗/poet.song.80000.json','["五千餘卷在高臺，內史翻時臘屐来。", "夢斷池塘人不見，年年春草綠成堆。"]'),
('59d789b0-5452-4161-b2b5-04abe20c175f','幽園風雨','李彭','宋','宋诗','song-poetry','','[]','妙手春工如畫史，鵝溪百幅掛城隅。',32,'全唐诗/poet.song.80000.json','["妙手春工如畫史，鵝溪百幅掛城隅。", "却將李成驟雨筆，掩映邊鸞花鳥圖。"]'),
('e4f32f35-8f8a-48db-9749-6af6ccbfe40c','竹間兩絕句  其一','李彭','宋','宋诗','song-poetry','','[]','鳥聲催得青春老，花氣渾忘白髪新。',32,'全唐诗/poet.song.80000.json','["鳥聲催得青春老，花氣渾忘白髪新。", "誰復能尋三徑友，信知真是五臺賓。"]'),
('20710d7c-299b-4a3d-a161-36045a00d601','竹間兩絕句  其二','李彭','宋','宋诗','song-poetry','','[]','何許晚鐘烟雨餘，花間蛺蝶舞蘧蘧。',32,'全唐诗/poet.song.80000.json','["何許晚鐘烟雨餘，花間蛺蝶舞蘧蘧。", "莫將絕壑潄流齒，戲誦文園封禪書。"]'),
('5b821db5-7172-4076-83ad-ac0bb6651537','自西林投宿歸宗','李彭','宋','宋诗','song-poetry','','[]','江都著足寫餘酣，頗怪朝暉變夕嵐。',32,'全唐诗/poet.song.80000.json','["江都著足寫餘酣，頗怪朝暉變夕嵐。", "我與諸峰俱是畫，解隨歸鳥過山南。"]'),
('e1163dfa-3d73-4fb7-9556-0fec7e662d2d','魏鍊師四松畫軸','李彭','宋','宋诗','song-poetry','','[]','四松在澗壑，歲晚乃更奇。',96,'全唐诗/poet.song.80000.json','["四松在澗壑，歲晚乃更奇。", "蕭然如黄綺，傲岸不可追。", "誰將談天口，掉舌聊見移。", "由來拂東絹，寫此霜雪姿。", "便有松上雨，催我窗間詩。", "翻思斸青冥，採藥堪扶衰。", "當年丹青手，開闢造化隨。", "既有圯下約，子行何後期。"]'),
('fb73da65-4b46-4c0c-ae74-55dad4e49788','徐叔明校書篆筆奇古復善丹青爲予作漢江暮靄扇材極妙力求鄙句作此以贈','李彭','宋','宋诗','song-poetry','','[]','曩時徐騎省，篆古逼秦相。',108,'全唐诗/poet.song.80000.json','["曩時徐騎省，篆古逼秦相。", "後來得仍孫，毫端溟渤壯。", "能回頓挫姿，丹青生意匠。", "餘酣寫便面，萬里烟莽蒼。", "何許捕魚郎，落日蕩雙槳。", "無勞翦吳淞，安用買疊嶂。", "真欲老是間，塵境孰非妄。", "憐君俱入妙，簡遠復清曠。", "定爲造物嗔，覓句聊分謗。"]'),
('2ff59358-74d5-4e10-b134-c99cf6fbc040','夢訪友生','李彭','宋','宋诗','song-poetry','','[]','少年結客長安城，妄喜縱酒同章程。',96,'全唐诗/poet.song.80000.json','["少年結客長安城，妄喜縱酒同章程。", "支離老去一茅屋，枕書卧聞長短更。", "友生相望止百里，寒夜寥閴無微聲。", "夢中乘興輙見戴，剡溪聊爾扁舟行。", "覺來蘧蘧一榻上，不用僮僕争驩迎。", "吹燈弄筆欲書寄，窗前白月方亭亭。"]'),
('fe96c319-f4c3-4540-a6dd-4a2a3c8f1c9f','唐明皇夜遊圖','李彭','宋','宋诗','song-poetry','','[]','開元御極垂衣裳，登三咸五凌羲皇。',176,'全唐诗/poet.song.80000.json','["開元御極垂衣裳，登三咸五凌羲皇。", "白環重譯銀甕出，卜夜遨遊離未央。", "香車鬬風秦與虢，羅帕覆鞍真乘黄。", "赭袍錯落綴北斗，步輦優游含縷觴。", "寜王玉笛上霄漢，御路花光争月光。", "汝陽羯鼓絹帽穩，打徹參旌低建章。", "太真霑醉玉欹側，力士傳呼聲渺茫。", "翠釵掛冠紅粉粧，金貂貰酒白面郎。", "君臣玩狎樂莫比，清禁喜聞宫漏長。", "若令姚宋坐廟堂，袖中諫疏神揚揚。", "萬里橋邊行幸處，後世龜鑑懷苞桑。"]'),
('2613da09-8051-4767-8bf1-d46abf314d9b','題駒父家江干秋老圖','李彭','宋','宋诗','song-poetry','','[]','江風颼飀江水寒，蘆洲雁下生微瀾。',64,'全唐诗/poet.song.80000.json','["江風颼飀江水寒，蘆洲雁下生微瀾。", "漁翁夫婦不能語，津吏醉倒船著灘。", "其旁病夫坐箕踞，持竿萬事那復顧。", "懸知寧斷嬌兒乳，不及冥鴻及飛鷺。"]'),
('26b65eee-c351-4de1-84d4-e84a7cd2d4f9','都城元夜','李彭','宋','宋诗','song-poetry','','[]','斜陽盡處蕩輕烟，輦路東西入管絃。',64,'全唐诗/poet.song.80000.json','["斜陽盡處蕩輕烟，輦路東西入管絃。", "五夜好春隨步暖，一年明月打頭圎。", "香塵掠粉翻羅带，密炬籠綃鬬玉鈿。", "人影漸稀花露冷，蹋歌吹度曉雲邊。"]'),
('6c8d1cf6-7a86-4d7b-909a-f72777a05f46','望西山懷駒父','李彭','宋','宋诗','song-poetry','','[]','去歲湖湘賦凛秋，聞君江國大刀頭。',64,'全唐诗/poet.song.80000.json','["去歲湖湘賦凛秋，聞君江國大刀頭。", "百年會面知幾遇，十事欲言還九休。", "照眼遥岑落懷袖，過眉拄杖立汀洲。", "莫言青山淡吾慮，誰料却能生許愁。"]'),
('0d681b0e-1b13-49cb-ab50-c5d55df37eb7','次韻謝朓登三山還望京邑寄六弟','李彭','宋','宋诗','song-poetry','','[]','驅車背郊園，殊鄉復異縣。',84,'全唐诗/poet.song.80000.json','["驅車背郊園，殊鄉復異縣。", "春色滿上都，雜遝眩聞見。", "危樓日輝輝，絳闕雲練練。", "那思赴修畛，豈復憶遙甸。", "佳人戛鳴瑟，開懷具芳宴。", "但願酒如澠，詎計花如霰。", "緬懷棄繻志，彬蔚期豹變。"]'),
('4a069515-9294-4196-b038-6e07f643afa0','食蟹','李彭','宋','宋诗','song-poetry','','[]','溪友提攜紫蟹肥，形模郭索就羈縻。',64,'全唐诗/poet.song.80000.json','["溪友提攜紫蟹肥，形模郭索就羈縻。", "抱黄斫雪老饕事，看碧成朱露醉時。", "大嚼故知羞海鏡，嗜甘易誤食蟛蜞。", "欲將磊落輕周雅，委頓深憐蔡克兒。"]'),
('1c3de419-d305-4bb0-9b90-cd0d9bdcb451','弔賈氏園池','李彭','宋','宋诗','song-poetry','','[]','瑤房錦樹曲相通，能幾番春事已空。',32,'全唐诗/poet.song.80000.json','["瑤房錦樹曲相通，能幾番春事已空。", "惆悵舊時吹笛處，壞窗風雨剝青紅。"]'),
('9c4fe7d6-bf66-423e-a1b4-23be85c9c482','謹次高韻酬禹功司錄博士','李彭','宋','宋诗','song-poetry','','[]','煙霞痼疾自藏身，刮膜頻窺佳句新。',64,'全唐诗/poet.song.80000.json','["煙霞痼疾自藏身，刮膜頻窺佳句新。", "學博還同杜侯庫，才慳深愧庾郎珍。", "倚風終日掃松徑，披霧何時對玉人。", "西掖鑾坡須妙手，如公那復困無津。"]'),
('0645d906-c54a-4d25-927b-e9a7c7a24e88','挽詩','李彭','宋','宋诗','song-poetry','','[]','周南留滯登封日，魯國逍遙曳杖時。',32,'全唐诗/poet.song.80000.json','["周南留滯登封日，魯國逍遙曳杖時。", "海內時流今略盡，不知誰作蔡邕碑。"]'),
('d9025319-a7b6-4680-aefb-f4af1a16e1f3','讀山谷文','李彭','宋','宋诗','song-poetry','','[]','折玉摧蘭事竟空，貯雲含霧思無窮。',64,'全唐诗/poet.song.80000.json','["折玉摧蘭事竟空，貯雲含霧思無窮。", "仙階忽列通明觀，人世猶稱太史公。", "絳帳老生悲湜籍，傳燈嫡子有徐洪。", "以那爲首聊披拂，三絕韋編對晚風。"]'),
('22d4fbf3-ed74-46c5-8d88-843bc6cd39a3','東翻經臺','李彭','宋','宋诗','song-poetry','','[]','枉渚映寒林，野航飛鳥急。',24,'全唐诗/poet.song.80000.json','["枉渚映寒林，野航飛鳥急。", "不見康樂侯，衡門煙際人。"]'),
('d4d7808a-ddab-43e4-9c06-e706da01d82d','句  其一','李彭','宋','宋诗','song-poetry','','[]','滿朝以詩鳴，何獨遺大雅。',24,'全唐诗/poet.song.80000.json','["滿朝以詩鳴，何獨遺大雅。", "平生黄葉句，摸索便知價。"]'),
('d8a849f5-37d3-477d-a866-d22a2e65d09b','句  其二','李彭','宋','宋诗','song-poetry','','[]','卻笑思鱸膾，應須持蟹螯。',12,'全唐诗/poet.song.80000.json','["卻笑思鱸膾，應須持蟹螯。"]'),
('b8254561-2958-4dcf-9562-cc5dba569736','句  其三','李彭','宋','宋诗','song-poetry','','[]','紫荷蟲篆霜葉枯，褭蹄垂房裂青膚。',16,'全唐诗/poet.song.80000.json','["紫荷蟲篆霜葉枯，褭蹄垂房裂青膚。"]'),
('27ad1d77-458a-452e-b96d-700ecbbc441c','句  其四','李彭','宋','宋诗','song-poetry','','[]','相望唇亡齒寒國，書來莫惜剡溪藤。',16,'全唐诗/poet.song.80000.json','["相望唇亡齒寒國，書來莫惜剡溪藤。"]'),
('4de19411-7b4d-4e07-b8f2-048f60292fae','句  其五','李彭','宋','宋诗','song-poetry','','[]','芝山雲物故如在，鄱水波瀾何似生。',16,'全唐诗/poet.song.80000.json','["芝山雲物故如在，鄱水波瀾何似生。"]'),
('1b4d137b-5f6f-4ced-a70c-03f52b425081','句  其六','李彭','宋','宋诗','song-poetry','','[]','湖平可愛西南水，石美堪鄰上下鐘。',16,'全唐诗/poet.song.80000.json','["湖平可愛西南水，石美堪鄰上下鐘。"]'),
('d786950b-05ed-4f26-97e3-64e0887265ac','句  其七','李彭','宋','宋诗','song-poetry','','[]','章江之水抱城流。',8,'全唐诗/poet.song.80000.json','["章江之水抱城流。"]'),
('25924cbe-7f8a-4c8e-9d7f-f3a867ce4b1c','句  其八','李彭','宋','宋诗','song-poetry','','[]','茲意與誰傳。',6,'全唐诗/poet.song.80000.json','["茲意與誰傳。"]'),
