('6dd0e79b-adb6-4bcb-95d0-1f005c24d399','句  其一五','李彭','宋','宋诗','song-poetry','','[]','知君頗有奇章病。',8,'全唐诗/poet.song.80000.json','["知君頗有奇章病。"]'),
('f1875e1a-39d3-4cb6-ae0a-1c0b172af380','句  其一六','李彭','宋','宋诗','song-poetry','','[]','幽尋勝事鳥窺牖。',8,'全唐诗/poet.song.80000.json','["幽尋勝事鳥窺牖。"]'),
('07645c1b-c001-45a8-96a5-c5ce74658e90','句  其一七','李彭','宋','宋诗','song-poetry','','[]','鴉啼古木亂雲深。',8,'全唐诗/poet.song.80000.json','["鴉啼古木亂雲深。"]'),
('b241f678-f1b1-4fe4-8d11-ee822f02d3db','句  其一八','李彭','宋','宋诗','song-poetry','','[]','高吟大醉三千首。',8,'全唐诗/poet.song.80000.json','["高吟大醉三千首。"]'),
('e79abfec-d8d1-4847-a759-0e5eb73d27f8','句  其一九','李彭','宋','宋诗','song-poetry','','[]','微風披拂香來去。',8,'全唐诗/poet.song.80000.json','["微風披拂香來去。"]'),
('a8ba80d5-f518-4ce9-9d23-493743984bf9','句  其二○','李彭','宋','宋诗','song-poetry','','[]','風流盡付小園春。',8,'全唐诗/poet.song.80000.json','["風流盡付小園春。"]'),
('db8570a8-8404-47ad-ad30-bc59628c1a6a','句  其二一','李彭','宋','宋诗','song-poetry','','[]','皎月句添光陸離。',8,'全唐诗/poet.song.80000.json','["皎月句添光陸離。"]'),
('c4614299-b8f0-4f44-a599-05b7437f32f4','句  其二二','李彭','宋','宋诗','song-poetry','','[]','苦無疏影橫斜句。',8,'全唐诗/poet.song.80000.json','["苦無疏影橫斜句。"]'),
('901286f7-89ff-4ede-80d9-a12b8c9791e7','句  其二三','李彭','宋','宋诗','song-poetry','','[]','供奉班中須此賢。',8,'全唐诗/poet.song.80000.json','["供奉班中須此賢。"]'),
('80667ab7-fd85-4788-886a-de4acce12cd6','句  其二四','李彭','宋','宋诗','song-poetry','','[]','已失裝懷萬斛愁。',8,'全唐诗/poet.song.80000.json','["已失裝懷萬斛愁。"]'),
('740190ae-a9c0-4bce-8bde-3f45f1904746','句  其二五','李彭','宋','宋诗','song-poetry','','[]','相思甲乙翻遺稿，力斛珠璣得貫穿。',16,'全唐诗/poet.song.80000.json','["相思甲乙翻遺稿，力斛珠璣得貫穿。"]'),
('8815d209-3155-4199-af2c-207b1329316d','睿謨殿曲宴詩','王安中','宋','宋诗','song-poetry','','[]','上帝通明闕，神霄廣愛天。',288,'全唐诗/poet.song.80000.json','["上帝通明闕，神霄廣愛天。", "九光環日月，五色麗雲煙。", "紫宙開三極，瓊璈列萬仙。", "希夷塵境斷，彷彿玉經傳。", "妙道逢昌運，真王撫契賢。", "龜圖規大壯，龍位正純乾。", "穹昊親無間，皇居掇自然。", "剛風同變化，梵氣共陶甄。", "層觀星潢上，重闉斗柄邊。", "摩空七雉峻，冠嶠六鼇連。", "夢想何嘗到，階升信有緣。", "昕朝初放仗，密燕忽聞宣。", "清禁來鳴佩，修廊列並肩。", "獸鋪金半闔，鸞障繡微褰。", "霽景流庭砌，雷文繪桷梴。", "宫簾波錦漾，殿榜字金填。", "花擁巍巍座，香浮秩秩筵。", "嵩呼稱萬億，韶奏侍三千。", "華歲稱堯歷，元璣候舜璿。", "冰霜知臘後，梅柳認春前。", "造化應呈巧，芳菲已鬬妍。", "樛枝琱檻小，多葉露桃鮮。", "錯落飛杯斝，鏘洋雜管絃。", "承雲歌歷歷，回雪舞翩翩。"]'),
('d2249faf-714c-447f-ad51-ca3425ce886d','宣和七年九月二十三日睿謨殿賞橘曲燕詩','王安中','宋','宋诗','song-poetry','','[]','赤伏符興運，長生帝應期。',288,'全唐诗/poet.song.80000.json','["赤伏符興運，長生帝應期。", "駿功光祖考，大道仰君師。", "皇極三才建，春臺四海熙。", "高高天輔德，蕩蕩物由儀。", "政叶陰陽敘，恩均雨露施。", "機緘神不測，橐籥化無私。", "黄道星循軌，璿璣日轉規。", "農祥朝自正，膏澤夜還滋。", "耕首天田稼，蠶先繭館絲。", "云誰知帝力，初弗奪民時。", "嘉種今仍降，來牟此獨貽。", "上方輕賦斂，人益勸耘耔。", "陸播顔寧汗，谿秧手任龜。", "雨暘常不過，高下兩俱宜。", "壠靜無稂莠，場登足秬秠。", "地腴從再易，倉富必千斯。", "已覺饒儲偫，何妨飽滯遺。", "滴珠香社釀，舂玉滑晨炊。", "廩廥連淮上，帆檣塞汴湄。", "人和通斔斛，家積等京坻。", "歲事豐如此，天心喜可知。", "肅霜時既屆，夷則律初吹。", "坐弛輸邊粟，先共饗帝粢。", "遂蠲陽館薦，將迓泰壇釐。"]'),
('cc736e23-9d33-4870-9d58-84c26383fe3a','進和御製艮嶽曲宴詩','王安中','宋','宋诗','song-poetry','','[]','柳暗宫城暈麴塵，行穿飛觀認敷春。',64,'全唐诗/poet.song.80000.json','["柳暗宫城暈麴塵，行穿飛觀認敷春。", "天垂千尺銀河外，雲湧三山碧海濵。", "地勝煙霞開浩劫，花濃雨露近中宸。", "曲江弭櫂歸侵夜，爭看升平際遇人。"]'),
('fd258372-21d8-4de9-8396-8d2441952e26','艮嶽進和御製二詩  其一','王安中','宋','宋诗','song-poetry','','[]','雲峰面面巧隨人，淥淨兼無一點塵。',32,'全唐诗/poet.song.80000.json','["雲峰面面巧隨人，淥淨兼無一點塵。", "開盡巖英并澗蕊，君王自與物爲春。"]'),
('715ee695-7e21-46c6-9b97-911f14b1c794','艮嶽進和御製二詩  其二','王安中','宋','宋诗','song-poetry','','[]','南苞雒艷貢驚春，造化爭先物物新。',32,'全唐诗/poet.song.80000.json','["南苞雒艷貢驚春，造化爭先物物新。", "鏤管裁詩天語妙，翠甖頒醴聖恩頻。"]'),
('81c3d0a4-a8fe-40e6-b7b8-14d615a96628','重和春宴口號','王安中','宋','宋诗','song-poetry','','[]','政布青陽左个邊，春回太極五門前。',64,'全唐诗/poet.song.80000.json','["政布青陽左个邊，春回太極五門前。", "琳宫就講三千士，瓊籙聯名八百仙。", "午夜雷霆來艮岳，東風耒耜出天田。", "頒觴紫殿君臣樂，萬紀重和第二年。"]'),
('0873ab00-7f4a-4a3b-8ca5-84449d8977d3','進和聖製元夕詩','王安中','宋','宋诗','song-poetry','','[]','斗城雲接始青天，汴水浮春放洛川。',64,'全唐诗/poet.song.80000.json','["斗城雲接始青天，汴水浮春放洛川。", "繒巘千峰延璧月，珠簾十里晃燈蓮。", "五門端闕初元夕，萬歷宣和第二年。", "聖世親逢叨四近，頒觴連日綴羣賢。"]'),
('b10aed7a-611a-4f2c-a50e-97c98047a287','進和御製幸太學祕書省詩','王安中','宋','宋诗','song-poetry','','[]','九譯何難致越裳，太平聲教陋成康。',64,'全唐诗/poet.song.80000.json','["九譯何難致越裳，太平聲教陋成康。", "千年文物儲天祿，四海英髦聚國庠。", "冊府緩留清蹕響，儒齋深映赭袍光。", "侍臣誰草宣和頌，落筆爭看立堵牆。"]'),
('295bfd2c-550c-4417-ade0-2e41a86e9037','進和御製芸館二詩  其一','王安中','宋','宋诗','song-poetry','','[]','路轉陽華許縱遊，南山松竹夏幽幽。',64,'全唐诗/poet.song.80000.json','["路轉陽華許縱遊，南山松竹夏幽幽。", "雲來天半蒼龍闕，波漲溪心白鷺洲。", "隔塢黄知林杏熟，連岡青認摽梅稠。", "絳霄樓觀身頻到，獨愧君恩久未酬。"]'),
('8cc8b114-b189-41bb-a651-8620b7af3325','進和御製芸館二詩  其二','王安中','宋','宋诗','song-poetry','','[]','芸館修篁靜絕塵，渭川那足比封君。',64,'全唐诗/poet.song.80000.json','["芸館修篁靜絕塵，渭川那足比封君。", "清陰密覆林間石，翠色寒摇水底雲。", "風好知從宫扇動，茶香宜入御甌分。", "裴回永晝人霑醉，歸踏青青徑草薰。"]'),
('fecfee32-f184-42ba-966e-e33c57b403ef','進和御製擷芳園二詩  其一','王安中','宋','宋诗','song-poetry','','[]','仙風吹袂到壺天，池館新晴日正妍。',64,'全唐诗/poet.song.80000.json','["仙風吹袂到壺天，池館新晴日正妍。", "罨畫溪邊初縱棹，籠鬆花底緩回船。", "金鱗躍躍依春藻，繡羽飛飛掠晚煙。", "醉眼重窺雲漢作，明朝萬口想爭傳。"]'),
('75426577-b967-4173-bd07-1ab1ef7a289f','進和御製擷芳園二詩  其二','王安中','宋','宋诗','song-poetry','','[]','西城春色靜年芳，靈沼文禽暖在梁。',64,'全唐诗/poet.song.80000.json','["西城春色靜年芳，靈沼文禽暖在梁。", "岸艤輕舟泛鷁首，路尋飛棧轉羊腸。", "杯心襯錦花留影，波面鎔銀月迸光。", "曾倚披霄高閣望，清都自有水雲鄉。"]'),
('4f1b3618-7631-4880-9a0c-3deb1d95373d','和御製白蓮詩  其一','王安中','宋','宋诗','song-poetry','','[]','十丈層簷日脚留，香風吹灧曲江秋。',64,'全唐诗/poet.song.80000.json','["十丈層簷日脚留，香風吹灧曲江秋。", "石梁架海三山近，玉井移蓮八月稠。", "白雪高盤初縷鱠，青天露坐晚臨流。", "夾城飛觀煙雲合，端覺身從物外遊。"]'),
('236d47df-646c-4a8e-a98e-118e127d4f40','和御製白蓮詩  其二','王安中','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','華堂起江沚，璇榜塞門楣。',144,'全唐诗/poet.song.80000.json','["華堂起江沚，璇榜塞門楣。", "眈如垂天雲，始與煙水宜。", "圓荷蓋千頃，高柳排四涯。", "娟娟初芙蓉，濯濯清淪漪。", "造物與奇勝，冰姿煥相差。", "唐昌玉蕊仙，流步光入扉。", "霜寒挈青女，夜永過月妃。", "紉佩雜瓊華，施朱笑紅滋。", "但薰百和香，不染六銖衣。", "新篇來帝所，天語妙莫窺。", "徜徉洞庭野，九奏驚咸池。", "恩隆許賡續，萬漏敢固辭。"]'),
('1854cea6-1d06-490f-9860-04e9569da4ab','進和御製上巳錫宴詩','王安中','宋','宋诗','song-poetry','','[]','三月昆明浩蕩春，芙蓉新殿壓池濵。',64,'全唐诗/poet.song.80000.json','["三月昆明浩蕩春，芙蓉新殿壓池濵。", "香飄花外流觴宴，雲擁波心捧劍人。", "別苑連岡晴縱目，重門飛鞚夜生塵。", "共欣魚藻千齡遇，拜舞昕朝整韠紳。"]'),
('7a9a2883-929b-4ca4-9ff4-43126aec0dba','進和御製幸池詩','王安中','宋','宋诗','song-poetry','','[]','神霄玉闕敞黎明，芝蓋琱輿下穆清。',64,'全唐诗/poet.song.80000.json','["神霄玉闕敞黎明，芝蓋琱輿下穆清。", "風挾龍舟横太液，人從鼇背上東瀛。", "赭黄袍接天光近，鴨綠波摇檻影平。", "持橐此時陪燕豫，岸花汀草共欣榮。"]'),
('1d841a02-0c46-49ac-a8da-25c9827c89da','進和御製大明殿御畫屏風詩','王安中','宋','宋诗','song-poetry','','[]','琳闕靈游恍馭風，曲屏親畫孝心通。',64,'全唐诗/poet.song.80000.json','["琳闕靈游恍馭風，曲屏親畫孝心通。", "越禽翠射宫簷外，閩果紅垂御扆中。", "階影近留金瑣碎，林光遥映玉青葱。", "萬年原廟欽崇極，更識君王繼序功。"]'),
('5426279f-f5e7-4324-82fd-7a7c3c0872c6','次韻趙承之赴穆清殿秋宴','王安中','宋','宋诗','song-poetry','','[]','樓殿雲端擁萬靈，新規重構帝居成。',64,'全唐诗/poet.song.80000.json','["樓殿雲端擁萬靈，新規重構帝居成。", "彤庭收霧乾坤靜，玉座中天斗極明。", "宣勸聲傳龍尾逈，醉歸塵逐馬蹄輕。", "小儒未預金閨籍，廣樂因風耳屢傾。"]'),
('69803f27-ca57-4c9a-8b59-0c886e0ff09b','朵樓侍宴','王安中','宋','宋诗','song-poetry','','[]','東闕年年曲宴頒，御尊宣勸醉春寒。',64,'全唐诗/poet.song.80000.json','["東闕年年曲宴頒，御尊宣勸醉春寒。", "衮衣密似魁三象，閣道高於蜀五盤。", "一氣已從調鼎順，八方今比覆盂安。", "君王禮貌超前古，輔弼須銘座右看。"]'),
('77b9af17-5795-451e-944f-29409f1db282','瑞雪應制','王安中','宋','宋诗','song-poetry','','[]','瑶壇親禱夜如何，雪逐青華玉仗過。',64,'全唐诗/poet.song.80000.json','["瑶壇親禱夜如何，雪逐青華玉仗過。", "翦水乍鋪重屋早，吹花偏入上林多。", "昕朝披霧聞天笑，燕序驚春誦帝歌。", "已卜豐年連四海，康衢還解譽堯麽。"]'),
('43a223e4-9988-451b-971e-d191c0950077','進和御製喜雪詩  其一','王安中','宋','宋诗','song-poetry','','[]','呼龍種玉夜相先，親禱那憑太史占。',64,'全唐诗/poet.song.80000.json','["呼龍種玉夜相先，親禱那憑太史占。", "天借春容裝苑木，曉催風片舞宫簷。", "勝遊獨許梁賓友，高臥誰尋漢孝廉。", "壠麥青青無近遠，三農知自帝恩霑。"]'),
('f5b920f3-79e1-4092-bbd0-fa22a1ffa30d','進和御製喜雪詩  其二','王安中','宋','宋诗','song-poetry','','[]','雲車初近紫壇陰，報享星光照羽林。',64,'全唐诗/poet.song.80000.json','["雲車初近紫壇陰，報享星光照羽林。", "萬乘欲祠琳館邃，九衢先雨玉花深。", "海山出日迎天步，花木催春悅聖心。", "帝與來牟興嗣歲，三農呼舞仰君臨。"]'),
('d7a2e624-73ab-400e-926f-e746a8293392','乙巳歲喜雪御筵即席和御製詩','王安中','宋','宋诗','song-poetry','','[]','九衢歌舞醉爲鄉，共慶飛霙報歲穰。',64,'全唐诗/poet.song.80000.json','["九衢歌舞醉爲鄉，共慶飛霙報歲穰。", "花趁小春飄宴席，天回和氣入彫觴。", "三銀闕湧雲潢外，萬玉妃朝月殿旁。", "聖旦親逢賡帝藻，不同梁苑召鄒陽。"]'),
('c13d44bd-15c8-4151-a80a-1f271f8c16c7','進和御製南郊禮成喜雪詩','王安中','宋','宋诗','song-poetry','','[]','竣事觚壇萬玉趨，繽紛密雪告休符。',64,'全唐诗/poet.song.80000.json','["竣事觚壇萬玉趨，繽紛密雪告休符。", "雲隨太極飛晨蓋，天在浮黎大寶珠。", "喜色生春臨魏闕，恩書掣電過幽都。", "願將上帝居歆意，寫作宣和吉禮圖。"]'),
('355e74fb-cf28-43d4-ad2d-604645b485bf','比在阜城寺中韻所得語還里任伯首和之因併錄傳冀有相廣者  其一','王安中','宋','宋诗','song-poetry','','[]','縠紋春霧輕，簟理秋濤平。',36,'全唐诗/poet.song.80000.json','["縠紋春霧輕，簟理秋濤平。", "天風一披拂，全體有餘清。", "是中自不惡，我懷陶淵明。"]'),
('376f40fb-4713-4f0d-949c-57f32410b7dd','比在阜城寺中韻所得語還里任伯首和之因併錄傳冀有相廣者  其二','王安中','宋','宋诗','song-poetry','','[]','層城填華屋，政爾無好風。',36,'全唐诗/poet.song.80000.json','["層城填華屋，政爾無好風。", "沉沉古殿閉，一洗萬濁空。", "端知黄面老，真有清凈功。"]'),
('f86332cc-b514-4c02-83d0-3eb8f6a05196','比在阜城寺中韻所得語還里任伯首和之因併錄傳冀有相廣者  其三','王安中','宋','宋诗','song-poetry','','[]','風襟得清泠，世味增淡薄。',36,'全唐诗/poet.song.80000.json','["風襟得清泠，世味增淡薄。", "委蟬觀四大，縛虎視六鑿。", "中腸過饑雷，益悟非妄作。"]'),
('7167284a-6f53-4953-afce-49e8290e6e7e','比在阜城寺中韻所得語還里任伯首和之因併錄傳冀有相廣者  其四','王安中','宋','宋诗','song-poetry','','[]','炎曦正流金，凉風在何許。',36,'全唐诗/poet.song.80000.json','["炎曦正流金，凉風在何許。", "障袂日中來，逃暑真得暑。", "晶瑩玉壺冰，終不落塵土。"]'),
('707db10a-73c2-4f43-b2f1-3398bab67a20','比在阜城寺中韻所得語還里任伯首和之因併錄傳冀有相廣者  其五','王安中','宋','宋诗','song-poetry','','[]','日月行天機，無意作炎夏。',36,'全唐诗/poet.song.80000.json','["日月行天機，無意作炎夏。", "百巧求一凉，勤我晨及夜。", "君子有四時，盍歸掃吾舍。"]'),
('93a92593-3cf4-4443-8b29-8bdec79521da','比在阜城寺中韻所得語還里任伯首和之因併錄傳冀有相廣者  其六','王安中','宋','宋诗','song-poetry','','[]','便凉即嗜眠，煮茗還破睡。',36,'全唐诗/poet.song.80000.json','["便凉即嗜眠，煮茗還破睡。", "不爲蟻穴戰，猶尋蟹眼沸。", "果欲夢何夢，應知味非味。"]'),
('9eefa27d-05b5-481e-bffa-49cc431bb80a','比在阜城寺中韻所得語還里任伯首和之因併錄傳冀有相廣者  其七','王安中','宋','宋诗','song-poetry','','[]','小學倚在門，大學升在堂。',36,'全唐诗/poet.song.80000.json','["小學倚在門，大學升在堂。", "衆星自伏見，兩曜常暉光。", "伊我思古人，踽踽復凉凉。"]'),
('4568da70-4840-4e8c-a2d7-d100001d93ec','比在阜城寺中韻所得語還里任伯首和之因併錄傳冀有相廣者  其八','王安中','宋','宋诗','song-poetry','','[]','我觀揚子雲，不解子輿語。',36,'全唐诗/poet.song.80000.json','["我觀揚子雲，不解子輿語。", "浩然天地間，忍事草玄苦。", "燭龍臨太空，鑒火君自取。"]'),
('fc979cf5-bc5d-4bb0-8c13-e840b9deb9ec','讀真誥  其一','王安中','宋','宋诗','song-poetry','','[]','吾宗桐柏君，冰采極少整。',48,'全唐诗/poet.song.80000.json','["吾宗桐柏君，冰采極少整。", "吹笙緱氏山，策轡金庭嶺。", "阿香侍紫清，眉壽亦秀穎。", "仙門定得仙，道廕及遐永。"]'),
('ae74b64f-f15a-4faf-973f-13f685b914d1','讀真誥  其二','王安中','宋','宋诗','song-poetry','','[]','清娥阿母嬌，飛軿來羽野。',48,'全唐诗/poet.song.80000.json','["清娥阿母嬌，飛軿來羽野。", "八龍雲篆章，肯向人間寫。", "南真苦論道，聲氣覺殊下。", "却携九華妃，共詣修仙者。"]'),
('a1eaffeb-5f88-42d8-9722-5404709520e8','讀真誥  其三','王安中','宋','宋诗','song-poetry','','[]','雲林授玉書，妙語真達道。',48,'全唐诗/poet.song.80000.json','["雲林授玉書，妙語真達道。", "心中翦荆棘，一一種梨棗。", "瓊軒駕靈風，歘下滄浪島。", "有待政何妨，衆真惡懷抱。"]'),
('f4add060-0da7-4df2-a2cd-4004ddbf7015','劉無損欲書十扇以韋蘇州喬木生夏凉流雲吐華月句作韻  其一','王安中','宋','宋诗','song-poetry','','[]','俗塵雲海漲，客慮風旌搖。',48,'全唐诗/poet.song.80000.json','["俗塵雲海漲，客慮風旌搖。", "還從不了處，坐以一念超。", "深居炷爐熏，翛然带忘腰。", "養生置莫論，吾已陋松喬。"]'),
('cf6627e1-105f-457d-ab52-7bff182f1c50','劉無損欲書十扇以韋蘇州喬木生夏凉流雲吐華月句作韻  其二','王安中','宋','宋诗','song-poetry','','[]','宿昔未聞道，十年醉幽讀。',48,'全唐诗/poet.song.80000.json','["宿昔未聞道，十年醉幽讀。", "睥睨天壤間，萬事真破竹。", "今來知自笑，逢場罷竿木。", "猶餘勸緣心，留賓與更僕。"]'),
('0ef32dad-036c-470e-9de8-16caf3e2be1d','劉無損欲書十扇以韋蘇州喬木生夏凉流雲吐華月句作韻  其三','王安中','宋','宋诗','song-poetry','','[]','學道辦何等，日用四時行。',48,'全唐诗/poet.song.80000.json','["學道辦何等，日用四時行。", "夢尋湯餅到，風入茶甌生。", "忘機心坦坦，詣理言平平。", "誰同坐清夜，籠燈對微明。"]'),
('cbaa8b21-4ce3-44df-9f99-168b24e77a99','劉無損欲書十扇以韋蘇州喬木生夏凉流雲吐華月句作韻  其四','王安中','宋','宋诗','song-poetry','','[]','出門趁雞晨，還舍結僧夏。',48,'全唐诗/poet.song.80000.json','["出門趁雞晨，還舍結僧夏。", "緣隨香火慣，跡涉林塘乍。", "便恐住山侣，麾手謝俗駕。", "悠然指此心，是中有餘暇。"]'),
('eed677ab-68e6-429b-9f4a-20a647aa2b9a','劉無損欲書十扇以韋蘇州喬木生夏凉流雲吐華月句作韻  其五','王安中','宋','宋诗','song-poetry','','[]','玫瑰紅被徑，薜荔綠走墻。',48,'全唐诗/poet.song.80000.json','["玫瑰紅被徑，薜荔綠走墻。", "風埃林籟起，中有楸花香。", "緯蕭隔雲霧，烏鵶自回翔。", "聽下轆轤聲，心與古井凉。"]'),
('e3cc36d2-9579-4316-bb18-d0918885ca97','劉無損欲書十扇以韋蘇州喬木生夏凉流雲吐華月句作韻  其六','王安中','宋','宋诗','song-poetry','','[]','枕玉褭蹄琢，簟波人字流。',48,'全唐诗/poet.song.80000.json','["枕玉褭蹄琢，簟波人字流。", "冰甕貯清泚，意境已生秋。", "睡餘弄徽軫，山高水幽幽。", "試作文王操，若人還見不。"]'),
('04a5e197-214e-49b3-b90f-6b5d615716de','劉無損欲書十扇以韋蘇州喬木生夏凉流雲吐華月句作韻  其七','王安中','宋','宋诗','song-poetry','','[]','一勺淡薄味，三生知見熏。',48,'全唐诗/poet.song.80000.json','["一勺淡薄味，三生知見熏。", "兹游聊忝耳，翩若出岫雲。", "弋有孔翠羽，寢有虎豹文。", "吾寧不堪用，渠亦何所聞。"]'),
('4457fba6-e904-4022-9d0c-3ad63765895c','劉無損欲書十扇以韋蘇州喬木生夏凉流雲吐華月句作韻  其八','王安中','宋','宋诗','song-poetry','','[]','魔環凈名牀，嫠納柳季户。',48,'全唐诗/poet.song.80000.json','["魔環凈名牀，嫠納柳季户。", "由來道力勝，婉孌莫予侮。", "菱花百鍊精，炯炯寒光吐。", "森羅萬象交，過即不得睹。"]'),
('f287675e-a34a-4ad3-9636-294408cfa209','劉無損欲書十扇以韋蘇州喬木生夏凉流雲吐華月句作韻  其九','王安中','宋','宋诗','song-poetry','','[]','成虧繫軒冕，心地生眼花。',48,'全唐诗/poet.song.80000.json','["成虧繫軒冕，心地生眼花。", "極知一餉静，可掃兩鬢華。", "琴雪同卧起，風月通貸賖。", "高哉彭澤柳，不比邵平瓜。"]'),
('5584e703-5561-47ce-ad4e-0acb464c624c','劉無損欲書十扇以韋蘇州喬木生夏凉流雲吐華月句作韻  其一○','王安中','宋','宋诗','song-poetry','','[]','柘漿工析酲，卉醴可消暍。',48,'全唐诗/poet.song.80000.json','["柘漿工析酲，卉醴可消暍。", "客至亦不疏，沃此蔭清樾。", "道人有眼句，翰墨相應發。", "勿隨標指看，舉似團扇月。"]'),
('19bdebd3-bc9f-48fd-b937-2a50feb13010','春懷賦得冰雪鶯來晚春寒花較遲十字  其一','王安中','宋','宋诗','song-poetry','','[]','深居足移氣，熏爐坐晨興。',48,'全唐诗/poet.song.80000.json','["深居足移氣，熏爐坐晨興。", "春來獨何覺，湯餅夢騰騰。", "永懷山中人，遣花破寒冰。", "一枝便有餘，經眼知吾曾。"]'),
('cf0d665f-2138-4c4a-ac03-c0a5b4b1aee1','春懷賦得冰雪鶯來晚春寒花較遲十字  其二','王安中','宋','宋诗','song-poetry','','[]','春寒殊未休，春事不堪說。',48,'全唐诗/poet.song.80000.json','["春寒殊未休，春事不堪說。", "陽谷溜微綫，陰崖削精鐡。", "森然十八公，鬚髯滿殘雪。", "非無料峭風，翠色已可悦。"]'),
('20539b31-2547-41f4-985a-6d5bdd9b7852','春懷賦得冰雪鶯來晚春寒花較遲十字  其三','王安中','宋','宋诗','song-poetry','','[]','寒雀隨山影，哀鴻带邊聲。',48,'全唐诗/poet.song.80000.json','["寒雀隨山影，哀鴻带邊聲。", "花遲社酒薄，春工了無情。", "東風好池館，芳草語流鶯。", "不必笑枯索，擁書輕百城。"]'),
('daeb5dfb-ba65-48c0-a08e-c308da01aec1','春懷賦得冰雪鶯來晚春寒花較遲十字  其四','王安中','宋','宋诗','song-poetry','','[]','幽窗鎻雲霧，無人誰與開。',48,'全唐诗/poet.song.80000.json','["幽窗鎻雲霧，無人誰與開。", "燕燕尾涏涏，知尋簾户來。", "春風到書律，溪藤照山煤。", "任爾擇家舍，梁塵飄硯臺。"]'),
('d9ce2bc0-5cf3-4d4e-8b4d-03f3c9c418e5','春懷賦得冰雪鶯來晚春寒花較遲十字  其五','王安中','宋','宋诗','song-poetry','','[]','種梓期十年，萟蘭盈九畹。',48,'全唐诗/poet.song.80000.json','["種梓期十年，萟蘭盈九畹。", "河清會有時，歲月坐成晚。", "向來忝聞道，及此且求本。", "行樂未渠央，何以語羌謇。"]'),
('e627c218-af28-407f-9bc3-2c707a4c816b','春懷賦得冰雪鶯來晚春寒花較遲十字  其六','王安中','宋','宋诗','song-poetry','','[]','文王有遺操，朱絃韻青春。',48,'全唐诗/poet.song.80000.json','["文王有遺操，朱絃韻青春。", "無言獨下拜，頎然見長人。", "道喪向千載，詩書絕逼真。", "逼真猶不盡，試語老斵輪。"]'),
('2b8c85a9-0bbd-49fe-b4c0-5df61e446089','春懷賦得冰雪鶯來晚春寒花較遲十字  其七','王安中','宋','宋诗','song-poetry','','[]','淵明苦長饑，中年求一官。',48,'全唐诗/poet.song.80000.json','["淵明苦長饑，中年求一官。", "歸來蒔松菊，頗覺生理難。", "我恐須出仕，未出心已寒。", "好謝山巨源，作吏廢遊觀。"]'),
('e947d20d-fe98-4ad9-b0b3-955ea125518b','春懷賦得冰雪鶯來晚春寒花較遲十字  其八','王安中','宋','宋诗','song-poetry','','[]','趙公丈人行，佛隱踏朝靴。',48,'全唐诗/poet.song.80000.json','["趙公丈人行，佛隱踏朝靴。", "風流漢北海，人物魯東家。", "同行得劉子，過門抵昏鴉。", "臨分無長語，進德除空花。"]'),
('804a9d64-ad34-450e-95ac-8339216472b7','春懷賦得冰雪鶯來晚春寒花較遲十字  其九','王安中','宋','宋诗','song-poetry','','[]','吾宗有子明，粉澤乏外貎。',48,'全唐诗/poet.song.80000.json','["吾宗有子明，粉澤乏外貎。", "白衣罷秋賦，深林藏霧豹。", "談經亦微詼，樂實在名敎。", "擬之金馬生，笑云恐差較。"]'),
('99841d5e-8140-4c9b-a1df-2755d1397279','同郡李達之貢辟廱偶試不利還鄉及河不得濟作二詩凄然讀之殆難爲懷因爲次韻極其悲苦卒少紓之當煩劉元忠彭少逸同賦  其一','王安中','宋','宋诗','song-poetry','','[]','客行天雨霜，屨穿敢留跡。',36,'全唐诗/poet.song.80000.json','["客行天雨霜，屨穿敢留跡。", "欲濟河冰凘，蛟龍情不測。", "去住兩更難，凄寒斷消息。"]'),
('959cac1c-9232-4e90-b7e3-7e20a3c5afd3','同郡李達之貢辟廱偶試不利還鄉及河不得濟作二詩凄然讀之殆難爲懷因爲次韻極其悲苦卒少紓之當煩劉元忠彭少逸同賦  其二','王安中','宋','宋诗','song-poetry','','[]','顛風無安巢，墮翼思故林。',36,'全唐诗/poet.song.80000.json','["顛風無安巢，墮翼思故林。", "誰回太陽惠，照此窮谷陰。", "扶持孔鸞輩，矯矯翔千尋。"]'),
('83319c92-c01f-4d48-a4b8-20c14625530d','用大名諸公唱和韻送别少逸  其一','王安中','宋','宋诗','song-poetry','','[]','宵濟洶濤波，晨征犯霜露。',48,'全唐诗/poet.song.80000.json','["宵濟洶濤波，晨征犯霜露。", "倐來忽語别，何所見而去。", "疑君略奉高，或我愧叔度。", "慨然陪節傳，邂逅莫忘故。"]'),
('0f970446-a921-4f6f-8d6b-fda950b0182c','用大名諸公唱和韻送别少逸  其二','王安中','宋','宋诗','song-poetry','','[]','初歡記鄴城，往還數如織。',48,'全唐诗/poet.song.80000.json','["初歡記鄴城，往還數如織。", "摶風回鑾閣，相賞垂天翼。", "君席今未暖，我井久不食。", "駕言又何之，游交請絕息。"]'),
('ed3eb37d-868b-4c40-a905-53e9d26f05e8','用大名諸公唱和韻送别少逸  其三','王安中','宋','宋诗','song-poetry','','[]','當仁語卒吐，仗義身不謀。',48,'全唐诗/poet.song.80000.json','["當仁語卒吐，仗義身不謀。", "所賢我者遠，甚薄物之尤。", "不荘醉麴蘖，欲收醉鄉侯。", "微辭致責備，近頗學春秋。"]'),
('0c903f05-1f5c-4222-88d6-d40b8577a2d5','用大名諸公唱和韻送别少逸  其四','王安中','宋','宋诗','song-poetry','','[]','邇來走筆吟，别後隨手散。',48,'全唐诗/poet.song.80000.json','["邇來走筆吟，别後隨手散。", "收拾亦安用，半是諧謔間。", "不能所作工，要解風水渙。", "莫以人廢言，遂忽博士謾。"]'),
('b5f2f4b0-3a08-4c16-b3d8-aeb684f1ae28','和李達之庚寅秋雨三首  其一','王安中','宋','宋诗','song-poetry','','[]','閏餘氣先寒，久雨愁更劇。',72,'全唐诗/poet.song.80000.json','["閏餘氣先寒，久雨愁更劇。", "丈夫固遠慮，奈此朝不夕。", "恐泥有危行，扶欹無安宅。", "我思補天漏，試鍊五色石。", "横空收洩雲，屏翳敢停跡。", "還我陽秋恩，與子兩相適。"]'),
('6b883107-31c4-4185-a5d7-81381d9b90a2','和李達之庚寅秋雨三首  其二','王安中','宋','宋诗','song-poetry','','[]','客舍無晴陰，日赴折簡喚。',48,'全唐诗/poet.song.80000.json','["客舍無晴陰，日赴折簡喚。", "家居跬步隔，心念旌旗亂。", "釡空雨生魚，遽敢議薪爨。", "衾裯我自抱，更爲子三歎。"]'),
('558f01b8-6360-463a-a2a1-df39759252a7','和李達之庚寅秋雨三首  其三','王安中','宋','宋诗','song-poetry','','[]','鄰僧雨不出，粥飯聽鐘魚。',72,'全唐诗/poet.song.80000.json','["鄰僧雨不出，粥飯聽鐘魚。", "事與吾輩異，一身易贏餘。", "而我千指家，食此半編書。", "饑驅欲何之，投瓜望瓊琚。", "側聞州禱晴，早願光景舒。", "祠官莫憚煩，霑濕秪臺輿。"]'),
('acabace0-c576-4b73-98af-c3ecedb40406','再和  其一','王安中','宋','宋诗','song-poetry','','[]','長安貴公子，對雨飲正劇。',72,'全唐诗/poet.song.80000.json','["長安貴公子，對雨飲正劇。", "明釭艶華屋，今夕知何夕。", "豈同揚子雲，反閉一廛宅。", "稍醒問予酒，已復憂甔石。", "賢愚置莫論，俛仰共陳跡。", "世路日參差，咄哉隨所適。"]'),
('50b37bcf-4c7b-4cd9-bfad-0ace19748703','再和  其二','王安中','宋','宋诗','song-poetry','','[]','霖霪連十日，茗盌闕招喚。',48,'全唐诗/poet.song.80000.json','["霖霪連十日，茗盌闕招喚。", "寒虀味獨辛，秋繭緒仍亂。", "憑將苦雨詩，商絃韻餘爨。", "果無真賞音，落魄不須歎。"]'),
('ca1443f8-3fa3-46e3-991f-fc481cd9f0fe','再和  其三','王安中','宋','宋诗','song-poetry','','[]','向來天不雨，啜泣歌枯魚。',72,'全唐诗/poet.song.80000.json','["向來天不雨，啜泣歌枯魚。", "今來雨彌旬，粒食還無餘。", "兩家各四壁，但聚古人書。", "羣爭聲利場，欲趨顧璜琚。", "豈敢喪所貴，我行自安舒。", "寒饑兩未救，杯水沃薪輿。"]'),
('e433640c-b27c-47ec-9515-e668f6975d32','郊行感興','王安中','宋','宋诗','song-poetry','','[]','邊風吹鴈寒，雨宿黄蘆下。',72,'全唐诗/poet.song.80000.json','["邊風吹鴈寒，雨宿黄蘆下。", "家鷄飽遺粒，喔喔庇簷瓦。", "孔鸞爾安巢，慎勿翔中野。", "鮮鮮野畦菊，的皪弄深黄。", "馨香不自暖，白露凄欲霜。", "明朝紫茱萸，雕檻薦高堂。"]'),
('b2e5d3ec-97c5-4c42-a493-4195823a0e79','試院對月','王安中','宋','宋诗','song-poetry','','[]','我行無町畦，忽逐春波起。',84,'全唐诗/poet.song.80000.json','["我行無町畦，忽逐春波起。", "平明發鄴城，暮宿清河涘。", "譙樓唱晚静，驛樹驚飊馭。", "亭亭華月上，熠熠繁星委。", "含暉穿幔翠，度影入窗綺。", "悲來興視夜，空庭縱幽履。", "飄如浮海仙，飛步不濡水。"]'),
('63b657d4-8b99-4de3-a15f-f499f443a303','無題','王安中','宋','宋诗','song-poetry','','[]','秋蘋一寸風，吹我鄴王臺。',144,'全唐诗/poet.song.80000.json','["秋蘋一寸風，吹我鄴王臺。", "臺邊委黄落，繐帷化飛埃。", "平生三逕步，屐齒粘蒼苔。", "覊棲望不到，蠅頭寫歸來。", "人間持板手，欲展何由開。", "再拜丈人行，卷投當瓊瑰。", "丈人龍眠龍，挾策奔風雷。", "毫端須臾寄，一挽正始回。", "年來心法孤，駸駸古爐灰。", "淵明不並世，此士誰爲才。", "紫鸞固超詣，白鷗竟何猜。", "所期豈朝華，歲莫儻相陪。"]'),
('7b5e6b10-7612-4d73-98fb-9029d894421e','張公作高陽醇酎送幕中楊時可作詩詩成亦得酒而瀛渌又將熟楊復垂涎次楊韻','王安中','宋','宋诗','song-poetry','','[]','平生顧建康，名下難爲人。',84,'全唐诗/poet.song.80000.json','["平生顧建康，名下難爲人。", "見其似者喜，敢復聖賢分。", "元侯惟麴蘖，好賜均無貧。", "萍官新荐熟，蓮幕先飲醇。", "坐令染指客，詩語生冤親。", "柑黄松小苦，賦筆久埃塵。", "何時獲瀛渌，更可調陽春。"]'),
('c8d6b85d-c277-4129-8772-15b16ccadbbc','次韻楊時可李元中酬贈之作','王安中','宋','宋诗','song-poetry','','[]','初年種交梨，可奈荆棘樹。',120,'全唐诗/poet.song.80000.json','["初年種交梨，可奈荆棘樹。", "聞道千聖前，不傳纔一語。", "彭殤幾許爭，端作旦暮遇。", "衣珠價連城，誰遣泣窮路。", "子知無生法，未短飛昇數。", "當身認同歸，絕學何外慕。", "龍眠玉頰翁，是中得深趣。", "蕭然住山人，妙甚垂天賦。", "我爲楊侯計，政欲借前筯。", "從翁須及今，頻脱户外屨。"]'),
('2997a04c-44f3-4e91-8c66-d03f5f320281','次韻王得之遊福源觀','王安中','宋','宋诗','song-poetry','','[]','維南國禋祀，崇丘五雲鮮。',192,'全唐诗/poet.song.80000.json','["維南國禋祀，崇丘五雲鮮。", "路轉樓居出，林深步虚傳。", "輜軿上真侣，鬟髻太古仙。", "綠章下祕祝，寶此一掬泉。", "至今爭晨門，奩香走填然。", "帝子留繡蓋，宫嬙擲金錢。", "吾宗初意行，跂馬税芝田。", "醒心影娥池，了了壺中天。", "呼兒話西遊，乃未得汝年。", "先生筆扛鼎，小友語更妍。", "斯文到真處，梔蠟漫賈鞭。", "賡酬就俄頃，驚絕圖書淵。", "覓句念宗武，愛奇容子遷。", "遊山本庭户，可但巢其巔。", "眼中摛文地，坐待步武連。", "幽尋賦異日，端爲續膠弦。"]'),
('c2ffa98b-ac03-4a22-bc99-18445b8c2fd4','望法華山懷慈上人','王安中','宋','宋诗','song-poetry','','[]','我無適俗姿，發興在林嶂。',132,'全唐诗/poet.song.80000.json','["我無適俗姿，發興在林嶂。", "前身一義墮，好山輸百丈。", "永懷住山人，敗毳裹龍象。", "頻驅塵外軫，徑抵雲雨上。", "道人初怪問，斗絕何從訪。", "師居不難尋，天壁愕異狀。", "風煙自蕭散，草木更森長。", "道人聊復爾，仁者作是想。", "重來傍岑翳，眼净人亦王。", "虎谿雖不過，鷲嶺聊得望。", "遥知師囅然，跛跛又安往。"]'),
('09db4fd1-277e-46f2-9058-79b2dcc400a9','過安平小集','王安中','宋','宋诗','song-poetry','','[]','王鮪未荐春，永歎念河曲。',168,'全唐诗/poet.song.80000.json','["王鮪未荐春，永歎念河曲。", "遊子懷故鄉，書劍就裝束。", "横流一葦航，歸日三秋促。", "屬驂饒陽道，解鞅獲館穀。", "鳴烏尾畢逋，喜信亂城角。", "邑中二三子，彼美温如玉。", "行李往來者，東道禮尤篤。", "一尊相勞苦，桃瓜間紅綠。", "深嚴布金地，良可避蒸溽。", "呼龍勸客留，雨聲裂華屋。", "諸公氣吐虹，不鄙余錄錄。", "號呶叫博盧，露跣圍弈局。", "漫郎本何者，蒿蓬倚松竹。", "更不效天隨，凄其茹杞菊。"]'),
('47d51c2e-77a7-4912-87ad-044fe11faacd','湖山紀遊','王安中','宋','宋诗','song-poetry','','["\u897f\u6e56"]','吳山東南秀，葱鬱盤帝城。',288,'全唐诗/poet.song.80000.json','["吳山東南秀，葱鬱盤帝城。", "西湖據其趾，御氣通波心。", "餘膏被草木，蔚眼皆欣榮。", "今晨天宇穆，惠風汛初晴。", "春色正妍妙，放懷共揚舲。", "中流入汗漫，曠闊無埃氛。", "湖光挾山綠，倒射玻瓈青。", "絲竹響空翠，樓觀森崢嶸。", "獻酬雜歌嘯，爛漫紛醉醒。", "取樂固莫並，興懷一何深。", "緬惟昔三賢，精爽日以沉。", "但餘畫象在，尚想鳴佩襟。", "希古秉微尚，崇雅攄恬情。", "羌予翳蓬藋，無復企組纓。", "澹泊自有得，榮華非所欣。", "舍舟縱散策，逸興生崚嶒。", "白雲引遐眺，碧岫延深登。", "幽期浩無涯，忽到静者門。", "長松有令姿，流水無俗聲。", "絕磴猿可呼，出谷鶯始鳴。", "乃知物外境，兹象本不驚。", "逝耶初無將，至耶亦無迎。", "便將謝塵鞅，兹焉支頹齡。", "山鴉接晚翅，落日催行幐。"]'),
('89c9bfb1-6e0d-46ae-8635-3c92d228eccf','貽梁東卿激','王安中','宋','宋诗','song-poetry','','[]','結髪抱奇趣，被褐深自珍。',120,'全唐诗/poet.song.80000.json','["結髪抱奇趣，被褐深自珍。", "空腸貯明月，坐友千載人。", "長饑爲驅出，宦遊古河濵。", "侵尋簿領書，陸海縱埃塵。", "深迷誰復見，無悶日湮淪。", "使車重皇眷，賓從實要津。", "平生相與昧，數面輙成親。", "如何冰霜别，邂逅梅柳春。", "我來閉空館，公歸柅輕輪。", "咫尺不得語，寤歎良苦辛。"]'),
('6446a3d9-4a0f-41f3-855c-32b61358507d','送曹文叔','王安中','宋','宋诗','song-poetry','','[]','讀書無見功，要足補吾拙。',120,'全唐诗/poet.song.80000.json','["讀書無見功，要足補吾拙。", "時從千載上，坐友萬人傑。", "心源貯古月，表裏湛空澈。", "政緣老懶故，早覺追隨苶。", "推遷懷短檄，甚愧固窮節。", "安陽耆舊衰，風采漫筆舌。", "翩翩阿瞞孫，乃出諸椽列。", "爽氣不可招，敵榜近縲紲。", "只今官罷休，道學歸澡雪。", "加飱一言足，人事會有别。"]'),
('21852d01-fab0-4557-8ad1-c9894da35931','奉酬李道源供奉','王安中','宋','宋诗','song-poetry','','[]','斯人倘遇真，何必吾黨士。',240,'全唐诗/poet.song.80000.json','["斯人倘遇真，何必吾黨士。", "向來風騷伯，領略罄同軌。", "仙路共飛騰，雞犬近天咫。", "但看横槊語，力足走餘子。", "小詩賦競病，政自賢乎已。", "眼中管陶郎，翰墨頗自喜。", "當官故癡絕，捉扇談名理。", "早時隨計偕，晚墮鶡冠裏。", "史君柱後文，此面惡難擬。", "陸機生不識，尚想汗顔泚。", "只今官罷閑，高唱動連紙。", "齊西井邑富，三月花事起。", "人奇渼陂同，物勝斜川似。", "遠心破城府，快論注弦矢。", "嗟予懷檄書，寸步畏瓜李。", "投床夢婉娩，日永貪睡美。", "亦思陪君嬉，静釣濠梁水。", "君方事箠轡，問津從隗始。", "十年投筆興，氣已無萬里。", "努力就功名，爵禄天下砥。"]'),
('610e697b-53a6-434c-8609-67efae195884','次韻李達之十月十九日風一首','王安中','宋','宋诗','song-poetry','','[]','葛製侵中冬，奈此河漢沍。',108,'全唐诗/poet.song.80000.json','["葛製侵中冬，奈此河漢沍。", "障門恃織蒲，更值飛廉怒。", "舂撞不遺力，既發寧却顧。", "陰機足自由，盛氣尚誰怖。", "老心百念灰，一睡美無度。", "投牀逼窗紙，罅穴響交互。", "飄霙半夜入，方夢踏雲路。", "帝居環玉闕，恍惚非常遇。", "回天力故微，訟風詞已具。"]'),
('445bd7db-928a-457b-940e-5ada7397e6f0','次韻李達之冬日自紀二首  其一','王安中','宋','宋诗','song-poetry','','[]','短長不相懸，視此律筒換。',84,'全唐诗/poet.song.80000.json','["短長不相懸，視此律筒換。", "天寒今幾許，冬序已强半。", "初陽來如縷，殘歲去莫絆。", "親交斷還往，官列閙稱喚。", "無牛可扣角，問夜何時旦。", "新詩當美酒，排遣孤悶散。", "風期終未沬，相與遊汗漫。"]'),
('1b31f70e-0807-4a20-aca2-2663afdfb7b7','次韻李達之冬日自紀二首  其二','王安中','宋','宋诗','song-poetry','','[]','古心出古語，不計彼不聽。',96,'全唐诗/poet.song.80000.json','["古心出古語，不計彼不聽。", "蹮蹮來問學，政有童九齡。", "尚爲一事大，更讀四方經。", "但我鮮兄弟，諸妹亦伶俜。", "皇皇門户寄，孤耿如晨星。", "何時休世網，遂逐鴻俱冥。", "君窮坐如醉，聞此或少醒。", "試憑道力勝，兩忘楹與莛。"]'),
('3c29d38e-de59-4932-95ed-682f5b8bcc99','達之質衣不售作詩某次韻達之有田在蒲陰日以侵削舊居嘗質人家既還而井亡于是簞瓢益艱故有爭畔改井之嘲','王安中','宋','宋诗','song-poetry','','[]','顔癯雖叵堪，幸列聖科四。',240,'全唐诗/poet.song.80000.json','["顔癯雖叵堪，幸列聖科四。", "瓢簞顧自給，所樂真細事。", "君窮欲誰依，月旦無高議。", "鄰貪故爭畔，囷收復易匱。", "吏懵輒改井，甖汲亦難致。", "空有能詩聲，度越侯叔起。", "時裁乞米帖，韻綴古風裏。", "嬌憐啼門兒，愠奈曳泥婢。", "喧喧聞發廩，共詬管城子。", "君云姑安之，吾肯屑嘑爾。", "篋中敝袍在，質當今可以。", "櫺窗豕腹生，列肆跨兩市。", "掉頭相閉拒，竟日却携至。", "似云儒酸慳，所得毫髪利。", "寒暑遞回換，錢出幾還此。", "由來刺繡工，不如市門倚。", "以彼居貨心，必求速化理。", "近聞高貲郎，禁與士夫齒。", "蓋防駔儈態，歲久薰蕕似。", "衆富乃良規，力古貧莫恥。"]'),
('632f7fee-8560-4bd9-9a79-8a5c428dc2fd','顔夷仲有次韻少無適俗韻詩少逸既和之不可不賦','王安中','宋','宋诗','song-poetry','','[]','少無適俗韻，市朝等居山。',120,'全唐诗/poet.song.80000.json','["少無適俗韻，市朝等居山。", "所思魯柳惠，去我今千年。", "官曹不厭卑，危慮忘冰淵。", "身恬道故在，心傲蒙漆園。", "顔丞賞我趣，屢顧塵埃間。", "我久作常語，何得君來前。", "東歸散俄頃，翩若風中煙。", "此意念莫領，搔髪空垂顛。", "出門久無味，不如杜門閑。", "君方篤行李，諒以吾言然。"]'),
('3dfb58ef-1908-42fb-899b-1656ebb45b14','次秦夷行觀老杜畫像韻','王安中','宋','宋诗','song-poetry','','[]','寒拆天吳圖，饑糴太官粟。',228,'全唐诗/poet.song.80000.json','["寒拆天吳圖，饑糴太官粟。", "拾遺官在朝，何異老林麓。", "英風想廉藺，妙手傳顧陸。", "蒙茸頭傾冠，駊騀鐙脱足。", "熊兒與阿叚，左右相扶逐。", "生平經綸具，悵望青蒲伏。", "窮塗付麴蘖，放意謝羈束。", "草堂幸無事，尹騎時見辱。", "清吟動霄堮，逸艶驚魚目。", "顧兹神明意，豈易丹青卜。", "當時腰長鑱，憔悴十指秃。", "聲名乾坤破，生事歲月促。", "但聞列仙癯，豈見肉食墨。", "企予攀逸駕，短步羞匍匐。", "不能師廣袖，乃爾好奇服。", "嗜詩得雋永，徐味自當肉。", "不知褒公貴，顧謂何郎俗。", "窮通等夢幻，思慮自棖觸。", "苦吟秪效尤，呼醆進蟻綠。"]'),
('0e76de3c-c8af-40ea-85d2-2eb21b7ed9d6','次韻答任德夫夾灘見貺長句并呈崔彦聖','王安中','宋','宋诗','song-poetry','','[]','我本可笑人，略已近俗士。',240,'全唐诗/poet.song.80000.json','["我本可笑人，略已近俗士。", "侵尋久未覺，大似城門軌。", "永懷北山路，相去不容咫。", "雲煙迷舊隱，鷄黍悞幽子。", "極知田二頃，足了仕三已。", "世緣成錯料，悔不妻法喜。", "只今無置錐，四海寄生理。", "因循插手版，俯仰鄴城裏。", "朝來對爽氣，或以古人擬。", "頗復廢將迎，陶泓弄幽泚。", "翩翩取自適，豈問書費紙。", "推移從短檄，此念初不起。", "園林齊地近，人物何郎似。", "無因覩白雉，漫自手弓矢。", "任侯十年舊，邂逅慰行李。", "新詩多態度，譽我傷溢美。", "君才老益豪，筆倒三峽水。", "我將觀浩渺，萬事問伯始。", "是間好看客，風味化鄰里。", "亦知崔亭伯，更欲就礲砥。"]'),
('7c1c4aaf-01a0-425e-92e0-cc73fe2484ab','送晁以道','王安中','宋','宋诗','song-poetry','','[]','人才限南北，河嶽日邊徼。',288,'全唐诗/poet.song.80000.json','["人才限南北，河嶽日邊徼。", "異時頗自振，以遠得輕笑。", "顧我尚友心，與渠不同調。", "吾州向雖陋，屬令文元肖。", "仙鳬謝雲羅，雪浪湧海嶠。", "問山如登天，翰墨相焜燿。", "高標快目擊，勝語醒耳剽。", "永懷種秫潛，不翅憩棠召。", "八年杖屨隔，坐睡夢嵩少。", "何人佀嚴陵，寒灘理幽釣。", "無因接孫登，半嶺聽清嘯。", "漸恐落流俗，中夜回光照。", "倒海覓三珠，更復得二妙。", "風埃鄴王城，晚從折簡召。", "倉曹賓客次，玉立見孤峭。", "神鋒森挺脱，俛嘿願還鞘。", "至今牛斗間，寶氣干兩曜。", "伯宜承華勛，仲合典書詔。", "翩翩誰輩行，官職忽哄叫。", "美鬚草未鬬，好面喪可弔。", "斯人但寂寞，瑚璉不薦廟。", "我嘗當饋嘆，吞憤類牛噍。", "淵龍豈易擾，遽敢議處劭。", "念昔忝聞道，鋭甚冠始醮。"]'),
('4694c774-ec67-41fe-8a72-4529b50a03d3','次韻和彭少逸送晁以道','王安中','宋','宋诗','song-poetry','','[]','吾軍久不張，建鼓覓同道。',288,'全唐诗/poet.song.80000.json','["吾軍久不張，建鼓覓同道。", "蒼黄一二獲，便作百萬號。", "我行初濟河，首得晁彭耗。", "輕車駕駟馬，邂逅王良造。", "悠然望八極，頗已快遠抱。", "兩公前後輩，凜凜不殊操。", "晁文早緯國，輔以家學奥。", "向來宏詞出，古氣軋盤誥。", "蕭生寧抱關，肯補郎衣皂。", "老成吾猶及，孝友神所勞。", "彭詩動驚俗，祖屈實自悼。", "追奇詣岑險，展讀眩欲眊。", "知名漁父篇，雅惬志和好。", "勿前丞相嗔，何恃翰林傲。", "方將摩二壘，併可潄雙瀑。", "瓜代苦敦薄，火攻良抵冒。", "荆州一人半，纔慰阿堅到。", "只今事行李，遽欲戒騶導。", "箕山老仙伯，遠行避喧噪。", "紛紛户外屨，三沐安無躁。", "仲氏往吹箎，吾黨端有靠。", "坐念玉壺冰，詎堪風日曝。", "魯公屋漏筆，莫靳平安報。", "否泰等時雨，春旱必秋澇。"]'),
('196c625f-f34a-4c6f-857e-5a75ea57b71b','長句送以道既辱和答而夏傳聖詩亦用此韻以道復和一篇篇末頗及少逸與不肖因再賦此傳聖姻家書問必數或可達以道','王安中','宋','宋诗','song-poetry','','[]','癯儒緩趨走，不堪備游徼。',288,'全唐诗/poet.song.80000.json','["癯儒緩趨走，不堪備游徼。", "古心乏嫵媚，亦莫齒優笑。", "十年營負郭，畢願了租調。", "詩書祝兒輩，風味久必肖。", "文窮覓退之，錢癖減和嶠。", "此計墮渺茫，浪出豈炫燿。", "官供取無耻，幾不類椎剽。", "退食獨委蛇，顧欲輩周召。", "誰論玄尚白，端覺壯非少。", "緬懷千載人，有道混屠釣。", "風雲隨闊步，功業付長嘯。", "事成有辭爵，緣斷或遺照。", "飛潛無必同，出處信俱妙。", "肯以牛衣泣，求因狗監召。", "竟知貂尾短，何益鳶肩峭。", "士初如大刀，天高看拔鞘。", "提携龍雀環，膽破勒與曜。", "斷蛟剸犀兕，左右隨所詔。", "用舍要有時，遽欲帝閽叫。", "沾襟豈終悔，失馬勿前弔。", "龜寜行曳泥，犧怯牽荐廟。", "但逃明火灼，詎厭短芻噍。", "固窮而山立，吾儕當勉劭。", "無禍福莫長，安用綠章醮。"]'),
('ba10f604-dca6-406f-b2fe-ef162df970a7','李永終還京師北嶽王某以送晁以道韻作詩贈行某外大父賢良裴公實爲邯鄲公行狀契義良厚故見之篇首','王安中','宋','宋诗','song-poetry','','[]','外家東眷裴，典學不觀徼。',288,'全唐诗/poet.song.80000.json','["外家東眷裴，典學不觀徼。", "初來接諸彦，半發士龍笑。", "賢科兩過閣，萬字出戲調。", "盡記十二題，博洽古人肖。", "亡書問安世，多識數華嶠。", "劉蕡廷策訐，罷去終弗燿。", "縱横五車讀，未捷一律剽。", "生涯日蕭索，更甚東陵召。", "當時邯鄲公，似是洛陽少。", "文潤淮南草，詩賡苑中釣。", "殿廬忽厭直，郡閤或坐嘯。", "相從賓客老，莫逆肝膽照。", "嚴詩見杜集，殆極天下妙。", "鵩來蒲州坐，永隔宣室召。", "門生状董晉，寒筆信雄峭。", "豈慚吳季札，墓劍掛遺鞘。", "嗟予乃裴出，母賢如德耀。", "授予其父書，勉使起應詔。", "此文載編末，疾讀快欲叫。", "耆舊成鬼錄，零落真可弔。", "但聞康靖第，萬物閟家廟。", "子孫同蠹魚，奇字飽咀噍。", "始予識京掾，已嘆才業劭。", "叔兮秉周禮，莊若客位醮。"]'),
('f94a91e3-e984-473a-a8ef-0747b9bb8524','定武贈晁以道','王安中','宋','宋诗','song-poetry','','[]','北山立雄秀，西山儼來奔。',240,'全唐诗/poet.song.80000.json','["北山立雄秀，西山儼來奔。", "稜層上雲雨，祕邃錯朝昏。", "風霆倐號怒，勢欲立厚坤。", "兹惟神靈宅，可但人物繁。", "嵩陽擅月旦，問山等龍門。", "謂我山之英，重以仁者言。", "丈人蓋代手，脱口千載存。", "蓴羮與羊酪，不復疑戲論。", "向來無極神，解與君爭尊。", "堂堂甄孟成，版籍見諸孫。", "如何置不問，遠借寒谷暄。", "我行傍鄉梓，念此永弗諼。", "逢人試語似，喜色凌朝暾。", "問公誰輩行，故侯蘇季昆。", "故侯遺妙墨，礱山龕山軒。", "亦有好事人，醉帖收蜿蜒。", "神明坐還觀，聲淚已復吞。", "公能破紙尾，師友道彌敦。", "要當藏名山，仍意作九原。", "續絃煎麟角，併洗萬古冤。"]'),
('138684d6-05dc-40f9-905f-d89816f35d86','顔持約爲范師厚作孔明坐嘯圖十大比丘象觀者以爲聱訛不可不下一句','王安中','宋','宋诗','song-poetry','','[]','窮顔妙畫今虎頭，忽以武侯爲范侯。',64,'全唐诗/poet.song.80000.json','["窮顔妙畫今虎頭，忽以武侯爲范侯。", "他日卻寫十比丘，下筆不數僧貫休。", "作佛作相三昧游，在江在海兩浮漚。", "丈夫心機入法流，到處還渠第一籌。"]'),
('9a5ba7c1-7238-409d-9be4-fb6816dc7a52','寄謝任伯','王安中','宋','宋诗','song-poetry','','[]','盛樂宫前紫府君，開花流水不知春。',96,'全唐诗/poet.song.80000.json','["盛樂宫前紫府君，開花流水不知春。", "悠悠永歎坐石室，自有此山無此人。", "我來婆娑弄明月，松聲草色俱清新。", "列仙元癯不佞佛，却語小謝求綸巾。", "明經使者風生在，文字政須君等輩。", "鴈門鴈美亦思歸，講肄還當尋馬隊。"]'),
('91c33612-3d21-491f-9965-7a558b5e4b72','寄江南睡翁','王安中','宋','宋诗','song-poetry','','[]','金鳯臺頭我欲仙，故人真謂翼垂天。',64,'全唐诗/poet.song.80000.json','["金鳯臺頭我欲仙，故人真謂翼垂天。", "目光射落三千尺，詩律追還五百年。", "應緣又踏瀛州土，寄問騎鯨今好否。", "俗情限量須破除，可無忘形我與渠。"]'),
('eca9d7a1-ed3a-4907-b9cd-96630165d4e6','崇寧寺詩','王安中','宋','宋诗','song-poetry','','[]','周郎同歲小一月，老氣凜凜能摧鋒。',64,'全唐诗/poet.song.80000.json','["周郎同歲小一月，老氣凜凜能摧鋒。", "佛隱由來足高士，經綸正在阿堵中。", "平生蓬藋一畝宫，頗與可人風味同。", "好在江南香火社，寄書會憶王牆東。"]'),
('e1b5441e-e478-4521-b994-981cf0c1af6e','次韻張應龍見贈長句','王安中','宋','宋诗','song-poetry','','[]','深居聽客譚西山，舌端崷崒生層巒。',96,'全唐诗/poet.song.80000.json','["深居聽客譚西山，舌端崷崒生層巒。", "山形卓犖尚可想，客趣超詣何由攀。", "漳潁空回自不韻，夢涉山澗波旋環。", "但携雲根萬竅碧，歸置毛穎陶泓間。", "客真與山欲爭秀，煙霞氣足詞高閑。", "我亦良非適俗者，分山一半同君還。"]'),
('62a7d756-a4d9-4222-8c82-d635f9dfe85e','同元忠少逸登大安閣各賦一篇','王安中','宋','宋诗','song-poetry','','[]','胸中堆奇忽塊磊，徑欲凴虚尋我對。',128,'全唐诗/poet.song.80000.json','["胸中堆奇忽塊磊，徑欲凴虚尋我對。", "梵宫日月擦鴟尾，複道雲霓湧鼇背。", "佛將高廣快心賞，天爲空長舒眼礙。", "冰層蹙岸見河漳，雪氣明山數齊岱。", "安知一身寄城郭，却指萬頂看闤闠。", "承平大駕昔此留，望幸遺民今幾在。", "哦詩人物到白也，題字風流希湛輩。", "北都三士行作圖，勝遊一日不可廢。"]'),
('d84d7b74-1bff-4317-a1b1-0fc9c754d093','顔夷仲欲赴藍田丞而鄆帥移雍姻家或當避讀夷仲詩爲和第二篇此次退之山石韻者','王安中','宋','宋诗','song-poetry','','[]','秋蟲不量翅股微，幾欲唐突鵷鸞飛。',160,'全唐诗/poet.song.80000.json','["秋蟲不量翅股微，幾欲唐突鵷鸞飛。", "高梧嘶風食沆瀣，何似死鼠鴟鳶肥。", "顔家事業更清絕，耆舊去眼知音稀。", "賢哉鼻祖井故在，執瓢便足忘君饑。", "一官晚悔登龍斷，經歲不出關荆扉。", "藍田之山石韞玉，白虹千丈晴霏霏。", "退之壁誌見彷彿，二松閲世應百圍。", "丞聾未換渠莫惡，郴江仙伯容摳衣。", "側聞親嫌又齟齬，漫恐髀肉摩鞍鞿。", "戲人造物亦薄相，咄咄此士將安歸。"]'),
('a5d9f561-67c0-4e3d-a89e-2b1cb2b16c06','趙聖符權漣水軍使按周立事且去猶聞上乞不赦爲作長句','王安中','宋','宋诗','song-poetry','','[]','潁川異日剛彊守，諸吏僵仆姦豪走。',176,'全唐诗/poet.song.80000.json','["潁川異日剛彊守，諸吏僵仆姦豪走。", "濟南使君羞怯懦，故破瞷宗三百口。", "官爲聲名計則多，尋常手滑如彼何。", "心知昔人不妄作，隨事砭斫或拊摩。", "河神娶婦理必往，城北殺子吾當訶。", "襄濆趙侯世儒雅，軒昂忽變腸無它。", "奴欺主女積十載，侯以半紙申嚴科。", "人言趙侯廣漢後，宜有擿伏如神手。", "青衫諸掾日蹉跎，衆或屈凌天自佑。", "誰過襄濆刻石傍，告以吾言慰耆舊。", "侯今兒子能文章，母太夫人百歲壽。"]'),
('6851cfb9-958c-4fe1-90e9-69a927bf6e36','過客有贈達之金者達之作鮒魚乞水急詩謹次韻','王安中','宋','宋诗','song-poetry','','[]','李侯茫茫悲欲泣，人生豈能無緩急。',176,'全唐诗/poet.song.80000.json','["李侯茫茫悲欲泣，人生豈能無緩急。", "晨炊米盡抱衾裯，富兒操金森壁立。", "縱横文字對空虛，肝膈不同如燥濕。", "寒鄉眼界太褊迫，名譽纔高憎怨集。", "誦書把琖九河懸，雖我亦驚追莫及。", "風雷會送横海鱣，躍上禹門過千級。", "奈何自比轍中鮒，商歌感慨行人揖。", "鮒魚不願决西江，李侯所須惟粟粒。", "肯捐一滴活波臣，客真義動修蛇蟄。", "得金遣客曾莫留，索我和篇何汲汲。", "孤竹之管空桑琴，已矣今人聽不入。"]'),
('2d269e9a-8255-428f-bd2c-6df5ad4169ed','第二子赴河間詩人皆作詩送行讀趙壻辟疆詩爲次韻','王安中','宋','宋诗','song-poetry','','[]','家世無人仕苕浙，送汝還爲北城别。',192,'全唐诗/poet.song.80000.json','["家世無人仕苕浙，送汝還爲北城别。", "河間知不去吾遠，汝母猶持離袖掣。", "中年生子今宦游，吾與汝母宜白頭。", "中山西望三舍身，諸老汝近吾何愁。", "宫傅恩憐逮猶子，宫師雁行餘五弟。", "至今鄉閭尚心化，友愛推高一門裏。", "向來寒甚草根蛩，邇來出入軒蓋從。", "富貴不願此身獨，安樂幸與諸老同。", "門户固應多國器，汝往豈爲功名會。", "古文科斗盡五車，娱人翰墨真餘事。", "客程搶笠風卷紗，歸及諸老醉榴花。", "京華新聞勿用說，一時名士詩可誇。"]'),
('83e6c342-e18d-48ab-be09-48feff2e38d4','題李成山水','王安中','宋','宋诗','song-poetry','','[]','五日十日一水石，此言雖工蓋其跡。',224,'全唐诗/poet.song.80000.json','["五日十日一水石，此言雖工蓋其跡。", "請看天地開闢初，豈鑄日魂鎔月魄。", "忽然而成隨所遇，納護風雲元滿肚。", "吐爲千偈口瀾翻，游戲法中同一趣。", "李侯落筆風烟氣，妙處欲回真宰意。", "扁舟不動水粘天，落日孤明山若倚。", "斷猿吟掛清楓林，澗松倒卧猶十尋。", "白鷗似作終老計，浮雲自在年何深。", "由來神品完天力，一抺江流吞萬磧。", "寸量尺度但形摹，畫史如山爾何得。", "貴人費盡千黄金，寶奩玉軸誰敢爭。", "一聲常賣落公手，世間得喪誰虧盈。", "我生懶率更疏放，只有幼輿巖石相。", "它時真作畫中人，儻辱書來問無恙。"]'),
('bebf2d7b-fdab-4726-9836-b4d777dd3f29','次韻題李公休輞川圖','王安中','宋','宋诗','song-poetry','','[]','山林策足高復高，俗子捷宦爭秋毫。',288,'全唐诗/poet.song.80000.json','["山林策足高復高，俗子捷宦爭秋毫。", "丹青邂逅着相衮，晚顧不欲傳兒曹。", "妙哉吾家右丞相，睥睨一世輕鴻毛。", "雲泉招隱去甚勇，粉墨狀景隨所遭。", "輞川莊圖最得趣，盡寫衆巘圍長臯。", "廢城荒煙颯衰柳，斷澗立石淙驚濤。", "篔簹插屋伴幽讀，蓮芰潑眼横輕舠。", "宫槐猶是鳴騶陌，漆園已作蒙莊逃。", "地因人好自奇勝，豈必海嶠騫鯨鼇。", "想見解衣盤礴時，六種震動山靈號。", "平生經行意境足，朽木不運筆已操。", "小詩氣象更清絕，遠跨陶謝追風騷。", "樂安老人吾莫及，摹搨彷彿收藏牢。", "隸書十詠有體法，鍼肆見此古赤刀。", "一時墨妙誰竊去，龍劍飛失餘環絛。", "只今跋題乃到我，千載吾祖安敢褒。", "家鷄詩畫愧弗學，但思卜築誅蓬蒿。", "輞川久無書契在，未免四海求田勞。"]'),
('27368902-2566-4b09-8af9-1746506b5448','大風','王安中','宋','宋诗','song-poetry','','[]','青陽乘時木當行，驟辭囚幽置高亨。',384,'全唐诗/poet.song.80000.json','["青陽乘時木當行，驟辭囚幽置高亨。", "驁驕嫚姣豪怒獰，睥睨萬物憤以爭。", "潛呼飛廉語曰卿，媒妁阿巽助躁輕。", "林交社姻窟昆兄，腰領搦持劫詛盟。", "玃顱鷹隼深目睛，沐猴冠元加紘纓。", "約束陰定陽眎瞠，鞴囊革橐齊露呈。", "頃刻翻簸揭奔轟，撦幃裂箔仆斾旌。", "墮簷塌桷掀架棚，注射垣壝穿冡塋。", "豹彪獐豬狒猱猩，鴻鶤雉鴉鳬鳦鶯。", "殷蹏捩翅突奔驚，蹶抵犖确罥灌檉。", "蒙衝千車屹傅城，犦槊萬騎鴉譟營。", "步趨宕跌忘珮珩，宫徴嘈雜停韶英。", "披木榦根搴芳榮，蹙水濤浪豗鏡平。", "眯霄耀靈一目盲，觸山不周八柱傾。", "六幕擺撼始稱情，神嬉鬼笑語咿嚶。", "餘噫不收爛謌賡，聚穢勃鬱封觀京。", "執攬北斗斟四瀛，五嶽爲豆羅崢嶸。", "腐株蠹穴侑竾笙，醉牽月娥舞金鉦。", "更持一杯壽長庚，誰省天意不汝令。", "小臣叫天吐丹誠，方春風暴稀所更。", "執法口噤臣輙抨，幸屬廷尉葅鯢鯨。", "天哀愚忠勑閽丁，往呼來前密訂評。", "竦身躡虛倐上征，涕洟拜手眄睟清。", "臣材瑣屑不足名，中有婞直肝腸撐。"]'),
('03b7b9cb-d799-478c-9d0a-c6e047b3a527','游峰山院','王安中','宋','宋诗','song-poetry','','[]','蕭寺倚絕壁，高軒凴衆芳。',48,'全唐诗/poet.song.80000.json','["蕭寺倚絕壁，高軒凴衆芳。", "僧窗得山翠，茗盌仍花香。", "眼界寫雙凈，心田增寸凉。", "陂陀日向夕，村落下牛羊。"]'),
('aabd58d9-fbdf-42f8-9086-e8ce48a620d0','次韻李厚之秋日即事','王安中','宋','宋诗','song-poetry','','[]','當暑獨披襟，誰同梁甫吟。',48,'全唐诗/poet.song.80000.json','["當暑獨披襟，誰同梁甫吟。", "山林勞客夢，簾幕斷人音。", "庭籟迎秋靜，宫雲傍晚陰。", "賴傳詩句好，偏慰未歸心。"]'),
('27a14a3f-eebf-43b2-9059-66d6adbe4f10','試院作','王安中','宋','宋诗','song-poetry','','[]','身入儒宫作抱關，不妨文史暫偷閑。',64,'全唐诗/poet.song.80000.json','["身入儒宫作抱關，不妨文史暫偷閑。", "秋陽皦皦天新雨，晚吹騷騷木落山。", "士子便應矜兩監，吾儕未合老三間。", "孝廉同歲真同道，對幕哦詩斷往還。"]'),
('41978f55-2710-40a5-8a3b-21ab078f679b','聞青守梁元彬移帥定武作詩寄賀諸梁','王安中','宋','宋诗','song-poetry','','[]','相門誰數十朱輪，華鄂今看節制分。',64,'全唐诗/poet.song.80000.json','["相門誰數十朱輪，華鄂今看節制分。", "鄉里正思前召父，朝廷難輟大馮君。", "風聲自是塤箎合，忠力同輸手足勤。", "應有池塘春草夢，夜闌還繞北山雲。"]'),
('9fffc4cc-8c4c-4f0d-add6-d9f19a42c589','聞帥府大閲軍作詩送梁帥','王安中','宋','宋诗','song-poetry','','[]','坐想郊坰皷角雄，弓刀十萬擁元戎。',64,'全唐诗/poet.song.80000.json','["坐想郊坰皷角雄，弓刀十萬擁元戎。", "令傳帳下偏裨慄，聲走山前部落空。", "勒石何須稱竇憲，反風已卜相周公。", "自嗟不預從軍樂，賈勇猶能氣吐虹。"]'),
('ea074eca-ed61-4807-9a1c-1f42dd9b22d2','和梁才甫贈定帥元彬','王安中','宋','宋诗','song-poetry','','[]','汶水衣冠記昔年，明堂一木起扶顛。',64,'全唐诗/poet.song.80000.json','["汶水衣冠記昔年，明堂一木起扶顛。", "孫枝競秀傳家學，華鄂聯榮握帥權。", "西省規摹留閫外，北園風景付樽前。", "晉陽親近皆兄弟，行集天朝拱細旃。"]'),
('e5e51ccc-942d-413f-a4d8-1a9f8c198e74','無題','王安中','宋','宋诗','song-poetry','','[]','玉府真游擁萬仙，蘂珠深殿駐雲軿。',64,'全唐诗/poet.song.80000.json','["玉府真游擁萬仙，蘂珠深殿駐雲軿。", "宫尊自吸瓊漿盡，御筆猶封寶字全。", "密護幾重香冉冉，倒藏餘瀝響涓涓。", "君恩許侍神霄仗，先向壺中覓洞天。"]'),
('cbc7818b-aded-4961-8370-1579558bb407','讀次文渼陂詩','王安中','宋','宋诗','song-poetry','','[]','白髪郎潛舊令君，東軒携酒幾回登。',64,'全唐诗/poet.song.80000.json','["白髪郎潛舊令君，東軒携酒幾回登。", "當初天上化鳬舄，今日人間下馬陵。", "邊地久無能賦筆，縣齋新有讀書燈。", "昔游零落岑參在，故語流傳許十稱。"]'),
('9325ded4-a62b-4ac8-b6d6-ffee256bb39e','次韻魏端夫田石送赴試詞學兼茂','王安中','宋','宋诗','song-poetry','','[]','謝韞歸寧雪載塗，新詩還道絮何如。',64,'全唐诗/poet.song.80000.json','["謝韞歸寧雪載塗，新詩還道絮何如。", "時因公子監門會，頗識中郎阿大餘。", "賦筆久無三峽水，囊書老趁獨輪車。", "只今靖郭家兒舍，誰似先生食有魚。"]'),
('8034d942-9d63-4ca4-b736-064e7c146a79','澶簽宗室伯言見寄爲次韻','王安中','宋','宋诗','song-poetry','','[]','賓客風流追七子，宗支文物笑諸郎。',64,'全唐诗/poet.song.80000.json','["賓客風流追七子，宗支文物笑諸郎。", "青藜吹燭書編亂，古錦作囊詩卷長。", "禪鉢芋羮聊得共，壽杯酥酒故催忙。", "秪今霜雪休車馬，誰對熏爐語夜堂。"]'),
('1c1ea229-bdfc-49bd-8683-d1102625528e','次韻元量貺詩','王安中','宋','宋诗','song-poetry','','[]','野性由來不受羈，可堪風雨斷追隨。',64,'全唐诗/poet.song.80000.json','["野性由來不受羈，可堪風雨斷追隨。", "卜鄰有素須歸隱，會面無多更話離。", "拜我低頭要晚歲，仗公取水記當時。", "魏城邂逅猶惆悵，秋鴈横分奈土思。"]'),
('03fb4b8b-5a3e-4597-b9f9-0ae0669d968f','送徐幹臣','王安中','宋','宋诗','song-poetry','','[]','聲華飛動水雲鄉，揮翰初宜玉作堂。',64,'全唐诗/poet.song.80000.json','["聲華飛動水雲鄉，揮翰初宜玉作堂。", "投老肯留賓客榻，臨分聊屬聖賢觴。", "家山到眼千巖秀，世路收心一粒藏。", "趣駕青牛尋尹喜，著書方便設津梁。"]'),
('a5e35b87-5ebc-4ebe-b9ee-3f67f8f64183','次韻道勝冬日惜别之作','王安中','宋','宋诗','song-poetry','','[]','相逢不作白頭新，肯復悠悠問大鈞。',64,'全唐诗/poet.song.80000.json','["相逢不作白頭新，肯復悠悠問大鈞。", "煮茗坐窮西寺日，哦詩驚動北州春。", "吾儕漸可傳書種，兒輩當令洗塞塵。", "節物崢嶸君遂去，驅蛩終始覓何人。"]'),
('069e9394-d1ab-41cb-af8f-d792b0e0fdfe','次韻安喜劉簿上梁才甫瑞蓮嘉禾一首','王安中','宋','宋诗','song-poetry','','[]','早日商霖浹四寰，兩年春令塞垣班。',64,'全唐诗/poet.song.80000.json','["早日商霖浹四寰，兩年春令塞垣班。", "秋清蓮萼駢幽沼，歲稔禾頭合舊山。", "事付史官應制可，曲翻相府看公還。", "王褒要是邦民耳，請頌中和敢自閑。"]'),
('55c0b3d4-9afb-4b92-9a6e-ad57fea3305e','楊時可屢遊朱氏園昨日方一載酒甚樂因次韻言其事','王安中','宋','宋诗','song-poetry','','[]','溪上桃花如有語，怨君前日只空回。',64,'全唐诗/poet.song.80000.json','["溪上桃花如有語，怨君前日只空回。", "徑須留客車投轄，相與澆愁酒漉醅。", "我自馬曹聊復爾，誰憂兒輩覺追陪。", "王郎醉墨題名處，尚有餘尊可再來。"]'),
('0db95169-e1f7-4ee3-b65c-d590d23a7552','次韻和梁才甫上元詩二首  其一','王安中','宋','宋诗','song-poetry','','[]','雪夕張燈白晝同，坐知酒價長新豐。',64,'全唐诗/poet.song.80000.json','["雪夕張燈白晝同，坐知酒價長新豐。", "月來方丈三山外，春在元戎十乘中。", "玉塞已傳台衮拜，火城先看相家風。", "公歸端是千年鶴，回首鵷行一夢空。"]'),
('cf1e7b46-8371-458d-b5a4-33d8b8718ec0','次韻和梁才甫上元詩二首  其二','王安中','宋','宋诗','song-poetry','','[]','陳橋陪乘五人同，劍鋏休彈禮過豐。',64,'全唐诗/poet.song.80000.json','["陳橋陪乘五人同，劍鋏休彈禮過豐。", "驥足爭先長策下，蛇脂乾盡舊山中。", "敢將野句酬明月，但記宸章起大風。", "默對短檠悲晼晚，綈袍恩重報全空。"]'),
('1e00f1c7-96d1-405b-a60c-37d40495dd73','次韻和梁才甫與曾叔夏喜雨','王安中','宋','宋诗','song-poetry','','[]','金節經過玉帳開，初筵風雨燭花摧。',64,'全唐诗/poet.song.80000.json','["金節經過玉帳開，初筵風雨燭花摧。", "鳯凰池外濃雲合，獬豸冠前爽氣來。", "已洗郊原秋淡蕩，不妨星月夜昭回。", "拾遺說尹村村到，盛看豐年社酒杯。"]'),
('5edc662c-f675-4213-ad4b-3338d3bd7486','次韻趙承之九日出郊','王安中','宋','宋诗','song-poetry','','[]','結客西城昔夢長，無題重和不成章。',64,'全唐诗/poet.song.80000.json','["結客西城昔夢長，無題重和不成章。", "老看殘菊情多感，靜數冥鴻首屢昂。", "餻酒故應隨節辦，絲桐政好爲秋張。", "鞭笞鸞鳯饒君去，獨守庭秋坐夕陽。"]'),
('c4552360-d6ef-4f06-891f-1bdb3e6ad435','喜雪贈梁幾道','王安中','宋','宋诗','song-poetry','','[]','風色蕭騷晚尚微，呼龍連夜布寒威。',64,'全唐诗/poet.song.80000.json','["風色蕭騷晚尚微，呼龍連夜布寒威。", "欲尋海上三銀闕，先舞雲中萬玉妃。", "難老松筠增氣槩，未春桃李借芳菲。", "典衣更爲來年賀，潤澤先從宿種歸。"]'),
('5de54228-26e6-4bc8-be55-ffdd042cb64f','觀儺','王安中','宋','宋诗','song-poetry','','[]','天回星斗臘將殘，儺仗歡呼陛盾寒。',64,'全唐诗/poet.song.80000.json','["天回星斗臘將殘，儺仗歡呼陛盾寒。", "逐癘已隨三闋鼓，鍊真何待五辛盤。", "皇居夙有仙官護，民瘼兼凴聖籙安。", "歲歲更修周典禮，都門耆舊喜同看。"]'),
('40f687e7-f52c-4263-9497-a62813f0e4b3','嘉山','王安中','宋','宋诗','song-poetry','','[]','喬木相望十里村，百年弦誦化耕耘。',64,'全唐诗/poet.song.80000.json','["喬木相望十里村，百年弦誦化耕耘。", "食魚誰就田文舍，下馬先經董相墳。", "烏几繙書心自遠，紅旗賽社酒初醺。", "何時結客嘉山路，剥啄敲門却訪君。"]'),
('c8f7731e-a4ad-4ab4-b649-ef9aa54bf3d1','次韻梁才甫游苑氏園  其一','王安中','宋','宋诗','song-poetry','','[]','地僻風光到後時，誰吹律琯轉陽暉。',64,'全唐诗/poet.song.80000.json','["地僻風光到後時，誰吹律琯轉陽暉。", "花爭先近三台坐，春敢輕隨一片飛。", "肯爲孤妍回鐵石，那憂餘賞間葑菲。", "它年造物因依在，領略吾州勝槩歸。"]'),
('fe6b666b-4a58-40de-91f0-1f3b47630ec4','次韻梁才甫游苑氏園  其二','王安中','宋','宋诗','song-poetry','','[]','國色無媒出有時，幾年幽户鎻寒暉。',64,'全唐诗/poet.song.80000.json','["國色無媒出有時，幾年幽户鎻寒暉。", "人從浴鳯池邊到，香入乘鸞扇底飛。", "詩落雲牋傳藉藉，花同錦隊想菲菲。", "更聞芍藥梢頭信，亦待邀公插帽歸。"]'),
('30581e3d-4140-44c6-9897-5bd8b8973c42','次韻梁跂道游苑氏園  其一','王安中','宋','宋诗','song-poetry','','[]','晴日催花爛漫開，九苞丹鳯引雛來。',64,'全唐诗/poet.song.80000.json','["晴日催花爛漫開，九苞丹鳯引雛來。", "春衫碧袖初單際，步障朱軿第二回。", "許掾登仙全室伴，謝公賭墅幾人陪。", "明年此樂知何處，宣勸重持翡翠杯。"]'),
('84705bff-c5c1-4ae2-b761-9896822b2b43','次韻梁跂道游苑氏園  其二','王安中','宋','宋诗','song-poetry','','[]','淵明歸侣獨龐通，坐客何人對孔融。',64,'全唐诗/poet.song.80000.json','["淵明歸侣獨龐通，坐客何人對孔融。", "鸎燕不驚賢者樂，蕙蘭爭泛快哉風。", "斑衣人在飄香外，彩筆詩成徒步中。", "和語不工緣窘陋，腐儒家巷草蒙戎。"]'),
('0e45b07d-d8c9-4d70-8667-917a0b70e182','試院作  其一','王安中','宋','宋诗','song-poetry','','[]','落葉飛飛度暗階，月簾風幔若爲懷。',32,'全唐诗/poet.song.80000.json','["落葉飛飛度暗階，月簾風幔若爲懷。", "瑣窗未有歸消息，應罥蛛絲上雀釵。"]'),
('010d44fa-f80e-4635-bd22-cd5226b46917','試院作  其二','王安中','宋','宋诗','song-poetry','','[]','秋屋無人見草經，忽驚太乙杖藜青。',32,'全唐诗/poet.song.80000.json','["秋屋無人見草經，忽驚太乙杖藜青。", "秪應燒燭金鑾殿，未勝熏香石竹屏。"]'),
('17ce0142-735d-4902-b31f-c556f13d1472','春日館中即事五首  其一','王安中','宋','宋诗','song-poetry','','[]','求友何人似谷鶯，羈游渾覺昧平生。',32,'全唐诗/poet.song.80000.json','["求友何人似谷鶯，羈游渾覺昧平生。", "閉門春事關身薄，薺菊青青自可羮。"]'),
('278d21c0-80c9-4b4a-8531-ff2935dfbfa5','春日館中即事五首  其二','王安中','宋','宋诗','song-poetry','','[]','暄寒稀復故人書，好在山中舊酒壚。',32,'全唐诗/poet.song.80000.json','["暄寒稀復故人書，好在山中舊酒壚。", "端欲夢從三徑去，方牀投枕展龍鬚。"]'),
('38efbcf0-cdfc-48c4-be74-3904b83358c9','春日館中即事五首  其三','王安中','宋','宋诗','song-poetry','','[]','故國悠悠雪外城，南山應復見高稜。',32,'全唐诗/poet.song.80000.json','["故國悠悠雪外城，南山應復見高稜。", "向來梅柳春亭月，曾傍詩書夜按燈。"]'),
('dba8601d-f01a-46dc-b6e8-cd7f2ae2fe1e','春日館中即事五首  其四','王安中','宋','宋诗','song-poetry','','[]','元夕嬉遊遍海涯，上林風物弄年華。',32,'全唐诗/poet.song.80000.json','["元夕嬉遊遍海涯，上林風物弄年華。", "餘霙墮柳高低舞，香蠟封梅早晚花。"]'),
('94bfb878-c522-40cb-9098-f8a4fb7c3ec9','春日館中即事五首  其五','王安中','宋','宋诗','song-poetry','','[]','熙熙人物爇金爐，歌舞升平六閏餘。',32,'全唐诗/poet.song.80000.json','["熙熙人物爇金爐，歌舞升平六閏餘。", "輦路雪晴雲五色，史臣得記汗青書。"]'),
('caf622af-70f9-4777-8e56-eb2af62bd977','直舍有書  其一','王安中','宋','宋诗','song-poetry','','[]','晚風收雨故森森，雀啅鴉驕未解陰。',32,'全唐诗/poet.song.80000.json','["晚風收雨故森森，雀啅鴉驕未解陰。", "車馬不喧緣底事，道人宴坐即山林。"]'),
('19e7b14d-7c1d-4c23-89e0-c32fbc55999f','直舍有書  其二','王安中','宋','宋诗','song-poetry','','[]','林低野闊暝煙浮，似與幽人耳目謀。',32,'全唐诗/poet.song.80000.json','["林低野闊暝煙浮，似與幽人耳目謀。", "邂逅前身溧陽尉，欲將半俸博冥搜。"]'),
('9aff8c64-3071-4ebf-81f3-128dfa3cc57e','直舍有書  其三','王安中','宋','宋诗','song-poetry','','[]','右丞筆力到諸孫，詩語元勝畫不言。',32,'全唐诗/poet.song.80000.json','["右丞筆力到諸孫，詩語元勝畫不言。", "看取疏疏并寂寂，霜林煙塢欲黄昏。"]'),
('d7ecd800-dd8f-4a4f-acf8-5648f68b4886','直舍有書  其四','王安中','宋','宋诗','song-poetry','','[]','年來方寸湛如水，照見霜空無一塵。',32,'全唐诗/poet.song.80000.json','["年來方寸湛如水，照見霜空無一塵。", "寫出禪家有眼句，不妨餘事作詩人。"]'),
('a2da7bf6-23e9-4601-a907-938ef68d6277','河西勘稻','王安中','宋','宋诗','song-poetry','','[]','據鞍不覺醉中鄉，水陸紛紛利害長。',32,'全唐诗/poet.song.80000.json','["據鞍不覺醉中鄉，水陸紛紛利害長。", "便作河西勸農使，夢回應未熟黄粱。"]'),
('9f54e02c-fb38-4e62-a219-7052255f51f9','予行爲魏倉監門忽得前監倉官詩人江南彭少逸詩因次韻時彭以遺火失官  其一','王安中','宋','宋诗','song-poetry','','[]','聞道長安桂作薪，斗升誰乞向隅人。',32,'全唐诗/poet.song.80000.json','["聞道長安桂作薪，斗升誰乞向隅人。", "魏倉一炬非無爲，似與寒枯慰晚春。"]'),
('c63851a0-dd76-42c2-93c9-8699d0d7fe42','予行爲魏倉監門忽得前監倉官詩人江南彭少逸詩因次韻時彭以遺火失官  其二','王安中','宋','宋诗','song-poetry','','[]','廟堂鼎實待鹽梅，幕府千金政築臺。',32,'全唐诗/poet.song.80000.json','["廟堂鼎實待鹽梅，幕府千金政築臺。", "孟子勸人蕭傅作，抱關不必是凡才。"]'),
('f2a9b827-58bf-4bab-8358-088602de345a','立春  其一','王安中','宋','宋诗','song-poetry','','[]','城頭雲樹不藏鴉，邂逅東風苦憶家。',32,'全唐诗/poet.song.80000.json','["城頭雲樹不藏鴉，邂逅東風苦憶家。", "凴仗主林神放手，爲人匝地與開花。"]'),
