('b6eb6edc-8f09-4fb1-b78c-db1e7c514cc4','保塞教授同年丁仲勤廣寄示和少逸十詩某輒寄之更不理彭意無復次第  其八','王安中','宋','宋诗','song-poetry','','[]','眼看玉食禍無鄉，更卜幽居學仲長。',32,'全唐诗/poet.song.80000.json','["眼看玉食禍無鄉，更卜幽居學仲長。", "但遣有年供脱粟，白頭終不願膏粱。"]'),
('49df1151-0d3b-4632-bef0-b1bd67b6269f','保塞教授同年丁仲勤廣寄示和少逸十詩某輒寄之更不理彭意無復次第  其九','王安中','宋','宋诗','song-poetry','','[]','自嗤郎罷用心迂，饑坐呼兒課古書。',32,'全唐诗/poet.song.80000.json','["自嗤郎罷用心迂，饑坐呼兒課古書。", "只準高軒它日過，令吟交翠織華裾。"]'),
('3741e989-25d3-4a15-bede-b9e93c1278b6','保塞教授同年丁仲勤廣寄示和少逸十詩某輒寄之更不理彭意無復次第  其一○','王安中','宋','宋诗','song-poetry','','[]','康侯蚤日共周旋，筆勢翩翩兩鬬妍。',32,'全唐诗/poet.song.80000.json','["康侯蚤日共周旋，筆勢翩翩兩鬬妍。", "乞與西山一丸藥，坐令風翮更超然。"]'),
('d80628ea-e0d5-4e7e-a9e7-9209f5ad2c20','許道寧松','王安中','宋','宋诗','song-poetry','','[]','玉骨巑岏雪作頂，清溪下舞蛟龍影。',182,'全唐诗/poet.song.80000.json','["玉骨巑岏雪作頂，清溪下舞蛟龍影。", "忽驚發地扶屋極，誰向天公乞刀尺。", "道人逸氣天雲高，韋偃畢宏皆坐超。", "奔崕斷壑皆睥睨，悲風激激星勞勞。", "胡爲乎挂卿高堂之素壁，許侯筆興萬牛敵。", "坐來一氣回霜秋，四顧滿堂皆古色。", "老夫卜築寄雲松，屢揖伯鸞攜敬通。", "忽見婆娑眼中物，使我嚼句生天風。", "千章奇材卧澗底，公獨區區悦其僞。", "我知金石貫冰霜，便與髯卿同一味。", "君不見丹霞大士燒木佛，此老胸中果何物。"]'),
('a019c8e7-b3b1-4f14-b81d-12dcd443dbee','戒壇院東坡枯木張嘉夫妙墨童子告以僧不在不可見作此示','王安中','宋','宋诗','song-poetry','','[]','雪裏壁間枯木枝，東坡戲作無聲詩。',80,'全唐诗/poet.song.80000.json','["雪裏壁間枯木枝，東坡戲作無聲詩。", "霅川謫仙亦豪放，酒闌爲吐雲烟詞。", "相傳秀色絕今古，正如四月出盆絲。", "老僧遮護不許見，敲門游客遭慢欺。", "我來擬看亦乘興，興盡却還君不嗤。"]'),
('706a46a4-7a5c-455c-a46a-2436c288e573','王摩詰釣魚圖','王安中','宋','宋诗','song-poetry','','[]','我本江湖人，市朝豈無心。',240,'全唐诗/poet.song.80000.json','["我本江湖人，市朝豈無心。", "偶然墮世網，如鳥思長林。", "交親豈不多，之子德我深。", "賜沐有餘閒，一馬時相尋。", "茅亭容膝耳，九衢可窺臨。", "挂壁出古圖，驚笑靡自任。", "筆墨粗可識，佳處疑非今。", "佳哉王摩詰，風味我所欽。", "自狀釣魚圖，葦間相拏音。", "有如渼波游，一杜挾兩岑。", "坐令黄塵中，思落清江潯。", "秦子詩思古，清新間雄沈。", "示我五字句，月杵鳴秋砧。", "回盃勸摩詰，對畫手自斟。", "我羨子高趣，子聆我微箴。", "譬如影與形，妙在同一陰。", "我時坐其旁，清風溢幽襟。", "歸來步長廊，缺月户半侵。", "丹青已過鳥，齒頰猶哦吟。", "煩公有聲畫，相我無絃琴。"]'),
('22241405-5628-44c0-b4dc-a1de8884775b','題席大光所藏謝安石真','王安中','宋','宋诗','song-poetry','','[]','小兒破賊書能置，此貎恐非山澤癯。',64,'全唐诗/poet.song.80000.json','["小兒破賊書能置，此貎恐非山澤癯。", "東山登臨猶可狀，新亭談笑若爲摹。", "雖疑太傅平生在，不比司空少恨無。", "只寫君真便相似，向來寧見管夷吾。"]'),
('10a05f1e-af1e-448d-bc60-642c61055ef1','題李伯時畫船子和尚  其一','王安中','宋','宋诗','song-poetry','','[]','等個魚兒久未逢，滿船明月一絲風。',32,'全唐诗/poet.song.80000.json','["等個魚兒久未逢，滿船明月一絲風。", "離鈎三寸誰開口，打落掀天白浪中。"]'),
('da43a40a-aacf-4534-8561-f0a03dfaffe1','題李伯時畫船子和尚  其二','王安中','宋','宋诗','song-poetry','','[]','一橈打省猶回首，露布須收人與船。',32,'全唐诗/poet.song.80000.json','["一橈打省猶回首，露布須收人與船。", "不著釣絲牽老會，却留戽斗付龍眠。"]'),
('e7c2aeeb-13df-4d27-8cf7-b14887c8abf0','題顔持約畫四小景 梧山暮雪','王安中','宋','宋诗','song-poetry','','[]','一白空迷浩淼，萬卷却立孱顔。',28,'全唐诗/poet.song.80000.json','["一白空迷浩淼，萬卷却立孱顔。", "北渚曾遊帝子，南巡更憶虞鰥。"]'),
('50c6a68c-caba-44c5-9250-0f71a1ff95a9','題顔持約畫四小景 荔浦久陰','王安中','宋','宋诗','song-poetry','','[]','曾向荔支浦宿，林紅間碧猶疑。',28,'全唐诗/poet.song.80000.json','["曾向荔支浦宿，林紅間碧猶疑。", "老矣少文欲卧，咄哉王贊何如。"]'),
('9ef6d02a-6fed-49ba-9a83-7bde5c135041','題顔持約畫四小景 桂嶺秋晴','王安中','宋','宋诗','song-poetry','','[]','海市當寒可出，嶽雲正雨猶開。',28,'全唐诗/poet.song.80000.json','["海市當寒可出，嶽雲正雨猶開。", "故捲黄茅障盡，爲飛碧玉簪來。"]'),
('9f2be059-f5a5-43c8-807d-50228b65497b','題顔持約畫四小景 梅村欲曉','王安中','宋','宋诗','song-poetry','','[]','暗射霏霏逆鼻，荒雞喔喔號村。',28,'全唐诗/poet.song.80000.json','["暗射霏霏逆鼻，荒雞喔喔號村。", "萬里客行憀慄，玉顔破霧相温。"]'),
('123db7bf-69b1-488a-b286-049d613dcc07','題陽華岩圖','王安中','宋','宋诗','song-poetry','','[]','元子說陽華，巉岩不可家。',24,'全唐诗/poet.song.80000.json','["元子說陽華，巉岩不可家。", "此招吾已諾，不恨客天涯。"]'),
('38f057b4-f670-4b15-acbe-998c1432218c','題陳去非王摩詰嘉陵圖','王安中','宋','宋诗','song-poetry','','[]','江山已暗大同殿，絃管猶喧凝碧池。',32,'全唐诗/poet.song.80000.json','["江山已暗大同殿，絃管猶喧凝碧池。", "别寫嘉陵三百里，右丞心事欲誰知。"]'),
('367402fe-aafa-43c3-b012-3ee65e18ace3','祁陽成逸畫浯溪圖相示爲作長句','王安中','宋','宋诗','song-poetry','','[]','少文閱世老不出，自畫雲山滿墻壁。',128,'全唐诗/poet.song.80000.json','["少文閱世老不出，自畫雲山滿墻壁。", "澄懷觀道追所歷，坐覺琴聲隱金石。", "我亦七年湖外客，夢中猶泛湘江碧。", "浯溪之圖喜新得，身卧嶺南心嶺北。", "憶嘗留語溪邊僧，異時人讀唐中興。", "說與此乃秦典刑，三句入韻之罘銘。", "今欲復作誰可令，似有元結無真卿。", "風烟慘淡萬古情，不如且尋畫隱成。"]'),
('81f5e37a-12bd-4aca-83cf-8117c0605786','題趙大年金碧山水圖','王安中','宋','宋诗','song-poetry','','[]','王孫胸中楚七澤，不學庸史誇水墨。',130,'全唐诗/poet.song.80000.json','["王孫胸中楚七澤，不學庸史誇水墨。", "試開緹襲拂蛛絲，半幅鵝溪射金碧。", "余聞女媧煉石補天缺，石破壓天天柱折。", "五色墮地金嵯峨，六鰲跨海吹銀波。", "扶桑玉虹下天半，貝闕珠宫紫雲滿。", "桃花笑作十洲春，劉郎此地聞雞犬。", "繫我不從天津槎，自閱妙畫徒驚嗟。", "迷魂一夜飛蝴蜨，覺來半破篷窗月。"]'),
('e6fa2dc8-88d4-4437-82fd-78491e9be132','觀僧舍山茶','王安中','宋','宋诗','song-poetry','','[]','山僧手種兩山茶，看到婆娑鬢已華。',64,'全唐诗/poet.song.80000.json','["山僧手種兩山茶，看到婆娑鬢已華。", "應爲客懷驚歲抄，先將春色照天涯。", "綠裁犀甲層層葉，紅染猩唇艷艷花。", "凍頰如丹相映渥，不辭衝雨踏泥沙。"]'),
('8bad8528-facf-4201-84bd-6f5d870ec97f','春帖子 皇帝閤','王安中','宋','宋诗','song-poetry','','[]','彤霞蒨霧繞觚稜，樓雪融銀滴半層。',32,'全唐诗/poet.song.80000.json','["彤霞蒨霧繞觚稜，樓雪融銀滴半層。", "別繞擬開延福宴，夾城先試景龍燈。"]'),
('e2460327-40bd-414f-86f2-07fdcdfaa4bb','春帖子 妃嬪閤','王安中','宋','宋诗','song-poetry','','[]','玉燕翩翩入鬢雲，花風初掠縷金裙。',32,'全唐诗/poet.song.80000.json','["玉燕翩翩入鬢雲，花風初掠縷金裙。", "神霄宮裏驂鸞侶，來侍長生大帝君。"]'),
('31cab7cb-591c-47ac-92a0-3c82808bfe6c','春帖子 皇后閤','王安中','宋','宋诗','song-poetry','','[]','蘂笈瑯函受秘文，清虛道合玉晨君。',32,'全唐诗/poet.song.80000.json','["蘂笈瑯函受秘文，清虛道合玉晨君。", "瑤臺夜靜朝真久，金屋春寒閱籙勤。"]'),
('5b128f12-b64c-4b3c-988d-2aa247171516','春帖子 妃嬪閤','王安中','宋','宋诗','song-poetry','','[]','曈曨曉日上金鋪，的皪春冰泮玉壺。',32,'全唐诗/poet.song.80000.json','["曈曨曉日上金鋪，的皪春冰泮玉壺。", "繡戶綠窗塵不到，凝酥點就輞川圖。"]'),
('5f520e8c-44d8-434a-83d0-f6fc7d72ff0f','題惠崇畫四首  其一','王安中','宋','宋诗','song-poetry','','[]','東風回，江上渚。',48,'全唐诗/poet.song.80000.json','["東風回，江上渚。", "何處來，雙白鷺。", "灼灼岸間桃，依希蘭杜苗。", "一銜湍瀨鱗，一下青林梢，瀟湘綠水春迢迢。"]'),
('b50421b7-31a1-4f14-b6b4-eb086bbf9544','題惠崇畫四首  其二','王安中','宋','宋诗','song-poetry','','[]','老柳無嘉色，紅蕖羞脈脈。',48,'全唐诗/poet.song.80000.json','["老柳無嘉色，紅蕖羞脈脈。", "宛在水中洲，雙鵝羽蒼白。", "何須玩引頸，顛倒寫經墨。", "惟應一臨流，當暑袗絺綌。"]'),
('1b4a459e-0d3e-4769-bedf-7bed5590a95e','題惠崇畫四首  其三','王安中','宋','宋诗','song-poetry','','[]','一雁孤風辭臨渚，兩雁將飛未成舉，三雁羣行依宿莽。',40,'全唐诗/poet.song.80000.json','["一雁孤風辭臨渚，兩雁將飛未成舉，三雁羣行依宿莽。", "蘆花已倒江上風，雲間分飛那可同。"]'),
('ac69116e-6f68-4023-ac04-f3fc8b5a268a','題惠崇畫四首  其四','王安中','宋','宋诗','song-poetry','','[]','天高靄靄雲昏，江闊霏霏雪繁。',56,'全唐诗/poet.song.80000.json','["天高靄靄雲昏，江闊霏霏雪繁。", "渚下鴨方遠泛，枝間雀不聞喧。", "鄙夫此志相依，生涯稊稗同微。", "欲具沙邊短艇，波濤歲晚人稀。"]'),
('7e29079e-3a5d-400a-837b-a0351c1e3968','象州上元','王安中','宋','宋诗','song-poetry','','[]','二年白玉堂，揮翰供帖子。',96,'全唐诗/poet.song.80000.json','["二年白玉堂，揮翰供帖子。", "風生起草臺，墨照澄心紙。", "三年文昌省，拜賜近天咫。", "紅蓼朌御盤，金幡裊宮蘂。", "晚爲日南客，環堵隱烏几。", "朝來聞擊鼓，土牛出城市。", "幽懷不自閑，欲逐春事起。", "安得五畝園，種蔬引江水。"]'),
('aa7ba698-3788-46f6-bd35-1893085d4e01','同名詩','王安中','宋','宋诗','song-poetry','','[]','蜀客更名緣好尚，漢臣書姓爲同官。',64,'全唐诗/poet.song.80000.json','["蜀客更名緣好尚，漢臣書姓爲同官。", "孟公自合名驚座，子夏尤宜便小冠。", "益號文章緣兩李，翃書制誥有諸韓。", "二元各自分南北，付與時人子細看。"]'),
('f732e75d-ca7d-4aa0-8511-ee4bb89ff671','登豐樂樓','王安中','宋','宋诗','song-poetry','','[]','日邊高擁瑞雲深，萬井喧闐正下臨。',65,'全唐诗/poet.song.80000.json','["日邊高擁瑞雲深，萬井喧闐正下臨。", "金碧樓臺雖禁籞，煙霞巖洞卻山林。", "巍然而適構千齡運，仰止常傾四海心。", "此地去天真尺五，九霄歧路不容尋。"]'),
('80be2edf-6b6b-4418-9c53-1565a5332931','次韻震子磐送糟蟹  其一','王安中','宋','宋诗','song-poetry','','[]','醉死楊家郭索生，此曹平日要橫行。',32,'全唐诗/poet.song.80000.json','["醉死楊家郭索生，此曹平日要橫行。", "不須覆醢煩諸子，試比糟蟹幾許爭。"]'),
('80d355bf-7125-41ce-890e-c3e7a564b410','次韻震子磐送糟蟹  其二','王安中','宋','宋诗','song-poetry','','[]','熟點醯薑洗手生，樽前此物正施行。',32,'全唐诗/poet.song.80000.json','["熟點醯薑洗手生，樽前此物正施行。", "哺糟晚出尤無賴，尚有饞夫染指爭。"]'),
('003b626e-46de-476c-a444-ada7a9b2b4c0','次韻震子磐送糟蟹  其三','王安中','宋','宋诗','song-poetry','','[]','烹不能鳴渠幸生，含糊終作醉鄉行。',32,'全唐诗/poet.song.80000.json','["烹不能鳴渠幸生，含糊終作醉鄉行。", "裂臍已死人誰照，折股猶腥犬謾爭。"]'),
('12fd2df0-f596-40a7-a2c7-6384b6f640a8','次韻震子磐送糟蟹  其四','王安中','宋','宋诗','song-poetry','','[]','塞上秋殘百萬生，書囊旁午此時行。',32,'全唐诗/poet.song.80000.json','["塞上秋殘百萬生，書囊旁午此時行。", "聾丞自薦牋雖妙，未必持螯手肯爭。"]'),
('41d6056c-8047-4625-af89-94a380fdc594','次韻震子磐送糟蟹  其五','王安中','宋','宋诗','song-poetry','','[]','莫笑頭陀飯出生，要將戒殺勸修行。',32,'全唐诗/poet.song.80000.json','["莫笑頭陀飯出生，要將戒殺勸修行。", "霜螯斷命終妨道，身作人爲了不爭。"]'),
('fbd50412-abde-4b2a-b854-eedea097f6b6','棗陽道中','王安中','宋','宋诗','song-poetry','','[]','閤閤林鳩起，巡方舜舊遊。',24,'全唐诗/poet.song.80000.json','["閤閤林鳩起，巡方舜舊遊。", "聲雖暨南朔，事罕記春秋。"]'),
('1a3027d0-19db-45e0-a9a5-1cbe34afd2f8','桂林','王安中','宋','宋诗','song-poetry','','[]','跨緣今似孤雲薄，隨身翩翩惟一鶴。',32,'全唐诗/poet.song.80000.json','["跨緣今似孤雲薄，隨身翩翩惟一鶴。", "縞衣赴節舞松風，好伴先生臥林壑。"]'),
('648eb481-580d-40b9-b907-d678811a3eb5','象州','王安中','宋','宋诗','song-poetry','','[]','孔子生闕里，居不陋九夷。',60,'全唐诗/poet.song.80000.json','["孔子生闕里，居不陋九夷。", "象郡雖云遠，王地各有宜。", "疏梅香度水，瘦竹筍穿籬。", "坐侍百卉芳，春風兼四時。", "惜哉此江山，顧肯遊者誰。"]'),
('11fc8838-18c6-46f8-98f2-27719e8dec2d','夜登天王臺','王安中','宋','宋诗','song-poetry','','[]','月色鎔銀爛不收，蕭然風露欲中秋。',64,'全唐诗/poet.song.80000.json','["月色鎔銀爛不收，蕭然風露欲中秋。", "天河澄淡星芒小，雲海溟濛夜氣浮。", "臺影迥無羣木礙，琴聲清入素商流。", "高吟此地容吾知，長嘯西山想獨遊。"]'),
('08fc13e0-9152-418e-ac47-0a32a4007c84','潮陽道中','王安中','宋','宋诗','song-poetry','','[]','火輪升日路初分，雷鼓翻潮脚底聞。',64,'全唐诗/poet.song.80000.json','["火輪升日路初分，雷鼓翻潮脚底聞。", "萬竈晨煙熬白雪，一川秋穗割黄雲。", "嶺茅已遠無深瘴，溪鰐方逃畏舊文。", "此若有田能借客，康成終欲老耕耘。"]'),
('05b2ed7f-0895-427c-9c5a-d1103fd2d35d','靈巖山','王安中','宋','宋诗','song-poetry','','[]','鑿破巓崖透碧流，小舟輕泛入深幽。',64,'全唐诗/poet.song.80000.json','["鑿破巓崖透碧流，小舟輕泛入深幽。", "石鱗映水玻璃皺，山勢凌空翡翠浮。", "雲護淵泉晴欲雨，寒生洞府夏成秋。", "停橈峭壁題名姓，醉墨淋漓記此游。"]'),
('00ecfbb7-73e2-4324-9ae8-63f80d7ae207','句  其一','王安中','宋','宋诗','song-poetry','','[]','鳳鞋微露繡帮相。',8,'全唐诗/poet.song.80000.json','["鳳鞋微露繡帮相。"]'),
('c4a40085-00cf-4182-8176-ae8174651ee5','句  其二','王安中','宋','宋诗','song-poetry','','[]','後人誰促漁陽戰，舊守猶遷象郡來。',16,'全唐诗/poet.song.80000.json','["後人誰促漁陽戰，舊守猶遷象郡來。"]'),
('3dac65a4-a028-495b-b0a7-0a1f8822647b','句  其三','王安中','宋','宋诗','song-poetry','','[]','不見牛醫黄叔度，即尋馬磨許文休。',16,'全唐诗/poet.song.80000.json','["不見牛醫黄叔度，即尋馬磨許文休。"]'),
('20d8552a-f800-438e-aec8-d941aafa0476','句  其四','王安中','宋','宋诗','song-poetry','','[]','浮雲事有千端異。',8,'全唐诗/poet.song.80000.json','["浮雲事有千端異。"]'),
('30b1ba6c-249a-4521-b927-8772eb094665','句  其五','王安中','宋','宋诗','song-poetry','','[]','不論與汝小一月，政自容君數百人。',16,'全唐诗/poet.song.80000.json','["不論與汝小一月，政自容君數百人。"]'),
('ec0c1391-1625-4318-909b-105d96e055fb','句  其六','王安中','宋','宋诗','song-poetry','','[]','桃花春有信，結子徧昭陽。',12,'全唐诗/poet.song.80000.json','["桃花春有信，結子徧昭陽。"]'),
('f731b0ce-8d2e-4ceb-9a8c-3f3d7e85126d','句  其七','王安中','宋','宋诗','song-poetry','','[]','來踏三湘雪，歸迎八桂秋。',24,'全唐诗/poet.song.80000.json','["來踏三湘雪，歸迎八桂秋。", "未過盤石寺，先憩訾家洲。"]'),
('6188074d-18d2-4832-a9d0-9ade3f29693f','句  其八','王安中','宋','宋诗','song-poetry','','[]','疏星殘月漾中流，黄鶴樓前鸚鵡洲。',16,'全唐诗/poet.song.80000.json','["疏星殘月漾中流，黄鶴樓前鸚鵡洲。"]'),
('32daab9c-174d-43fb-84a5-506c33549eb9','句  其九','王安中','宋','宋诗','song-poetry','','[]','雲山連楚塞，夏木暗隨城。',12,'全唐诗/poet.song.80000.json','["雲山連楚塞，夏木暗隨城。"]'),
('79913f61-2a81-41aa-8b5f-e57785630433','句  其一○','王安中','宋','宋诗','song-poetry','','[]','漢東老人家壁立，隨行只有淵明集。',16,'全唐诗/poet.song.80000.json','["漢東老人家壁立，隨行只有淵明集。"]'),
('ff02e95e-f10a-48f0-840e-dc33fc6c8541','句  其一一','王安中','宋','宋诗','song-poetry','','[]','忘情漢東客，行脚水南禪。',12,'全唐诗/poet.song.80000.json','["忘情漢東客，行脚水南禪。"]'),
('df08356d-d227-40a5-acb9-50d2c3f7f044','句  其一二','王安中','宋','宋诗','song-poetry','','[]','隨州九十九重山，安得鄉人住此間。',16,'全唐诗/poet.song.80000.json','["隨州九十九重山，安得鄉人住此間。"]'),
('ca323060-c93d-4520-a28a-8adbebb3efc1','句  其一三','王安中','宋','宋诗','song-poetry','','[]','隨崗百欠一，陸產萬不一。',12,'全唐诗/poet.song.80000.json','["隨崗百欠一，陸產萬不一。"]'),
('972b0a44-94d0-445f-bed8-95304ef48e72','句  其一四','王安中','宋','宋诗','song-poetry','','[]','誰料此行逾溠水，吾能未到說隨州。',16,'全唐诗/poet.song.80000.json','["誰料此行逾溠水，吾能未到說隨州。"]'),
('62c686af-62da-4776-ad34-9f7cc50d0db3','句  其一五','王安中','宋','宋诗','song-poetry','','[]','八桂西南天一握，重江今古水雙流。',16,'全唐诗/poet.song.80000.json','["八桂西南天一握，重江今古水雙流。"]'),
('514dece1-631d-4c6e-a7ee-ca6333c0454e','句  其一六','王安中','宋','宋诗','song-poetry','','[]','來踏三湘雪，歸回八桂秋。',36,'全唐诗/poet.song.80000.json','["來踏三湘雪，歸回八桂秋。", "人忘五嶺熱，山似九華尤。", "日月通南極，星河带北流。"]'),
('62e50ca3-7662-4e95-855d-1e7b64fa302a','句  其一七','王安中','宋','宋诗','song-poetry','','[]','山川爲公來，先已流瘴癘。',12,'全唐诗/poet.song.80000.json','["山川爲公來，先已流瘴癘。"]'),
('d90fd5a8-30ff-4e21-8bb4-dce5c38eadef','句  其一八','王安中','宋','宋诗','song-poetry','','[]','江山似慰天涯客，花卉先回嶺北春。',16,'全唐诗/poet.song.80000.json','["江山似慰天涯客，花卉先回嶺北春。"]'),
('43355546-17aa-49a5-ac98-1744e6c74afe','句  其一九','王安中','宋','宋诗','song-poetry','','[]','宦遊梅嶺外，訟訴榕庭空。',12,'全唐诗/poet.song.80000.json','["宦遊梅嶺外，訟訴榕庭空。"]'),
('6902ae51-1be2-4eeb-a39a-d44cd3aaf80a','句  其二○','王安中','宋','宋诗','song-poetry','','[]','玉顔知復爲誰容。',8,'全唐诗/poet.song.80000.json','["玉顔知復爲誰容。"]'),
('c5ea4457-c75f-46d1-92f4-33bd0c19eaba','句','宋哲宗','宋','宋诗','song-poetry','','[]','周紹裕陵尊。',6,'全唐诗/poet.song.80000.json','["周紹裕陵尊。"]'),
('7006568c-68e3-4362-a49f-40cf133cc38a','宴延和樓即事','趙良嗣','宋','宋诗','song-poetry','','[]','建國舊碑朝日暗，興王故地野風乾。',32,'全唐诗/poet.song.80000.json','["建國舊碑朝日暗，興王故地野風乾。", "回頭笑謂王公子，騎馬隨軍過五鑾。"]'),
('5cfad2b4-4e60-4c38-be13-ac7f36b101cf','聞王師入燕','趙良嗣','宋','宋诗','song-poetry','','[]','朔風吹雪下雞山，燭暗穹廬夜色寒。',32,'全唐诗/poet.song.80000.json','["朔風吹雪下雞山，燭暗穹廬夜色寒。", "聞道燕山好消息，曉來驛騎報平安。"]'),
('c3a0c7a4-1f12-42b9-b6ec-dc8aa15b4707','同舍弟泛舟西湖登晝錦堂步至紫翠亭望懶堂景物懷故龍舒先生','王庭秀','宋','宋诗','song-poetry','','["\u897f\u6e56"]','城中十頃湖，雲水相演漾。',192,'全唐诗/poet.song.80000.json','["城中十頃湖，雲水相演漾。", "春風破冰谷，拍岸新流漲。", "平鋪鴨頭綠，澹沲葡萄釀。", "朱甍媚孤嶼，梵宇麗相向。", "萬瓦生清暉，千花聯錦帳。", "晨曦照炯炯，芳氣浮泱泱。", "日暮姿態妍，煙霞渺空曠。", "誰將水仙鏡，聊借詩人仗。", "臥護五羊城，追懷老詩將。", "微吟示清野，鏖戰得閑放。", "變化無端倪，虛無落名狀。", "坐令湖上景，勝絕神宇王。", "當時經行地，藻麗隨屨杖。", "斯人今則亡，物色亦摧喪。", "它年牛馬走，曾拜丈人行。", "塵埃久漂泊，歲月成漫浪。"]'),
('1adb300f-4622-40ff-aec9-4c5041ada438','五峰寺','王庭秀','宋','宋诗','song-poetry','','[]','度崦得幽勝，遵谿步橫斜。',192,'全唐诗/poet.song.80000.json','["度崦得幽勝，遵谿步橫斜。", "哀湍瀉曲折，虬枝老蟠拏。", "危然五峰高，突兀凌晨霞。", "若有神物護，遺此瞿曇家。", "何年老苾蒭，巾鉢寄枯槎。", "乳麀饋朝供，野禽或銜花。", "爾來三百年，拓址夷谽谺。", "締架俯層巘，棟宇日就奢。", "古殿儀像設，棲雲擁欄牙。", "董修奉檀施，鐘鼓驚麕䴥。", "中有無盡燈，賡續歲踰賒。", "大千破幽暗，照了無等差。", "逢禪頗修潔，悃愊初無華。", "十年坐空谷，日月絕纖瑕。", "運水及搬柴，爲罪作生涯。", "前山逢老婦，試問趙家茶。"]'),
('b469ee94-0030-4c7d-9366-14aff9b9c887','自誓','魏行可','宋','宋诗','song-poetry','','[]','萬里心馳懷故國，千行淚灑望行宮。',32,'全唐诗/poet.song.80000.json','["萬里心馳懷故國，千行淚灑望行宮。", "孤臣不死忠誠在，爲報無忘此犬戎。"]'),
('556880a4-1f3a-4172-8aac-1b690637db80','句','章之邵','宋','宋诗','song-poetry','','[]','雲山犬吠聲相答，野水禽飛影自隨。',16,'全唐诗/poet.song.80000.json','["雲山犬吠聲相答，野水禽飛影自隨。"]'),
('33698338-76d1-4d83-9f7f-d49f26a176be','呈佛眼','釋法順','宋','宋诗','song-poetry','','[]','頂有異峰雲冉冉，源無別派水泠泠。',32,'全唐诗/poet.song.80000.json','["頂有異峰雲冉冉，源無別派水泠泠。", "游山未到山窮處，終被青山礙眼睛。"]'),
('77de84fd-fa43-4c24-aa8e-fa9202d6b5c2','偈五首  其一','釋法順','宋','宋诗','song-poetry','','[]','好事堆堆疊疊來，不須造作與安排。',64,'全唐诗/poet.song.80000.json','["好事堆堆疊疊來，不須造作與安排。", "落林黄葉水推去，橫谷白雲風卷回。", "寒雁一聲情念斷，霜鐘纔動我山摧。", "白楊更有過人處，盡夜寒爐撥死灰。"]'),
('78f82a11-37ce-4c57-8a6e-7c89371ccefb','偈五首  其二','釋法順','宋','宋诗','song-poetry','','[]','我手何似佛手，天上南星北斗。',72,'全唐诗/poet.song.80000.json','["我手何似佛手，天上南星北斗。", "我脚何似驢脚，往事都來忘卻。", "人人盡有生緣，個個足方頂圓。", "大愚灘頭立處，孤月影射深灣。", "會不得，見還難，一曲漁歌過遠灘。"]'),
('5670e0e9-be28-48f7-abc7-d8268c812432','偈五首  其三','釋法順','宋','宋诗','song-poetry','','[]','雞啼曉月，狗吠枯椿。',70,'全唐诗/poet.song.80000.json','["雞啼曉月，狗吠枯椿。", "只可默會，難入思量。", "看不見處，動地放光。", "說不到處，天地玄黄。", "撫城尺六狀紙，元來出在清江。", "分明話出人難見，昨夜三更月到窗。"]'),
('c16b17bd-b070-4229-a1a1-439f8995f497','偈五首  其四','釋法順','宋','宋诗','song-poetry','','[]','風吹茆茨屋脊漏，雨打闍黎眼睛濕。',32,'全唐诗/poet.song.80000.json','["風吹茆茨屋脊漏，雨打闍黎眼睛濕。", "憑麽分明卻不知，卻來這裏低頭立。"]'),
('52ed696f-7f36-402c-8ae9-3af7eb23fd3b','偈五首  其五','釋法順','宋','宋诗','song-poetry','','[]','久病未嘗推木枕，人來多是問如何。',32,'全唐诗/poet.song.80000.json','["久病未嘗推木枕，人來多是問如何。", "山僧據問隨緣對，窗外黄鸝口更多。"]'),
('d5b87d03-bb23-47b0-ad1e-485caa377975','仆雪中偈','釋法順','宋','宋诗','song-poetry','','[]','垂老住山寺，參官走道途。',24,'全唐诗/poet.song.80000.json','["垂老住山寺，參官走道途。", "前村雪嶺上，顛倒沒人扶。"]'),
('bbb1f128-d176-4354-944d-32ea5fc0f071','偈','釋世奇','宋','宋诗','song-poetry','','[]','夢中聞版響，覺後蝦蟆啼。',24,'全唐诗/poet.song.80000.json','["夢中聞版響，覺後蝦蟆啼。", "蝦蟆與版響，山嶽一時齊。"]'),
('bdd89d1b-b384-4b20-b92d-4a4784e9365e','臨終偈','釋世奇','宋','宋诗','song-poetry','','[]','諸法空故我心空，我心空故諸法同。',32,'全唐诗/poet.song.80000.json','["諸法空故我心空，我心空故諸法同。", "諸法我心無別體，只在而今一念中。"]'),
('adc39de6-c3fc-4c8e-8c17-7f594367bc8f','焦山寺','翟汝文','宋','宋诗','song-poetry','','[]','水輪依風負坤輿，百川東流同灌輸。',208,'全唐诗/poet.song.80000.json','["水輪依風負坤輿，百川東流同灌輸。", "掀巾之陂莽吞受，沃焦之山初不濡。", "雲根終古插江湖，狂瀾滔天隨卷舒。", "空神迴標避突兀，海門排霄岌相扶。", "僧居蠔山迷向背，佛宇蜃氣成吹噓。", "昔游玄冬崖壑枯，洪濤濺雨吹裳裙。", "風來驚潮愁海若，溟漲跋浪翻鯨魚。", "羽淵咸池相蕩潏，月阿日窟漂方隅。", "此身浮漚一緣聚，四大濕相彌空虛。", "鍼鋒懸持妙喜住，蚊睫坐睨焦螟居。", "山中老禪眼於菟，香飯遺化分彫胡。", "重淵垂涎舞蛟首，方丈宴寢凝熏爐。", "夜寒月黑照濁水，乞取壞衲摩尼珠。"]'),
('c11b514a-c741-4e30-b791-f52d8c78c4e9','賦米芾海岳庵','翟汝文','宋','宋诗','song-poetry','','[]','楚米仙人好樓居，植桐崇岡結精廬。',64,'全唐诗/poet.song.80000.json','["楚米仙人好樓居，植桐崇岡結精廬。", "下瞰赤縣賓蟾烏，東西跳丸天馳驅。", "腹藏萬卷胸垂胡，論古如河決九渠。", "掀髯送目轉八區，欲叫虞舜起蒼梧。"]'),
('0a0af7fb-3059-46c2-bb0f-98d57a5eb2c3','北固山','翟汝文','宋','宋诗','song-poetry','','[]','山形鬰長虬，掉尾趨平川。',291,'全唐诗/poet.song.80000.json','["山形鬰長虬，掉尾趨平川。", "迴峰聳贔屭，廣殿凌雲巓。", "登臨望八極，天蓋垂空元。", "鴻濛一氣亂，鬼物半塗顛。", "天風河漢響，戶牖斗柄懸。", "黄圖昔散漫，赤伏竟沮遷。", "凄涼霸氣歇，徙倚平臺騫。", "山川宛如昔，獨爲騷人妍。", "江聲戰九地，幽憤爲誰湔。", "晴雷殷列缺，電火搜蜿蜒。", "矞皇故代物，猛熾隨飛煙。", "僧繇六花佛，生面行差肩。", "銖衣類帝網，肉髻浮青蓮。", "巍峨開元帝，玉座猶高懸。", "奮迅陸子畫，青{犭兕}戲芝田。", "蕭梁遺巨鑊，仿佛像姦鐫。", "贊皇藝兩柏，鬰屈蛟龍纏。", "空焚蕩灰劫，涕視悲人天。", "鏗鏗斧斤初，千柱欻修椽。", "蒼頭封草樹，佳氣封雲泉。", "孤標危塔湧，迥佛層陰堅。", "溟翻塔影倒，天轉磨蟻旋。", "咨嗟一彈指，悲悟三生緣。", "有生甚脆弱，膏火消煩煎。"]'),
('a98a0b15-1a65-4a8e-a5f1-5633e34cc0a1','句','翟汝文','宋','宋诗','song-poetry','','[]','青女霜如失，黄人日故遲。',12,'全唐诗/poet.song.80000.json','["青女霜如失，黄人日故遲。"]'),
('c4438099-c605-4d16-85cf-8b8465a1b459','句','呂拭','宋','宋诗','song-poetry','','[]','松竹初栽未靚深。',8,'全唐诗/poet.song.80000.json','["松竹初栽未靚深。"]'),
('9979dc8b-ed8b-4186-a791-5d53715da673','題清心堂','趙資道','宋','宋诗','song-poetry','','[]','燕坐都忘俗慮縈，小橋橫截跨幽亭。',64,'全唐诗/poet.song.80000.json','["燕坐都忘俗慮縈，小橋橫截跨幽亭。", "漣漪池面銀開鑒，篠蕩庭心玉展屏。", "桃李並蹊春競麗，檜松分徑歲長青。", "我來每覺塵心豁，客至還同醉眼醒。"]'),
('d34b162f-c2d2-41b2-bdec-0d2af15057dd','題勁節堂','趙資道','宋','宋诗','song-poetry','','[]','爲愛青青竹一林，旋開庭宇占清陰。',32,'全唐诗/poet.song.80000.json','["爲愛青青竹一林，旋開庭宇占清陰。", "風前蕭瑟聲敲五，月下玲瓏影碎金。"]'),
('2628dab2-6764-4239-af7f-20ec7afe70df','題洪陽洞','柳交','宋','宋诗','song-poetry','','[]','洞口春歸草木長，洞中流水薜蘿香。',32,'全唐诗/poet.song.80000.json','["洞口春歸草木長，洞中流水薜蘿香。", "真仙鶴馭今何處，應共白雲朝帝鄉。"]'),
('a7c25959-7de6-4279-9f29-169266bc3187','句','江暐','宋','宋诗','song-poetry','','[]','鬬草事空猶昨日，惜花心在又明年。',16,'全唐诗/poet.song.80000.json','["鬬草事空猶昨日，惜花心在又明年。"]'),
('6f206d38-d365-46d4-8541-1e10084a6028','句','朱昇','宋','宋诗','song-poetry','','[]','半塢煙霞金世界，一堂風月玉壺秋。',16,'全唐诗/poet.song.80000.json','["半塢煙霞金世界，一堂風月玉壺秋。"]'),
('ceba1b4f-bd3c-458a-b1c6-bd63095e2a62','資州  其一','宋京','宋','宋诗','song-poetry','','[]','江山不負人，入眼四時新。',36,'全唐诗/poet.song.80000.json','["江山不負人，入眼四時新。", "古寺巖爲屋，危峰竹是鄰。", "從來瀟灑地，今日自由身。"]'),
('d509c8f9-ada0-44c6-9dcc-400449edc63b','資州  其二','宋京','宋','宋诗','song-poetry','','[]','簫鼓旌旗簇錦韉，路人遙指翠微閑。',32,'全唐诗/poet.song.80000.json','["簫鼓旌旗簇錦韉，路人遙指翠微閑。", "使君乘興同民樂，猿鶴無心不礙閑。"]'),
('c37e68e2-c43b-4f17-a24a-bd5d85cd19b3','武擔','宋京','宋','宋诗','song-poetry','','[]','君不見蜀王妃子墓突兀，成都城中若山積。',131,'全唐诗/poet.song.80000.json','["君不見蜀王妃子墓突兀，成都城中若山積。", "墓頭寒鏡澀無光，妬月欺煙化爲石。", "鴻荒無根憑野史，直謂山妖化妃子。", "臨終未免懷首丘，運土山中葬於此。", "山名武擔錦江邊，用是得名千萬年。", "如今佛閣倚空翠，老木盤鬰摩蒼天。", "晴雲入穴西山出，捲簾坐見嵐光滴。", "撥得文如汲冢書，免使後人疑往昔。"]'),
('fd628b6c-9104-42d7-8d69-f52755029931','龜化','宋京','宋','宋诗','song-poetry','','[]','君不見秦時張儀築少城，土惡易敗還顛傾。',131,'全唐诗/poet.song.80000.json','["君不見秦時張儀築少城，土惡易敗還顛傾。", "力疲智竭築未就，神龜爲爾開其靈。", "龜行所至城不圮，板築之功以此已。", "功成隱去智且賢，城下於今祗流水。", "殷勤高謝余且網，不夢元君寧自放。", "儀兮儀兮奈爾何，口舌縱橫飾欺妄。", "天使神龜籠爾術，不言而行功自畢。", "安得人靈若爾靈，照見百爲心遐逸。"]'),
('e38f9d02-7a7d-485e-a951-ee9453797b70','禮殿','宋京','宋','宋诗','song-poetry','','[]','君不見漢人制作禮殿存，法度嚴廣分卑尊。',131,'全唐诗/poet.song.80000.json','["君不見漢人制作禮殿存，法度嚴廣分卑尊。", "祇今年數不可考，列畫古帝丹青昏。", "晉人遺書刻柱邊，字劃刓決骨氣全。", "衣冠真不異闕里，事業直笑銘燕然。", "鏘鏘似有環珮聲，七十二子羅簪纓。", "閉藏濁世如有待，開眼今日觀文明。", "陳倉石鼓歸辟雍，大成門閥何穹崇。", "安得貌取禮殿制，太學西有宣尼宮。"]'),
('691cb8f9-c9db-4a83-bf80-11e294b04e43','石室','宋京','宋','宋诗','song-poetry','','[]','君不見西漢文翁爲蜀守，蜀學不居齊魯後。',131,'全唐诗/poet.song.80000.json','["君不見西漢文翁爲蜀守，蜀學不居齊魯後。", "諸生競欲保翁名，石室鐫磨貴難朽。", "東漢高公又幾時，爲作石室還如茲。", "至今二室堅且久，文公高公名不衰。", "世間可傳唯鐵石，石終可泐鐵終蝕。", "古人好事留其名，石室存亡竟何益。", "漢水沉碑知在不，叔子名存空峴首。", "安得眼看石室銷，要知二子名終有。"]'),
('3952630a-63da-4d10-93e6-a89e9f3d645a','玉局','宋京','宋','宋诗','song-poetry','','[]','君不見青陽老人飛下天，口宣至道朝群仙。',131,'全唐诗/poet.song.80000.json','["君不見青陽老人飛下天，口宣至道朝群仙。", "地中神人捧玉局，異事祕怪于今傳。", "龜城坤隅地有穴，俗說西與岷山連。", "嵯峨古觀森偉像，老柏慘澹含風煙。", "令威已去城郭在，人物自改名依然。", "亳州宮庭煥星斗，真皇行幸祥符年。", "所託得地近京邑，此獨隱晦遐方偏。", "安得老人洗此心，還我澹泊同古先。"]'),
('bab21365-c4e9-4b84-aea6-101ecefb0278','嚴真','宋京','宋','宋诗','song-poetry','','[]','君不得莊遵賣卜成都市，市中仙隱無人值。',132,'全唐诗/poet.song.80000.json','["君不得莊遵賣卜成都市，市中仙隱無人值。", "百錢度日復何求，猶有沉真見文字。", "不因問着牛女星，下士安能知姓名。", "雲中雞犬拔家去，舊宅寂寞秋蕪平。", "榰機石在年年長，藥鼎空留閉黄壤。", "前時發掘篆籀新，明水神丹光滉瀁。", "金雁橋邊臺觀存，神仙遺事渺難論。", "安從師先生爲我卜，俗骨庶可遺天閽。"]'),
('8049ba67-7aec-49d3-9c8d-9950afdf0a62','琴臺','宋京','宋','宋诗','song-poetry','','[]','君不見成都郭西有琴臺，長卿遺跡埋黄埃。',131,'全唐诗/poet.song.80000.json','["君不見成都郭西有琴臺，長卿遺跡埋黄埃。", "千年乃爲狐兔窟，化作佛廟空崔嵬。", "黄鬚老人猶記得，昔時荒破樵蘇入。", "鉏犂畏淺牛脚勻，古甕耕開數逾十。", "乃知昔人用意深，甕下取聲元爲琴。", "人琴不見甕已掘，唯有鳥雀來悲吟。", "一朝風流隨手盡，況復千年何所訊。", "安得雄辭弔汝魂，寂寞秋蕪耿寒燐。"]'),
('e5208d89-e571-4a7f-9048-9d027e33a275','墨池','宋京','宋','宋诗','song-poetry','','[]','君不見子雲草玄西郭門，一逕秋草間朝昏。',131,'全唐诗/poet.song.80000.json','["君不見子雲草玄西郭門，一逕秋草間朝昏。", "何須筆塚高百尺，池墨黯黯今猶存。", "童烏侯巴竟零落，玄學無人終寂寞。", "漢家執戟知幾年，垂老身沒天祿閣。", "俗兒紛紛重劉向，思苦言艱動嘲謗。", "漢已中天雄亦亡，不較空文從覆醤。", "如今卻作給孤園，吐鳳亭前池水寒。", "安得斯人尚可作，會有奇字令君看。"]'),
('8029fc56-e70f-4d96-b803-8d64a7394e48','書臺','宋京','宋','宋诗','song-poetry','','[]','君不見孔明書臺遺廟旁，古書不見臺荒涼。',131,'全唐诗/poet.song.80000.json','["君不見孔明書臺遺廟旁，古書不見臺荒涼。", "臥龍未起蜀天遠，茅廬日日空南陽。", "赤符光寒白水涸，秣陵王氣猶能作。", "璋若嬰兒操虎狼，脫去荆州殊不惡。", "十倍奇才安用書，此臺昔時知有無。", "蜀人思君識古處，未若江水存兵圖。", "黄冠所居門第改，祇有坊名今尚在。", "安得臺邊見古人，秋草重生類書带。"]'),
('255f2c93-d2ac-4813-bb40-d7d22c5699f1','草堂','宋京','宋','宋诗','song-poetry','','[]','君不見少陵草堂背西郭，浣花溪水流堂脚。',131,'全唐诗/poet.song.80000.json','["君不見少陵草堂背西郭，浣花溪水流堂脚。", "竹寒沙白自凄涼，莫問四松霜草薄。", "入門好在烏皮几，公去不歸換鄰里。", "西嶺千秋雪書消，舍北泥融飛燕子。", "祇今榿木平橋路，籠竹和煙雜江霧。", "野僧作屋號草堂，不是柴門舊時處。", "詩壇今古誰能將，艷艷文章光萬丈。", "安得英才擅品量，當使公居摩詰上。"]'),
('0359d9d3-c76b-4182-98ed-b865d2f45f5c','留題周文王廟  其一','宋京','宋','宋诗','song-poetry','','[]','征西將帥念君王，刻石巴山事渺茫。',32,'全唐诗/poet.song.80000.json','["征西將帥念君王，刻石巴山事渺茫。", "□載衣冠付冥寞，路人無語奠椒漿。"]'),
('dffcede1-1e4b-4158-89b6-d487d174162e','留題周文王廟  其二','宋京','宋','宋诗','song-poetry','','[]','典章文物一朝完，有子何憂霸業難。',32,'全唐诗/poet.song.80000.json','["典章文物一朝完，有子何憂霸業難。", "□使阿堅生肉角，至今遺恨碧峰寒。"]'),
('e711a4c0-8ca8-422c-a0ff-5c076e6d3148','登尚清閣二首  其一','宋京','宋','宋诗','song-poetry','','[]','望斷秦原日月寬，西來涇渭側依山。',32,'全唐诗/poet.song.80000.json','["望斷秦原日月寬，西來涇渭側依山。", "憑誰喚取王摩詰，寫到孤鴻滅沒間。"]'),
('701db66f-295e-45dd-9b44-509e63ccd706','登尚清閣二首  其二','宋京','宋','宋诗','song-poetry','','[]','輦路名存跡已陳，斜陽今作幾家村。',32,'全唐诗/poet.song.80000.json','["輦路名存跡已陳，斜陽今作幾家村。", "繚牆月轉華清夢，來破高陵渡口昏。"]'),
('28668ef7-61d5-4c9b-b591-3ab7c95f88f5','京請郡得豳取道渭上觀爲命□詩刻次韻奉呈□□奉議公  其一','宋京','宋','宋诗','song-poetry','','[]','金節逶迤去不還，羅胸星斗煥秦天。',32,'全唐诗/poet.song.80000.json','["金節逶迤去不還，羅胸星斗煥秦天。", "白雲拱木今何在，歲月聲名相與延。"]'),
('b96d87e7-51a4-4a20-9d5c-8fe4f6c4e477','京請郡得豳取道渭上觀爲命□詩刻次韻奉呈□□奉議公  其二','宋京','宋','宋诗','song-poetry','','[]','乞守初來到渭濱，玻瓈親爲拂詩塵。',32,'全唐诗/poet.song.80000.json','["乞守初來到渭濱，玻瓈親爲拂詩塵。", "□江集裏新添得，留取鍾評付後人。"]'),
('d7abe7f7-e057-43b5-986d-aff66fd634d1','大觀庚寅冬遊資州北巖','宋京','宋','宋诗','song-poetry','','[]','資州城郭雲山裏，北巖正在雲山底。',128,'全唐诗/poet.song.80000.json','["資州城郭雲山裏，北巖正在雲山底。", "翠壁嵌空抱日明，飛閣橫斜矗天起。", "游人祇解愛城郭，不知山底幽人樂。", "六月全無暑氣生，三冬亦有林花落。", "蒼楠臥月影如輪，乳泉濺瀑波生鱗。", "利名付與百忙者，早晚自由無事身。", "紅蓮幕下青城客，五斗留人歸未得。", "衙迴不用展山圖，直到巖邊看秋色。"]'),
('549ccbcd-83bc-4d2f-99d5-51c6cdf00c59','句  其一','宋京','宋','宋诗','song-poetry','','[]','雲生氈帽山頭雨，日落琵琶峽口風。',16,'全唐诗/poet.song.80000.json','["雲生氈帽山頭雨，日落琵琶峽口風。"]'),
('7540ac0b-5be7-4b91-b0fb-31806987984a','句  其二','宋京','宋','宋诗','song-poetry','','[]','野性樂閑適，我州富佳山。',12,'全唐诗/poet.song.80000.json','["野性樂閑適，我州富佳山。"]'),
('2dd981e1-3a37-4cfc-86db-95ada10a5e11','句  其三','宋京','宋','宋诗','song-poetry','','[]','日約繡綳長一線。',8,'全唐诗/poet.song.80000.json','["日約繡綳長一線。"]'),
('01b2d076-425f-4427-a03f-cf9dcc3550a8','詠劉伶','龔況','宋','宋诗','song-poetry','','[]','逃名以酒轉名高，醉裏張髯罵二豪。',32,'全唐诗/poet.song.80000.json','["逃名以酒轉名高，醉裏張髯罵二豪。", "日月已爲吾戶牖，何妨東海作醇醪。"]'),
('a555256f-933f-4c9e-9348-be403e0a1aa4','九日  其一','龔況','宋','宋诗','song-poetry','','[]','家家高會錦模糊，誰信貧家菊也無。',32,'全唐诗/poet.song.80000.json','["家家高會錦模糊，誰信貧家菊也無。", "多謝東鄰送醅至，旋於籬畔覓茱萸。"]'),
('606a677e-5a9c-42e5-9628-6f9785c0c74c','九日  其二','龔況','宋','宋诗','song-poetry','','[]','自古誰無九日詩，詩成須道菊花枝。',32,'全唐诗/poet.song.80000.json','["自古誰無九日詩，詩成須道菊花枝。", "直饒無菊何妨醉，野蓼村葵總是題。"]'),
('12536ee4-7e96-4d11-861e-d9488f51d3f1','遊天峰寺','龔況','宋','宋诗','song-poetry','','[]','杖藜高踏半山雲，不見此崗知幾春。',32,'全唐诗/poet.song.80000.json','["杖藜高踏半山雲，不見此崗知幾春。", "異時人物凋零盡，只有青山似故人。"]'),
('b64a3a01-88b2-4fc1-9bce-4411932d0fa5','午歇惠安寺','龔況','宋','宋诗','song-poetry','','[]','寒食都來數日閑，顔卿家帖到今傳。',32,'全唐诗/poet.song.80000.json','["寒食都來數日閑，顔卿家帖到今傳。", "此公剛鯁無情煞，到得春時也自憐。"]'),
('925da08c-fb46-4bac-a13c-18eb75ae5621','送唐大監','龔況','宋','宋诗','song-poetry','','[]','東山相別又相逢，轉覺衰頹一老翁。',32,'全唐诗/poet.song.80000.json','["東山相別又相逢，轉覺衰頹一老翁。", "子約重來我方去，滿庭黄葉正秋風。"]'),
('6f7846ad-4077-4ee8-90f0-c04bf1e24da8','古樂府','龔況','宋','宋诗','song-poetry','','[]','妖嬈破𤓰女，争上秋千架。',48,'全唐诗/poet.song.80000.json','["妖嬈破𤓰女，争上秋千架。", "香飄石榴裙，影落薔薇下。", "牆外見鴛鴦，雙雙春水塘。", "歸來情脉脉，無緒理殘妝。"]'),
('addb9254-f03d-4a02-a10f-e10cdb81797a','古樂府  其一','龔況','宋','宋诗','song-poetry','','[]','妖嬈破瓜女，爭上秋千架。',24,'全唐诗/poet.song.80000.json','["妖嬈破瓜女，爭上秋千架。", "香飄石榴裙，影落薔薇下。"]'),
('d572efdc-55d1-4388-8359-46fad9d50a3b','古樂府  其二','龔況','宋','宋诗','song-poetry','','[]','牆外見鴛鴦，雙雙春水塘。',24,'全唐诗/poet.song.80000.json','["牆外見鴛鴦，雙雙春水塘。", "歸來情脈脈，無緒理殘妝。"]'),
('6bfb1be5-25b4-4eb1-a799-28c0e5d5537a','句  其一','龔況','宋','宋诗','song-poetry','','[]','貪山借船賞，嗜酒典琴沽。',12,'全唐诗/poet.song.80000.json','["貪山借船賞，嗜酒典琴沽。"]'),
('9ac19579-e467-46b8-98be-aa4021902af1','句  其二','龔況','宋','宋诗','song-poetry','','[]','閑多卷滿新成句，懶極床堆未答書。',16,'全唐诗/poet.song.80000.json','["閑多卷滿新成句，懶極床堆未答書。"]'),
('a9e1bc43-1e5a-4f22-8731-a083ecd335af','句  其三','龔況','宋','宋诗','song-poetry','','[]','客疏閑吠犬，庖匱割啼雞。',12,'全唐诗/poet.song.80000.json','["客疏閑吠犬，庖匱割啼雞。"]'),
('635071e3-fef3-4baa-8506-207630adfa28','句  其四','龔況','宋','宋诗','song-poetry','','[]','得句怕難續，避人長轉多。',12,'全唐诗/poet.song.80000.json','["得句怕難續，避人長轉多。"]'),
('24b4030c-7093-4ac0-9a35-01f5110e4fc3','句  其五','龔況','宋','宋诗','song-poetry','','[]','山色秋難老，池光夜不昏。',12,'全唐诗/poet.song.80000.json','["山色秋難老，池光夜不昏。"]'),
('98c4a460-0110-439f-bcb2-25946fa26d80','題宴坐石','石端誠','宋','宋诗','song-poetry','','[]','飛流噴雪散層巖，瓴水無時瀉屋簷。',32,'全唐诗/poet.song.80000.json','["飛流噴雪散層巖，瓴水無時瀉屋簷。", "客夢夜回疑是雨，起看窻戶有明蟾。"]'),
('d7259303-cf52-4c93-b2bb-842d465a891c','水索','石端誠','宋','宋诗','song-poetry','','[]','籜龍何用更橫空，一線長繩引水通。',32,'全唐诗/poet.song.80000.json','["籜龍何用更橫空，一線長繩引水通。", "頃刻能周清凈供，漢陰端謝桔槔功。"]'),
('4824cc62-a4db-43a8-8558-35a196dcfe1b','題八角亭','蔣存誠','宋','宋诗','song-poetry','','[]','由來祗說四簷亭，今日先生八角成。',32,'全唐诗/poet.song.80000.json','["由來祗說四簷亭，今日先生八角成。", "最喜瀟瀟春夜雨，一簷分作兩簷聲。"]'),
('8799a659-979b-42ca-b021-b01bf72d512f','靈巖夜月','侯延年','宋','宋诗','song-poetry','','[]','十年辛苦唐賢士，千載奇觀舊石巖。',32,'全唐诗/poet.song.80000.json','["十年辛苦唐賢士，千載奇觀舊石巖。", "天籟沉沉山月小，夜深文字與誰談。"]'),
('d0909e94-5244-4397-a9cc-f97c985bd155','登麻姑山','童邦直','宋','宋诗','song-poetry','','[]','碧苔侵野逕，好鳥隔春煙。',71,'全唐诗/poet.song.80000.json','["碧苔侵野逕，好鳥隔春煙。", "有洞尋青翼，無僧結白蓮。", "雨添蛙一部，暖足柳三眠。", "綠髪便花朵，慳腸怯酒船。", "安仁嗟拙宦蘇晉暫逃禪，日色同悲慘，東風亂紙錢。"]'),
('6189af85-2823-4e55-84d5-89f83a5aaa6d','仙湖','儲惇叙','宋','宋诗','song-poetry','','[]','咫尺仙湖號堵平，先賢曾此勸農耕。',32,'全唐诗/poet.song.80000.json','["咫尺仙湖號堵平，先賢曾此勸農耕。", "若教一日歸豪右，敢向黄公廟下行。"]'),
('c9b69b7d-cf7d-4f17-a3c3-7fdd64487f62','宿大滌山','吳倜','宋','宋诗','song-poetry','','[]','解驂投宿到蓬壺，骨冷魂清夢寐無。',32,'全唐诗/poet.song.80000.json','["解驂投宿到蓬壺，骨冷魂清夢寐無。", "可怪春禽曉啼月，又催行李出凡途。"]'),
('d23537de-9d71-4b4b-995b-d78786b60003','頌妙喜老師室中所問因緣','吳偉明','宋','宋诗','song-poetry','','[]','不是心，不是佛，不是物，通身一穿金鎖骨。',36,'全唐诗/poet.song.80000.json','["不是心，不是佛，不是物，通身一穿金鎖骨。", "趙州參見老南泉，解道鎮州出蘿蔔。"]'),
('5eb18608-66f2-4e80-95d6-8a163e87cc96','偈一首','吳偉明','宋','宋诗','song-poetry','','[]','毒蛇猛虎空相向，鐵壁銀山謾自橫。',32,'全唐诗/poet.song.80000.json','["毒蛇猛虎空相向，鐵壁銀山謾自橫。", "長笛一聲歸去好，更于何處覓疑情。"]'),
('85928d13-e3ae-4fd2-b8a5-2e5f81e29c17','句','吳偉明','宋','宋诗','song-poetry','','[]','梁山重回首，翠峰三十六。',12,'全唐诗/poet.song.80000.json','["梁山重回首，翠峰三十六。"]'),
('1636137e-27ad-45e2-84a1-dab060be42fd','題碧沼寺','徐偉達','宋','宋诗','song-poetry','','[]','古寺登臨不記秋，重來境物更清幽。',64,'全唐诗/poet.song.80000.json','["古寺登臨不記秋，重來境物更清幽。", "煙籠野色穿窻日，竹引寒泉繞徑流。", "杜閣諦觀緇侶肅，蓮堂時有妙音浮。", "老僧喜客殷勤甚，冰簟蒲團爲我留。"]'),
('512257ad-2471-4f98-84dd-e36a7417e17d','三江亭','顧文','宋','宋诗','song-poetry','','[]','詞源倒峽勢奔侵，綆短那容汲萬尋。',64,'全唐诗/poet.song.80000.json','["詞源倒峽勢奔侵，綆短那容汲萬尋。", "望屬滄浪驚鶴唳，志存流水識琴心。", "揮毫句句囊盛錦，拜賜人人袖有金。", "不日都俞在廟廟，更聽虎嘯應龍吟。"]'),
('bcd2f365-461c-463b-90a0-37e68df6d013','句','李宋臣','宋','宋诗','song-poetry','','[]','秀峰雙拱背，庾嶺獨當眸。',12,'全唐诗/poet.song.80000.json','["秀峰雙拱背，庾嶺獨當眸。"]'),
('967ebe93-45f0-49cc-86c9-6723826f0b57','資福寺','黄薦可','宋','宋诗','song-poetry','','[]','一逕崎嶇步翠微，亂山深處掩柴扉。',64,'全唐诗/poet.song.80000.json','["一逕崎嶇步翠微，亂山深處掩柴扉。", "煙蘿密鎖人家少，碎石崚嶒馬足稀。", "泉跳浮漚員復散，人生幻夢是還非。", "何時識此林泉趣，飽飯參禪向上機。"]'),
('9a6bbb21-4cbb-4050-98b3-c924a30bf3a2','題大眉小眉山','黄銳','宋','宋诗','song-poetry','','[]','一嶺復一嶺，山巓又一巓。',48,'全唐诗/poet.song.80000.json','["一嶺復一嶺，山巓又一巓。", "步丘皆力穡，掌地也成田。", "線引山腰路，針穿石眼泉。", "眉山同是號，此處合生賢。"]'),
('157a224e-bf4b-47b9-b559-3bf0e6e1c562','次韻竟宣聖林','林伯顯','宋','宋诗','song-poetry','','[]','生民未有如夫子，好學皇泉最自強。',32,'全唐诗/poet.song.80000.json','["生民未有如夫子，好學皇泉最自強。", "功業當年雖坎壈，聲名後世愈芬芳。"]'),
('82357aff-2616-4244-8410-6fdccdb381b4','題濂溪','林煥','宋','宋诗','song-poetry','','[]','我來濂溪拜夫子，馬蹄深入一尺雪。',98,'全唐诗/poet.song.80000.json','["我來濂溪拜夫子，馬蹄深入一尺雪。", "長嗟豈惟溪泉廉，化得草木皆清潔。", "夫子德行萬古師，坡云廉退乃一隅。", "有室既樂賦以拙，有溪何減名之愚。", "水性本清撓之濁，人心本善失則惡。", "安得此泉變作天下雨，飲者猶如夢之覺。"]'),
('51876ec8-1f09-4104-b2e1-417a65018218','洞霄宮','成無玷','宋','宋诗','song-poetry','','[]','我欲觀太華，一笑凌險阻。',132,'全唐诗/poet.song.80000.json','["我欲觀太華，一笑凌險阻。", "滅跡恨未果，衰容遽如許。", "東南豈不佳，泉石閟靈府。", "未訪潛山源，且尋天目乳。", "一峰拔地起，離立誰敢侮。", "千巖絕附麗，萬壑失媚嫵。", "有如人中傑，羞與絳灌伍。", "翠箬藏丹砂，石洞飛白鼠。", "游人倦登陟，異境何由睹。", "振衣臨絕頂，雲外聽天語。", "仙人儻予迎，從此遂輕舉。"]'),
('dddbb3e1-ed64-4426-93ec-c78195c5a922','游開山寺','歐陽子槐','宋','宋诗','song-poetry','','[]','高平北路入禪堂，行轉茅岡上石岡。',64,'全唐诗/poet.song.80000.json','["高平北路入禪堂，行轉茅岡上石岡。", "壑險橋危需一葦，山深樹古立千章。", "禽聲嚦嚦如簧巧，溪曲灣灣似带長。", "我欲拂衣登絕頂，低徊吟嘯白雲鄉。"]'),
('9f2014c6-5c87-45f3-bbcc-df25db019f41','自題仁壽樓','徐衡','宋','宋诗','song-poetry','','[]','百尺樓成接昊蒼，御題仁壽問行藏。',64,'全唐诗/poet.song.80000.json','["百尺樓成接昊蒼，御題仁壽問行藏。", "四端所有雖爲貴，五福爲先孰敢當。", "日出千山凝曉色，花開十里带秋香。", "老來意外無他念，贏得登臨興味長。"]'),
('5840d9b9-b2f4-4340-8f8f-e8831c699c74','贈彭神童','徐衡','宋','宋诗','song-poetry','','[]','吾家先世有童子，姓名嘗著杜詩史。',208,'全唐诗/poet.song.80000.json','["吾家先世有童子，姓名嘗著杜詩史。", "不緣神氣形相殊，安得公詩重褒美。", "三百年有宋興，妙裔四海皆豪英。", "番郡自古稱多士，群兒頭角又崢嶸。", "洎水之東有彭氏，生兒五歲真佳瑞。", "雙眸點漆肌骨清，不與孩提共嬉戲。", "誦詩記字何了然，瑯瑯一口千萬言。", "弱不勝衣行未穩，凌人氣岸已軒軒。", "嗟予去國亦云久，爲報君恩矢奔走。", "繡衣持節入閭閻，大半故人新白首。", "與兒阿父昔同遊，高才終不事王侯。", "報不在身當在子，發源所與今其流。", "行看直上青雲梯，決取鐘如探囊中籌。"]'),
('9f38c628-f5ab-4d21-a371-8e1d87d7f520','題東明寺','蜀僧','宋','宋诗','song-poetry','','[]','三十年前鎮益州，紫泥丹詔鳳池遊。',64,'全唐诗/poet.song.80000.json','["三十年前鎮益州，紫泥丹詔鳳池遊。", "大鈞播物心難一，六印懸腰老未休。", "佐主不能如傅說，知幾那得似留侯。", "功名富貴今何在，寂寂招題一土丘。"]'),
('5ad22153-001d-487f-9e40-ba2873aea184','答外兄王子常問修行之術','劉卞功','宋','宋诗','song-poetry','','[]','非道亦非律，又非虛空禪。',24,'全唐诗/poet.song.80000.json','["非道亦非律，又非虛空禪。", "獨守一畝宅，惟耕己心田。"]'),
('eabc5b1a-e774-42e8-bc4f-b16841ecb67d','題李公謨壁','劉卞功','宋','宋诗','song-poetry','','[]','日轉庭槐影漸移，重門複壁轉呼遲。',32,'全唐诗/poet.song.80000.json','["日轉庭槐影漸移，重門複壁轉呼遲。", "不如拂袖穿雲去，惟有落花流水知。"]'),
('5db8c856-1c4e-458c-9041-3bf38a1e98f8','自題寫真','劉卞功','宋','宋诗','song-poetry','','[]','韜光晦跡居環堵，閉自凝神事事疏。',32,'全唐诗/poet.song.80000.json','["韜光晦跡居環堵，閉自凝神事事疏。", "漫許丹青傳道貌，難將妙筆寫真如。"]'),
('f8b62abb-1e07-4908-a781-4e0ffbc5227e','贈黎如璧','崔羽','宋','宋诗','song-poetry','','[]','茫茫宇宙春復秋，上清曾記昔年遊。',64,'全唐诗/poet.song.80000.json','["茫茫宇宙春復秋，上清曾記昔年遊。", "燒丹竈古雲煙在，遺履亭虛草樹幽。", "花壓畫欄香夢遠，酒傾磁琖瑞光浮。", "飲餘忍別賢昆季，回首向雲天際頭。"]'),
('27703dd9-3432-4c43-aa34-cea3672900a7','示黎如璋丹訣','崔羽','宋','宋诗','song-poetry','','[]','丹即筌蹄道即魚，忘筌得道證空虛。',64,'全唐诗/poet.song.80000.json','["丹即筌蹄道即魚，忘筌得道證空虛。", "莫堅守抱無爲一，撲碎空虛一也無。", "妙有靈丹常赫赫，含容法界自如如。", "隨緣應感長清靜，九載金剛不壞軀。"]'),
('aedbd977-17c8-4dd0-8c52-90f3d48e0864','雨夜乩壇偶筆','崔羽','宋','宋诗','song-poetry','','[]','煙霏雨濕路泥濘，鶴駕飄然下紫京。',32,'全唐诗/poet.song.80000.json','["煙霏雨濕路泥濘，鶴駕飄然下紫京。", "休咎吉凶休動問，細談時事與黄庭。"]'),
('0b684221-20ac-4cd1-920e-3bc875278f44','葛塘','段拂','宋','宋诗','song-poetry','','[]','築圃依山曲，開門向水湄。',48,'全唐诗/poet.song.80000.json','["築圃依山曲，開門向水湄。", "春風搖鼠梓，夜雨足鳬茈。", "但解髡能飲，焉知朔欲饑。", "提壺花外轉，催出眼前詩。"]'),
('861a4a1a-4783-4f53-a868-e3d9292929fa','呈大慧禪師偈','計法真','宋','宋诗','song-poetry','','[]','終日看經文，如逢舊識人。',24,'全唐诗/poet.song.80000.json','["終日看經文，如逢舊識人。", "莫言頻有礙，一舉一回新。"]'),
('fbe9df72-be8d-4e12-a920-05942cd4c657','子温姪用再聞誦新作突過黄初詩作十詩見遺輒勉强次韻  其一','張擴','宋','宋诗','song-poetry','','[]','小人無遠謀，湮没如湛輩。',48,'全唐诗/poet.song.80000.json','["小人無遠謀，湮没如湛輩。", "胸中氣奄奄，垂盡鼓一再。", "安知翰墨場，李杜凛然在。", "文章作甘棠，百世負遺愛。"]'),
('19b0cae2-f57c-4518-bdbc-0952ed8b9cd2','子温姪用再聞誦新作突過黄初詩作十詩見遺輒勉强次韻  其二','張擴','宋','宋诗','song-poetry','','[]','退休小得計，耳冷百不聞。',48,'全唐诗/poet.song.80000.json','["退休小得計，耳冷百不聞。", "戎馬叵奈何，四郊尚兵氛。", "眼中習主簿，才似李將軍。", "小試未爲屈，有君如華勲。"]'),
('f78d45bb-5cc6-4bd2-8548-302aa168b328','子温姪用再聞誦新作突過黄初詩作十詩見遺輒勉强次韻  其三','張擴','宋','宋诗','song-poetry','','[]','十年功名心，客枕寄歸夢。',48,'全唐诗/poet.song.80000.json','["十年功名心，客枕寄歸夢。", "衆中不卓立，老大復何用。", "收身入禪寂，蔬茹飽僧供。", "蛙鳴誰官私，聊欲當絃誦。"]'),
('92513782-3d08-43c1-a5f2-534123bdfbe2','子温姪用再聞誦新作突過黄初詩作十詩見遺輒勉强次韻  其四','張擴','宋','宋诗','song-poetry','','[]','大道昔彫喪，夷塗日荒榛。',48,'全唐诗/poet.song.80000.json','["大道昔彫喪，夷塗日荒榛。", "進無活國謀，俯仰多由人。", "人生幾何時，夜旦互相因。", "往者不可作，未妨来日新。"]'),
('b46533e2-0bf0-44a9-87ff-0ce4619c9e57','子温姪用再聞誦新作突過黄初詩作十詩見遺輒勉强次韻  其五','張擴','宋','宋诗','song-poetry','','[]','國風久淪亡，毛鄭紛六鑿。',48,'全唐诗/poet.song.80000.json','["國風久淪亡，毛鄭紛六鑿。", "譬如秋水篇，破壞向與郭。", "千年見淵明，五字配前作。", "誰傳古人訣，定自顧方略。"]'),
('8333e181-7e82-4715-adab-85f436b92aa9','子温姪用再聞誦新作突過黄初詩作十詩見遺輒勉强次韻  其六','張擴','宋','宋诗','song-poetry','','[]','吾詩窘時窮，章句羞拙訥。',48,'全唐诗/poet.song.80000.json','["吾詩窘時窮，章句羞拙訥。", "君詩非吾偶，齊大輕鄭忽。", "雷門不敢過，西施忌唐突。", "政當就阿戎，談天捜理窟。"]'),
('0ac87261-f61b-404c-a0d3-580401bb81dd','子温姪用再聞誦新作突過黄初詩作十詩見遺輒勉强次韻  其七','張擴','宋','宋诗','song-poetry','','[]','贈篇最崛奇，披讀輒三過。',48,'全唐诗/poet.song.80000.json','["贈篇最崛奇，披讀輒三過。", "巧如媧皇手，五色補天破。", "珍宜宗廟享，净戒兒女涴。", "誰能續離騷，且用追楚些。"]'),
('7d71a0f2-ee16-47c2-8d89-43adf1f3f559','子温姪用再聞誦新作突過黄初詩作十詩見遺輒勉强次韻  其八','張擴','宋','宋诗','song-poetry','','[]','達人雲間鶴，初不謀稻粱。',48,'全唐诗/poet.song.80000.json','["達人雲間鶴，初不謀稻粱。", "渠有酒百壺，買舟從伯郎。", "世間乳臭兒，衣服誇玄黄。", "豈識衛叔寶，胸中無膏肓。"]'),
('79b94e31-388d-4de6-af23-21566c86099e','子温姪用再聞誦新作突過黄初詩作十詩見遺輒勉强次韻  其九','張擴','宋','宋诗','song-poetry','','[]','躬耕良苦辛，十畝手自鋤。',48,'全唐诗/poet.song.80000.json','["躬耕良苦辛，十畝手自鋤。", "我窮分定耳，矧復憐封胡。", "君今未三十，詩聲殿黄初。", "後生要努力，勿及几杖扶。"]'),
('525e89a8-61c1-429e-8c2b-30e7c122f0a1','子温姪用再聞誦新作突過黄初詩作十詩見遺輒勉强次韻  其一○','張擴','宋','宋诗','song-poetry','','[]','連門水竹居，照映麋鹿姿。',48,'全唐诗/poet.song.80000.json','["連門水竹居，照映麋鹿姿。", "子戴靖節巾，得我如遠師。", "花黄催重九，羽葆雜金規。", "未能沽酒飲，且賦止酒詩。"]'),
('181e99ec-9f33-4b15-8091-1d1a3f4d4f53','子温縣丞姪長篇見贈并攜少卿伯父梅堂所賦絕句相示翰墨宛然嘆息久之因次其韻','張擴','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','平生張洪州，豪氣壓羣士。',288,'全唐诗/poet.song.80000.json','["平生張洪州，豪氣壓羣士。", "唾視狗鼠輩，紛紛何足數。", "晚登文石陛，劍服峨櫑具。", "高論忍違時，所愧罔君父。", "至今家集中，秩秩有倫次。", "流傳到諸孫，誰復步亦步。", "此翁日已遠，疇昔旦暮遇。", "何温少也爽，芝蘭秀而紫。", "狀貌類洪州，談笑了萬事。", "筆端見微鋩，妙解如削鐻。", "精剛金百鍊，該貫龜五聚。", "俗學不足詆，紛綸或殊趣。", "斯文懸諸天，字字有分付。", "詖詞頗亂真，蕪纇少刪去。", "吾子壯且勇，政在戒逸豫。", "昨者忽過門，短袖出長句。", "軒然禰正平，坐誦鸚鵡賦。", "洞庭莽空闊，終日奏咸濩。", "初非郭林宗，豈識黄叔度。", "但驚錦囊文，及此春秋富。", "未能賞雌霓，且復說奇字。", "吾年過半百，世事亦何慕。", "杖屨相扶攜，筋骸日僵仆。", "猶於五字中，彫刻歎冰柱。"]'),
('02c128d3-68d5-4417-b411-bc924f380a14','次韻大年姪見贈古詩二首  其一','張擴','宋','宋诗','song-poetry','','[]','人生幾何時，心地要平曠。',72,'全唐诗/poet.song.80000.json','["人生幾何時，心地要平曠。", "不須意外求，辛苦尋蒟醬。", "此郎有高處，智出百夫上。", "禪窗接輭語，眉宇春盎盎。", "詩壇久失律，齋戒欲謀將。", "誰専筆陣功，定起太公望。"]'),
('44df2ddc-9a7d-4db0-9cd7-96c5daf82cb8','次韻大年姪見贈古詩二首  其二','張擴','宋','宋诗','song-poetry','','[]','君文秋水篇，曲士羞臆度。',72,'全唐诗/poet.song.80000.json','["君文秋水篇，曲士羞臆度。", "吾文元尚白，窮老甘寂寞。", "向來失宗盟，士氣日卑弱。", "後生苖未秀，况復病草惡。", "如君真挺特，文字獸一角。", "頭風吾何憂，解后當勿藥。"]'),
('1c75fcde-dcdc-480d-aa04-2faa0aa9e57d','大年耆年各賦長篇投名詩社中顧景蕃及伯初子温二姪傳誦喜甚子温有詩因次其韻','張擴','宋','宋诗','song-poetry','','[]','諸君總能詩，字字秉忠信。',120,'全唐诗/poet.song.80000.json','["諸君總能詩，字字秉忠信。", "聯章輒驚人，我老終不近。", "朝來試披讀，花雨亂巾衽。", "獨慚草元迂，浪說周易凖。", "至今覆瓿謗，文字愧小謹。", "昨觀兩雄篇，詞采溢肝腎。", "高參風雅淳，俯謝邊幅窘。", "誰能報殽役，怒語激先軫。", "吾軍老而怯，望敵倒戈盾。", "會看兩猶子，秋風横鴈陣。"]'),
('780f418f-401a-4a4c-9f44-a2c0a880fb74','蓬萊室','張擴','宋','宋诗','song-poetry','','[]','巨鼇戴浮水，屹然瀛海中。',48,'全唐诗/poet.song.80000.json','["巨鼇戴浮水，屹然瀛海中。", "斷取入君手，棗葉懸鍼鋒。", "君本山中人，俗子那用逢。", "猶應謁帝夢，佩環摇天風。"]'),
('690730b3-5ed9-4fd3-85eb-68da6967b137','子温作驅瘡詩伯初與顧景蕃皆屬和蕃以謂不當止酒初以謂宜鍊元氣予亦戲次其韻','張擴','宋','宋诗','song-poetry','','[]','小兒私化權，令行錯窮冬。',192,'全唐诗/poet.song.80000.json','["小兒私化權，令行錯窮冬。", "淫瘍薄皴膚，欲戰壘塊胸。", "道人寖不平，怒髪忽上衝。", "饞夫猶收痂，義士唯吮癰。", "快無仙爪爬，濫有苦劑攻。", "坐令費譏訶，沾汗文字中。", "虎頭筆有神，衆妖避其鋒。", "似聞以意醫，請用三杯通。", "阿兄言更深，細述葆鍊功。", "二說俱可人，而子將何從。", "酒醇儻消憂，氣厚定保躬。", "自然四體胖，那復百病凶。", "吾聞柳州語，禍物人猶蟲。", "旻蒼厭呻呼，疴癢應汝容。", "疾去會有時，未爲吾道窮。", "汝自多識者，吾言猶匆匆。"]'),
('76baf6f3-cd4a-44b7-a9d2-3c3d137a8fd1','送惠子澤工曹罷官還陜右','張擴','宋','宋诗','song-poetry','','[]','關西多名流，後出亦豪俠。',120,'全唐诗/poet.song.80000.json','["關西多名流，後出亦豪俠。", "三年佐幕府，論事費口頬。", "人情易薰染，久或化爲怯。", "不如殽黽去，歸路馬蹀躞。", "雖無米千斛，尚有書百篋。", "吾曹官爲家，窮老漫隨牒。", "南州美風土，水净山九疊。", "子嘗訪之我，行欲買舟楫。", "我本江湖人，妙處飽經涉。", "誰能老作傖，政恐夢爲蝶。"]'),
('27f063e5-f4fe-4d50-b238-bebffd7e8e5f','曾徽言學士求賦所蓄端硯曾嘗避亂海陵家貲盡没于賊獨攜此硯脫去','張擴','宋','宋诗','song-poetry','','[]','君家文房珍，尤者一二數。',108,'全唐诗/poet.song.80000.json','["君家文房珍，尤者一二數。", "端溪從誰得，不記歲月古。", "中窪隱天成，外削餘靁斧。", "色羞龍尾乾，質陋雀臺窳。", "平生依石丈，什襲費調護。", "向來萑葦中，險作百碎補。", "脱身間道還，神物遠侵侮。", "他年沉香亭，奉詔翻樂府。", "周旋妃子手，借潤毛與楮。"]'),
('7f798884-6d7f-47c1-8c50-18febb57421e','次韻周嘉仲刑曹簡航師食筍四首  其一','張擴','宋','宋诗','song-poetry','','[]','籜龍豢不得，託根暫神奇。',48,'全唐诗/poet.song.80000.json','["籜龍豢不得，託根暫神奇。", "忽化清凈供，結緣貧導師。", "回甘溢齒頬，常带泉石滋。", "要知服食功，不减瓊田芝。"]'),
('74dc5d90-07c1-4a95-875c-28f29b72e5bd','次韻周嘉仲刑曹簡航師食筍四首  其二','張擴','宋','宋诗','song-poetry','','[]','此君淡難交，挺挺如立玉。',48,'全唐诗/poet.song.80000.json','["此君淡難交，挺挺如立玉。", "何意昆仍中，爲人償口腹。", "羣嬰脫錦褓，珍勝臠項肉。", "猶堪作味諫，没齒蠲腊毒。"]'),
('10bb5abc-688d-44e4-80f3-a3b4d2c49817','次韻周嘉仲刑曹簡航師食筍四首  其三','張擴','宋','宋诗','song-poetry','','[]','長鑱太寡恩，斵喪東南美。',48,'全唐诗/poet.song.80000.json','["長鑱太寡恩，斵喪東南美。", "至今管城封，濫罰及孱子。", "例求一赦貸，餘潤乞松髓。", "周旋南董手，罵賊到盧杞。"]'),
('68baeeff-dd12-4eb7-ae87-89eaae4496e6','次韻周嘉仲刑曹簡航師食筍四首  其四','張擴','宋','宋诗','song-poetry','','[]','周郎清而臞，菜把助嚴苦。',48,'全唐诗/poet.song.80000.json','["周郎清而臞，菜把助嚴苦。", "槃中玉離離，醖釀冰雪語。", "向來幾時亡，徑欲就君補。", "請讀食笋篇，微言皆可咀。"]'),
('3997c685-d3ec-45a3-97a9-222e75659dfa','謝元齡惠貓頭笋予去春曾同元齡伯初昆仲子公顧景蕃經行林間掘笋以歸子公刻名竹上也','張擴','宋','宋诗','song-poetry','','[]','貍奴戴頭來，本是籜龍種。',60,'全唐诗/poet.song.80000.json','["貍奴戴頭來，本是籜龍種。", "長鑱借願力，攙汝入珍供。", "晨庖辱分甘，輒應食指動。", "令人懷舊游，春服粲羣從。", "竹間留名字，小刻妙南董。"]'),
('dab92d29-64b1-41cb-968a-f500575bc3bd','送次公姪從辟顔拱衛軍中','張擴','宋','宋诗','song-poetry','','[]','結髪事師友，投身翰墨場。',144,'全唐诗/poet.song.80000.json','["結髪事師友，投身翰墨場。", "技成忽棄去，短衣親戎行。", "平生萬卷書，豈無活國方。", "不如口擊賊，對面用所長。", "顔侯將家種，勇過王鐵槍。", "蝥弧每先登，裂袂裹箭創。", "得君如敵國，乳臭未易當。", "中原干戈滿，貔虎政陸梁。", "誰専發縱策，坐待錐脱囊。", "事平各分功，千級歉莫償。", "位卑君勿言，儒雅故自將。", "會從傔籍中，微見奏凱章。"]'),
('68e8b88c-4946-441d-ade5-f3dd6e734d9f','短句調子温姪','張擴','宋','宋诗','song-poetry','','[]','阿丞善談詩，眼如九方臯。',60,'全唐诗/poet.song.80000.json','["阿丞善談詩，眼如九方臯。", "相馬空馬羣，妙在遺骨毛。", "衰老鑚不入，鈍愚如棗膏。", "後生不應爾，筆力生波濤。", "黄絹幼婦語，莫負秋風高。"]'),
('51863457-20b2-4dc3-96f2-395d623ab1c1','與客手談坐久廢食瘧子忽作病退家人相勸從此却枰因爲數語以自解甚似劉伯倫斷酒文也昔孟嘉嗜酒或曰酒有何好而卿嗜之嘉曰公未得酒中趣爾予於弈棋亦云','張擴','宋','宋诗','song-poetry','','[]','棋亦有何好，味如酒中天。',72,'全唐诗/poet.song.80000.json','["棋亦有何好，味如酒中天。", "勝處要自知，豈爲醒者傳。", "吾身等芭蕉，幻質非真堅。", "儻無輕舉訣，未免憂患纒。", "願從爛柯叟，時作坐隱仙。", "人生幾兩屐，不愧阮孚賢。"]'),
('d8b3044c-0f30-4339-8c33-18c5b9835840','詩社近日稍稍復振而顧子美堅壁既久伯初以詩致師請于老僕無語但乞解嚴爾','張擴','宋','宋诗','song-poetry','','[]','宣城詩不多，警句憶江練。',144,'全唐诗/poet.song.80000.json','["宣城詩不多，警句憶江練。", "至今一斑在，時許管中見。", "顧後更難窺，機鋒捷于電。", "欲求換骨訣，如仰射空箭。", "近逃滑稽嘲，不著毛穎傳。", "深藏品題手，舉市謝葵扇。", "我知老成人，别得妙方便。", "要留一轉語，凖備奔北殿。", "後生舌如銛，酬答了忘倦。", "不須遠乞兵，唾手當八面。", "小人智謀短，敢倚筋力健。", "請馳班師檄，白罷兩河戰。"]'),
('4de07cfa-553e-4ffe-9eaa-8ce02dfaed86','盛暑得竹簟甚精戲爲之賦','張擴','宋','宋诗','song-poetry','','[]','南山小籜龍，離立身蒼蒼。',180,'全唐诗/poet.song.80000.json','["南山小籜龍，離立身蒼蒼。", "舊任管城子，脫帽棲文房。", "詩書每誤身，或得敗塜殃。", "泠鳩稍知音，與致雛鳯凰。", "人云不如肉，笨伯豈我當。", "何如碎其身，織翠供文章。", "舒卷得自試，作配六尺床。", "主人冰玉潔，風味如潘郎。", "奉身無長物，却暑有奇方。", "空庭貯明月，皎皎夜未央。", "卧看河漢移，使我侵肌凉。", "床間老夫人，面冷如嚴霜。", "相與有瓜葛，未用或參商。", "孤高自可守，炎熱安得長。", "君看白羽扇，秋後徒悲傷。"]'),
('2bb4dade-d18b-4ae9-92c9-c0518e0f24bd','次韻顧景蕃和倪裘師避謗軒詩','張擴','宋','宋诗','song-poetry','','[]','大倪昔遭讒，中路駭車覆。',96,'全唐诗/poet.song.80000.json','["大倪昔遭讒，中路駭車覆。", "今人刺舌戒，默坐惴空谷。", "小倪不類渠，先見妙蓍卜。", "閉門自澡雪，巧舌欲誰讟。", "顧侯以詩來，披咏輒三復。", "後生真可畏，我亦慕前躅。", "謗書空滿箧，底用展終幅。", "逢人但稱好，莫問甲煎俗。"]'),
('b58cfcb7-3fd0-4e31-acdc-332b878b8314','汴中追寄吕居仁學士','張擴','宋','宋诗','song-poetry','','[]','頻年如隔生，相見各潦倒。',108,'全唐诗/poet.song.80000.json','["頻年如隔生，相見各潦倒。", "不聞語呫呫，但怪别草草。", "故人俄老矣，零落秋葉掃。", "往者蘇韓輩，人品豈不好。", "時危頗賴渠，惋憤塵一窖。", "五湖在何許，狼籍付鷗鳥。", "春風掠湖尾，蓴絲日夜老。", "我行望吳越，尚及身檢校。", "請分十頃餘，遲子洗鞾帽。"]'),
('0d798375-7747-45f6-8cb9-2725d125121c','次韻出郊','張擴','宋','宋诗','song-poetry','','[]','枝頭見春風，恍覺光景逼。',48,'全唐诗/poet.song.80000.json','["枝頭見春風，恍覺光景逼。", "人生謾拘攣，且作半日適。", "荒郊晴亦好，當費幾兩屐。", "會有遮我留，田家甖甕積。"]'),
('f49fe3c4-2657-4608-81b0-7cb7ce51878a','宿山寺詩','張擴','宋','宋诗','song-poetry','','[]','羸馬不受鞭，倦僕足生繭。',48,'全唐诗/poet.song.80000.json','["羸馬不受鞭，倦僕足生繭。", "茫然山徑間，馳急路逾遠。", "古寺翳林薄，投宿日昏晚。", "夢魔不可眠，青燈照愁眼。"]'),
('1219bd1a-000d-49b8-a5ff-652db8c19562','臘前五日立春天氣極暄妍今復雨雹凛凛不休所居梅花方盛開一雨零落殆盡悵然爲賦此詩','張擴','宋','宋诗','song-poetry','','[]','東風破殘臘，吹盡五日寒。',96,'全唐诗/poet.song.80000.json','["東風破殘臘，吹盡五日寒。", "晴光下楊柳，美影鬭鴨欄。", "錦鱗觸輕冰，碎玉已珊珊。", "日夜望鮮榮，發我砌下蘭。", "寒去仍復來，崛强作跳丸。", "爛漫江梅花，孤芳忽飄殘。", "落跗不可綴，香雪空闌干。", "賴有青春心，養此商羮酸。"]'),
('a9577761-7774-47b9-8a48-3b39b0a18ca3','遊天台山石橋','張擴','宋','宋诗','song-poetry','','[]','亂山雲溟濛，修徑石盤錯。',84,'全唐诗/poet.song.80000.json','["亂山雲溟濛，修徑石盤錯。", "聲聞住世果，窟宅遍巖壑。", "我行適遇雨，風籟響天樂。", "石橋定鬼設，險滑不容脚。", "臨流輒生怖，政墮葱韮惡。", "猶欣曇華供，尚及薦杯勺。", "分嘗不敢餘，稽首謝發藥。"]'),
('bad0cd48-8bca-4e2e-9eca-18e1cd2e1b8e','元齡招飲未果赴復以詩見促輒次其韻并呈景蕃','張擴','宋','宋诗','song-poetry','','[]','主人劇風味，玉壺涵春冰。',120,'全唐诗/poet.song.80000.json','["主人劇風味，玉壺涵春冰。", "惡客費招呼，詩來委弓旌。", "兩季復可人，名應處士星。", "請從狗竇窺，敢辱蒲輪迎。", "我昨占食指，似當嘗黿羮。", "平日口腹累，老窮尚蠅營。", "百花曉無跡，良辰况難并。", "虎頭政病酒，渇肺憐江清。", "未知幾百盞，澆腸訶靁鳴。", "歸時戒被肘，會見金盆傾。"]'),
('ffaca072-3980-44f6-b777-235117b07721','題龔士掾廳壁畫遠山','張擴','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','古來終南山，引手得佳處。',96,'全唐诗/poet.song.80000.json','["古來終南山，引手得佳處。", "未負移文慚，已遭捷徑語。", "公真樂山者，爽氣落眉宇。", "平生手中板，不暇著頬拄。", "叩門無俗客，何礙入官府。", "人生一縷氣，所愧吞不吐。", "畫山猶畫餅，餘習近兒女。", "勿學好事人，吾言當有取。"]'),
('a3fa493c-6c34-4c79-a8ee-f3fcb199e524','遊虎丘寺詩','張擴','宋','宋诗','song-poetry','','[]','官舟轉城隅，十里虎丘路。',108,'全唐诗/poet.song.80000.json','["官舟轉城隅，十里虎丘路。", "招提占山頂，像設儼廊廡。", "池深歸寶劍，石老化蹲虎。", "晉時生法師，談辯阿佛祖。", "至今講經地，往往拾花雨。", "我行及摇落，秋色侵杖屨。", "衲僧施净供，汲井薦牛乳。", "平臺俯曠野，䆉稏莽四顧。", "纍纍多新塜，不見真娘墓。"]'),
('7e88a396-2d64-4944-8221-2f3ca8348d64','次韻趙悦中防禦喜雪','張擴','宋','宋诗','song-poetry','','[]','天南霜力微，不洗瘴地煖。',120,'全唐诗/poet.song.80000.json','["天南霜力微，不洗瘴地煖。", "窮冬雪一尺，坐受坑谷滿。", "夢聞淅瀝聲，驚起欲窺管。", "敢倚狐貉温，但愁衣带緩。", "王孫雪争妍，耿耿抱丹款。", "閉門不知寒，高卧腹自坦。", "紙窗飛花集，亂撲書檠短。", "不憂詩作魔，政藉酒爲伴。", "忽枉郢人曲，懸知和者罕。", "猶餘雪清甘，味勝茶七椀。"]'),
('76458429-ef0f-4fb5-bbca-3b0bf1b2bd0a','君山','張擴','宋','宋诗','song-poetry','','[]','亂山如羣羊，合沓千里犇。',72,'全唐诗/poet.song.80000.json','["亂山如羣羊，合沓千里犇。", "君山屹當前，盤踞老虎蹲。", "巨鎮壓坤維，層巔没雲屯。", "下瞰大溪流，千尺清不渾。", "舟人落風帆，挽縴繫山根。", "欲上看星斗，懸崖那可捫。"]'),
('53401580-0846-497b-8ca2-9245b80d2b94','奉和朱新仲祠部六月晦日省宿用白樂天詩無波古井水有節秋竹竿十字爲韻  其一','張擴','宋','宋诗','song-poetry','','[]','漫郎省中宿，展轉良夜徂。',48,'全唐诗/poet.song.80000.json','["漫郎省中宿，展轉良夜徂。", "過雨忽催詩，君詩不可無。", "夜闌風轉高，秋聲倒江湖。", "前對百尺井，夢中聞轆轤。"]'),
('c0fe4c29-397e-46b6-bf44-b1b337d7a4f6','奉和朱新仲祠部六月晦日省宿用白樂天詩無波古井水有節秋竹竿十字爲韻  其二','張擴','宋','宋诗','song-poetry','','[]','六月忽已晦，餘月復幾何。',48,'全唐诗/poet.song.80000.json','["六月忽已晦，餘月復幾何。", "紈扇暫去手，簟紋欲生波。", "詰朝天門開，冠劍争巍峨。", "駑馬策不入，獰劣如騎騾。"]'),
('96d44979-3a07-41a9-9710-3d99f7edec43','奉和朱新仲祠部六月晦日省宿用白樂天詩無波古井水有節秋竹竿十字爲韻  其三','張擴','宋','宋诗','song-poetry','','[]','街鼓肅市喧，爐薰起煙縷。',48,'全唐诗/poet.song.80000.json','["街鼓肅市喧，爐薰起煙縷。", "掩關一繩床，坐穩得處所。", "風前數莖竹，偃蹇不受暑。", "初無兒女姿，氣貌頗高古。"]'),
('d5cb06e8-b1ff-4776-9ca8-33c7266bf146','奉和朱新仲祠部六月晦日省宿用白樂天詩無波古井水有節秋竹竿十字爲韻  其四','張擴','宋','宋诗','song-poetry','','[]','我乃抱俗人，老蛙窺坎井。',48,'全唐诗/poet.song.80000.json','["我乃抱俗人，老蛙窺坎井。", "從君已再暑，造席謾三請。", "倒床輒靁鳴，便腹費嘲哂。", "君豈錄我者，胸次涵萬頃。"]'),
('2a4efb95-3acc-4b99-88d5-d30a102cf5a9','奉和朱新仲祠部六月晦日省宿用白樂天詩無波古井水有節秋竹竿十字爲韻  其五','張擴','宋','宋诗','song-poetry','','[]','玉壺貯層冰，憐子清徹底。',48,'全唐诗/poet.song.80000.json','["玉壺貯層冰，憐子清徹底。", "對之三伏中，愧我汗如水。", "謬呼同舍郎，坐席更論齒。", "從今痛自戒，子出則我止。"]'),
('b9d1530e-50ec-4c43-b8f5-dd7eaa2f0dd0','奉和朱新仲祠部六月晦日省宿用白樂天詩無波古井水有節秋竹竿十字爲韻  其六','張擴','宋','宋诗','song-poetry','','[]','昨者東觀遊，歲月未覺久。',48,'全唐诗/poet.song.80000.json','["昨者東觀遊，歲月未覺久。", "對床屢忘形，持論相可否。", "君年雖减我，文字稱祭酒。", "十篇亦奇偉，乞我未曾有。"]'),
('e8c59918-91be-46d2-8cff-7e9b60b2168d','奉和朱新仲祠部六月晦日省宿用白樂天詩無波古井水有節秋竹竿十字爲韻  其七','張擴','宋','宋诗','song-poetry','','[]','陰陽無停機，百物競時節。',48,'全唐诗/poet.song.80000.json','["陰陽無停機，百物競時節。", "燠寒更事爾，氣至自融結。", "炎天勿怨嗟，歲晏見霜雪。", "此時衣褐單，但恨不得熱。"]'),
('3a3e1156-1a57-4b0a-941e-c98c45c32601','奉和朱新仲祠部六月晦日省宿用白樂天詩無波古井水有節秋竹竿十字爲韻  其八','張擴','宋','宋诗','song-poetry','','[]','俎豆能折衝，儒冠或兜鍪。',48,'全唐诗/poet.song.80000.json','["俎豆能折衝，儒冠或兜鍪。", "六月早奏功，豈待防高秋。", "俗士懷晏安，所至賈人留。", "襆被應自疏，未知幾宜休。"]'),
('f1ba76f4-508b-4023-89f7-9953209f5ddd','奉和朱新仲祠部六月晦日省宿用白樂天詩無波古井水有節秋竹竿十字爲韻  其九','張擴','宋','宋诗','song-poetry','','[]','疾風掃蚊雷，勢力如破竹。',48,'全唐诗/poet.song.80000.json','["疾風掃蚊雷，勢力如破竹。", "青奴冷侵肌，此乃我所欲。", "周旋蝸舍中，未用歎跧伏。", "亦莫問馬曹，微文禁離局。"]'),
('6c230fcd-a7a7-4362-98fd-ac30b45b45ad','奉和朱新仲祠部六月晦日省宿用白樂天詩無波古井水有節秋竹竿十字爲韻  其一○','張擴','宋','宋诗','song-poetry','','[]','祠曹秉史筆，翰墨窺金鑾。',48,'全唐诗/poet.song.80000.json','["祠曹秉史筆，翰墨窺金鑾。", "燈火漸可親，蠹藁字未漫。", "玉殿行奏書，秋暉上旌竿。", "君文永有託，九廟方如盤。"]'),
('3a1c6514-f592-4d55-b32e-a05ace070f68','送向履方吏部提刑浙西','張擴','宋','宋诗','song-poetry','','[]','君曾仗使節，惠浹東吳民。',72,'全唐诗/poet.song.80000.json','["君曾仗使節，惠浹東吳民。", "豈無賢大夫，平反孰與君。", "省户昔郎潛，渇見老成人。", "賜還席未煗，被遣日已新。", "瘡痍要撫摩，秋荼傷吾仁。", "掾吏熟官長，定不専惠文。"]'),
('98b6d53f-5ab3-44a6-9081-4f463a4985d1','括蒼官舍夏日雜書五首  其一','張擴','宋','宋诗','song-poetry','','[]','南方饒鬱蒸，頗厭夏日永。',60,'全唐诗/poet.song.80000.json','["南方饒鬱蒸，頗厭夏日永。", "好風從南來，分我簟枕冷。", "官曹早歸休，客禮疏造請。", "讀書無近功，睡魔印湯餅。", "誰家烹茶急，羸缾斷脩綆。"]'),
('17c3e45f-4856-48e0-81b1-8e3d06729feb','括蒼官舍夏日雜書五首  其二','張擴','宋','宋诗','song-poetry','','[]','昨日猶苦雨，高簷如懸麻。',72,'全唐诗/poet.song.80000.json','["昨日猶苦雨，高簷如懸麻。", "今朝陰雲開，閃閃見日花。", "孤城如斗大，籬落無千家。", "共迫口腹營，不如市井譁。", "日暮計錐刀，辛苦良可嗟。", "吾儕豈達者，亦是蚿憐蛇。"]'),
('305b2b82-40e6-45a5-8eea-0174137a65d9','括蒼官舍夏日雜書五首  其三','張擴','宋','宋诗','song-poetry','','[]','富者餘金玉，所畏盗賊攻。',72,'全唐诗/poet.song.80000.json','["富者餘金玉，所畏盗賊攻。", "貧人迫饑寒，無奈四壁窮。", "我今仰官給，政在貧富中。", "雖無兩者憂，歸興忽已濃。", "同僚相掩覆，幸此東郭蹤。", "獨念素餐者，幽暗弗汝容。"]'),
('b09d62be-df42-4f83-98fd-683878819d19','括蒼官舍夏日雜書五首  其四','張擴','宋','宋诗','song-poetry','','[]','狴犴深扄鐍，符驗劇關防。',60,'全唐诗/poet.song.80000.json','["狴犴深扄鐍，符驗劇關防。", "老胥蛇蝮心，抱案鳬鶩行。", "我無平反手，補劓救闕傷。", "但知三尺律，絲髪不可攘。", "便文真得計，所愧漢于張。"]'),
('37e41050-886b-43f1-9275-d72939be7795','括蒼官舍夏日雜書五首  其五','張擴','宋','宋诗','song-poetry','','[]','說詩如說禪，妙處要懸解。',72,'全唐诗/poet.song.80000.json','["說詩如說禪，妙處要懸解。", "無人具眼目，胸臆空壘塊。", "吾友吕居仁，句法入三昧。", "向者五言城，精密逼前輩。", "教我深耕鋤，歲晚識稊稗。", "三年苦未領，慚愧朋友戒。"]'),
('069b4a33-fe63-4d86-938c-a6fa2227225e','庭前兩鳴鵲','張擴','宋','宋诗','song-poetry','','[]','庭前兩鳴鵲，聲好色亦美。',60,'全唐诗/poet.song.80000.json','["庭前兩鳴鵲，聲好色亦美。", "曾陪織女駕，或是竇家子。", "誰云屋上烏，可厭不可邇。", "烏能逐人好，鵲竟誤君喜。", "烏鵲莫愛憎，鷄蟲任生死。"]'),
('9d39669c-b9a8-4a9f-b1cf-99ae0faaa1d0','讀試卷有感','張擴','宋','宋诗','song-poetry','','[]','巧語互一律，紛然如銛鋒。',144,'全唐诗/poet.song.80000.json','["巧語互一律，紛然如銛鋒。", "揮筆餘萬言，積案成千重。", "誰令繆悠子，持衡居其中。", "兩目病且昏，不辨牛馬蹤。", "而使視試文，豈能分雌雄。", "往時心力彊，眼明耳猶聰。", "本欲藉科舉，脱此文字攻。", "一朝反自縛，身隨蠹書蟲。", "負郭有田園，猶存荒菊叢。", "頻年秔稻熟，酒賤尊不空。", "胡不駕柴車，遠揖陶令風。", "作詩請伯氏，林下相追從。"]'),
('f2c8b4ca-cad7-41b0-a51a-b91111dcccc7','送王賓察院提點成都府路刑獄','張擴','宋','宋诗','song-poetry','','[]','三峽占地嶮，風濤漲高秋。',144,'全唐诗/poet.song.80000.json','["三峽占地嶮，風濤漲高秋。", "君還席未穩，忽理上水舟。", "潭潭御史府，登用第一流。", "持斧亦間遣，平反要分憂。", "岷峨接家山，民瘼不待求。", "身從日邊來，彈壓西南州。", "風煙亂老眼，轉覺詩語遒。", "平生補衮心，敢爲衣錦留。", "賦歸摩刀環，趣覲瞻前旒。", "會收巖壑姿，入綴鵷鷺遊。", "誰云蜀道遠，笑却萬里愁。", "灧澦漫如馬，莫作忠臣羞。"]'),
('68b94edb-e1dd-4cc2-89e1-449b05ece019','送韓存中侍郎赴隨州','張擴','宋','宋诗','song-poetry','','[]','昔時公卿門，一飯日三吐。',240,'全唐诗/poet.song.80000.json','["昔時公卿門，一飯日三吐。", "末流士自棄，此道久如土。", "韓公昌黎裔，樂善從其祖。", "低頭拜東野，舉頸望杜甫。", "今年河陽歸，坐穩得處所。", "開關逢俗人，却走唾腐鼠。", "禪房大如掌，僅著范蘇吕。", "小人江湖散，賦性甚愚魯。", "青衫插手板，舌卷紙上語。", "曾從諸公遊，過聽謬見許。", "嘗聞公姓名，桓桓貔與虎。", "乞身雖及早，朝論久未與。", "昨日恩詔下，還分一麾去。", "風霜侵行李，笳角嚴曉鼓。", "漢東諸侯國，文物略近古。", "下車訪諸生，往往得何武。", "莫空罇前酒，豈乏户外屨。", "應還二三子，雪擁一環堵。", "詩成欲相寄，黄鵠短翎羽。", "阿連儻可借，千里亦跬步。"]'),
('f2fe405b-1e64-4452-b273-e68f9e3daede','送胡德輝禮部知嚴州先還毗陵待闕','張擴','宋','宋诗','song-poetry','','[]','識君大梁城，才逸驥千里。',84,'全唐诗/poet.song.80000.json','["識君大梁城，才逸驥千里。", "相從十年後，志節老彌厲。", "石渠浩圖史，萬事問伯始。", "爲郎初未伸，請郡聊自試。", "連朝風雨惡，春日尚餘幾。", "故山窗户接，巵酒庭闈喜。", "離别不足云，得詩倘頻寄。"]'),
('86f7b683-c501-43f2-9b72-8a0fd24d9668','送邵公濟校書守果州分韻得歌字','張擴','宋','宋诗','song-poetry','','[]','人物妙伊洛，衣冠肩上摩。',144,'全唐诗/poet.song.80000.json','["人物妙伊洛，衣冠肩上摩。", "君門世所高，家學承丘軻。", "斯文晚付君，自信保不磨。", "平生眼中書，五車未爲多。", "一字不借力，虚名空作魔。", "我數奉談麈，老頑君弗訶。", "持酒欲挽君，酒盡如君何。", "百丈泝巴峽，脩途接岷峨。", "新句探古錦，好風散沉疴。", "先君果山政，惠愛如春和。", "向來窺一斑，再至鬢已皤。", "會尋竹馬盟，爲續襦袴歌。"]'),
('d8bda4fc-e978-4d1b-a48e-6fe8c768c033','周秀實監丞聞嘉禾兵亂請急歸唁其親朋還朝有作因次其韻','張擴','宋','宋诗','song-poetry','','[]','羽書劇紛綸，將士愧庸懦。',84,'全唐诗/poet.song.80000.json','["羽書劇紛綸，將士愧庸懦。", "誰扶中興舉，康濟須十亂。", "周郎人中傑，表表蒼柏幹。", "向來圍城厄，夢想音信斷。", "瞻敬會有時，神明恍還觀。", "他年銓衡手，抗論清月旦。", "勿爲俗人言，鐘鼓驚斥鷃。"]'),
('35e9ab31-b85d-47d6-a429-f8cd69ae9240','次韻伯初春日村居','張擴','宋','宋诗','song-poetry','','[]','君新御祥琴，哀調寫苫塊。',120,'全唐诗/poet.song.80000.json','["君新御祥琴，哀調寫苫塊。", "夕衣愴純素，忍復向綵繢。", "春風苦撩人，浪信翦刀碎。", "試尋桃李枝，紅白已平配。", "嗟予老亡聊，屋角委冠珮。", "出門如鬼縶，久不歷闤闠。", "憐君佛屋底，喜客妙占對。", "家田半收秫，掀簸出舂碓。", "不妨釀春酒，莫及春事退。", "要觀空洞腹，容我數百輩。"]'),
('f84ddec9-2d95-49b1-8607-120f421661b2','次韻方仲運使兄遊允仲花園即事  其一','張擴','宋','宋诗','song-poetry','','[]','園中主人老書生，結髪入仕今辭榮。',96,'全唐诗/poet.song.80000.json','["園中主人老書生，結髪入仕今辭榮。", "自培花柳趁時節，客來時亦倒屣迎。", "江西使者歸更早，功名夙戒良狗烹。", "今晨相遇及閒暇，短榻分坐如意横。", "竹間細路元屈曲，雪後諸峰自分明。", "豈無麗人奉巾櫛，瓊枝照眼生光晶。"]'),
('6ff38648-01f6-4971-9ab9-ffa65926e7ea','次韻方仲運使兄遊允仲花園即事  其二','張擴','宋','宋诗','song-poetry','','[]','新蔬無價手自擷，濁酒有功面微頳。',96,'全唐诗/poet.song.80000.json','["新蔬無價手自擷，濁酒有功面微頳。", "似聞野燒出奇觀，風中烈焰若化城。", "須臾變滅了無迹，何獨世事遭紛更。", "逢場作戱達者事，感物入詠詩人情。", "來篇况是冰雪語，三復使人毛骨輕。", "欲續短章却袖手，偏師莫犯細柳營。"]'),
('4d16b038-3cc0-4e75-9877-d47c8b056ae7','建炎辛亥八月二十六日夜夢艤舟江岸與梅和勝論詩梅出古詩示予極壯麗復爲予作湯餅方就席視梅手中器已十裂湯餅淋漓覺而悵然作此篇','張擴','宋','宋诗','song-poetry','','[]','青燈吐吞幃幔間，竹風吹衾夢初圓。',80,'全唐诗/poet.song.80000.json','["青燈吐吞幃幔間，竹風吹衾夢初圓。", "故人頸血化秋碧，詩語尚作春花妍。", "平生酒炙飽澆潑，湯餅那用相周旋。", "即今彊敵要電掃，四海銜憤聲徹天。", "乞靈上帝真易耳，底事未忘章句傳。"]'),
('d12a6d5c-8e0f-4c12-a91e-dbe37d9d7970','題長沙王祠','張擴','宋','宋诗','song-poetry','','[]','霸上真人赤龍子，西滅彊秦東破楚。',96,'全唐诗/poet.song.80000.json','["霸上真人赤龍子，西滅彊秦東破楚。", "一時佐命皆人豪，崛起屠沽拔行伍。", "番君舊德江湖情，不用智勇收功名。", "抑然退讓古君子，坐視几俎登韓彭。", "漢家南面屬同姓，公亦疏封奉朝請。", "至今遺愛祀鄉人，不獨當年書甲令。"]'),
('98a76255-2e06-4f36-866c-8d9b97ae9955','雙椿堂牡丹盛開彦紳節推弟置酒集客子温不在席中以詩乞花歸賞因次其韻','張擴','宋','宋诗','song-poetry','','[]','春風不悞東君委，杏苑桃蹊滿行李。',96,'全唐诗/poet.song.80000.json','["春風不悞東君委，杏苑桃蹊滿行李。", "春風好處總未忙，姚花初黄魏花紫。", "洛陽園中枝梗肥，欹壓帽簷如覆巵。", "南遷終覺典刑在，不數侍女誇時宜。", "詩中了了惜花意，苦覓繁枝定誰寄。", "何如秉燭坐花傍，照到夜分從墮淚。"]'),
('6adf0561-d50d-4203-a7fe-2039901a099f','子温用前韻催彦紳賞牡丹未及開罇請再作詩促之','張擴','宋','宋诗','song-poetry','','[]','後園冠蓋如雲委，坐客其誰數程李。',96,'全唐诗/poet.song.80000.json','["後園冠蓋如雲委，坐客其誰數程李。", "吾家小謝自風流，薄羅新染香囊紫。", "老翁看花心已疲，數負十分金屈巵。", "君今年妙言語便，愛酒惜花諸事宜。", "春光不爲主人計，行色匆匆暫如寄。", "欲借珠璣一再酬，恐君泣盡鮫人淚。"]'),
('23463bb4-25bf-4c0b-9d4f-8c9fca369176','次韻何任叟正字舘中試茶','張擴','宋','宋诗','song-poetry','','[]','金柈猥稱檳榔珍，藿食未辨汙吾脣。',176,'全唐诗/poet.song.80000.json','["金柈猥稱檳榔珍，藿食未辨汙吾脣。", "茶丁妙寫犀銙真，排方似欲驕華紳。", "爲君走碾颺微塵，羊腸聲乾行隻輪。", "柘羅裁絹素縷匀，筩絲巧織霜後筠。", "中貯刀圭護百神，乳花初幻人間春。", "計君别品尚絕倫，完璧不受敵國嗔。", "白虹夜氣干秋旻，把玩自覺舌生津。", "天衢小草搜八垠，蒙山顧渚亦懷新。", "香歇色壞非法身，妖星森索避北辰。", "不須會稡權羣臣，龍翔鳯翥登嚴宸。", "向來策勲自有人，君其問諸脩水濵。"]'),
('ac6353cd-4d58-4d56-987d-7b16ce07d1e2','伯初姪謁客道傍叢竹間見梅花盛開村人不知賞嗟惜賦詩因次韻','張擴','宋','宋诗','song-poetry','','[]','少年眼似春冰滑，風味最于花曲折。',144,'全唐诗/poet.song.80000.json','["少年眼似春冰滑，風味最于花曲折。", "衝泥訪客竹邊過，邂逅寒梅照疏節。", "不應誤落野人手，自賦新詩爲昭雪。", "坐憐窮臘太嚴苦，萬木如僵生意絕。", "零丁老枿獨回暖，似借餘波霑涸轍。", "今君把玩不忍去，吹面朔風皴欲裂。", "還家笑我病隤豗，茅屋千窗牆百穴。", "自言親到玉妃館，縞練分行洗紋纈。", "詩成不費鑪錘功，君看錚錚句成鐵。"]'),
('3c4e1f1a-7384-4faf-96ab-4ce428e8674d','用伯初韻再和一篇請子温户曹同賦','張擴','宋','宋诗','song-poetry','','[]','孤山山下苔痕滑，翠竹扶疏水方折。',144,'全唐诗/poet.song.80000.json','["孤山山下苔痕滑，翠竹扶疏水方折。", "靚粧無數招不應，曾與先生護名節。", "即今湖上荆棘滿，誰見穿林度飛雪。", "道傍數本忽照眼，所喜風流未中絕。", "不嫌青女暫試粉，却要風師小回轍。", "君看萬點已可憐，半雜春泥封地裂。", "版曹平生詩作史，坐陋故人探禹穴。", "惜花未忍任零落，借酒生春面如纈。", "酒醒定作返魂章，筆底有丹工點鐵。"]'),
('dac914ef-0544-4689-b898-2db4a7dae9b7','再次韻簡子温','張擴','宋','宋诗','song-poetry','','[]','予詩久愧溪藤滑，佩服君詩生罄折。',144,'全唐诗/poet.song.80000.json','["予詩久愧溪藤滑，佩服君詩生罄折。", "君詩盤錯見梅詩，似借梅花作根節。", "梅花元非世間種，雪裏開花白於雪。", "平生和靖最知音，誰是鸞膠續絃絕。", "苦吟似君良有以，我復何爲怒當轍。", "定知孤艷訴不平，曉來哀笳噴窗裂。", "明朝百蘤豈不好，得魚縱珍非丙穴。", "春風晚賜桃杏寵，琥珀調膏誤成纈。", "寒英謝去亦機警，且禀嚴冬令如鐵。"]'),
('6c8a6747-eaf8-4f99-b380-889a83eea9b0','顧景蕃訪大年姪昆仲留宿細柳軒夜論詩律輒及老朽大年作長篇調景蕃末章見稱過實且欲盡借拙詩因次其韻爲謝','張擴','宋','宋诗','song-poetry','','[]','平生不依南路徐，斗升寄活真魚濡。',304,'全唐诗/poet.song.80000.json','["平生不依南路徐，斗升寄活真魚濡。", "了知浮名誰得喪，定自有數相乘除。", "朅來雲卧澗壑底，槁項不減霜松臞。", "里中能詩二三友，安步過我無庸車。", "要須文字賞雌霓，未暇詼謔翻娵隅。", "談天坐聽落鐻屑，蹇步那敢争先驅。", "顧侯風味更嚴苦，家貧闕辦三韭菹。", "龜腸撐突五千卷，底用會稡箋蟲魚。", "文如楚賓醉後藁，下筆應得銀盆斟。", "近聞晝犯細柳壁，酒闌罷歌却驪駒。", "未妨仲子工料理，珠緋餞歸懷不虚。", "想當展緘疾讀時，新飈策策驚籧篨。", "主人韻高絕少可，客亦未易折簡呼。", "末章字字關老朽，愛我如愛屋上烏。", "吾家兄弟俱人傑，飽聞石氏多珊瑚。", "莫云癡叔良不癡，久諱筆硯陪樵蘇。", "諸郎胸中氣吐霧，咳唾自可回春枯。", "少年得譽似勮勃，他日不愧先楊盧。", "儻見惡詩幸掩覆，人所罵譏鬼揶揄。"]'),
('aacea096-059f-4ab8-8a60-140ba729a0d3','大年復用前韻賦詩見贈亦次韻答之','張擴','宋','宋诗','song-poetry','','[]','燭龍停邊天步徐，酒薄肉乾唇不濡。',304,'全唐诗/poet.song.80000.json','["燭龍停邊天步徐，酒薄肉乾唇不濡。", "漫郎憐我困蒸溽，爲送古風専掃除。", "山頭逢君日乍午，作詩瘦似仙人臞。", "展緘初疑走甘露，熟讀政似鏘鸞車。", "世間癡兒浪摇吻，談空說有天一隅。", "我今冥頑老不入，十年此路空馳驅。", "邇來病廢關藥裹，枵腹日厭葵菽菹。", "窗間敗毫積霜笴，架上蠹帙繁書魚。", "錢神無耳未易使，斗宿不靈那可斟。", "誰門有士料理得，隨地駔駿吾家駒。", "三珠連樹價亡敵，一鶚掣韝名不虚。", "近聞掃徑避袢暑，竹杖青鞋一籧篨。", "枕中邯鄲夢不到，户外孔賓渠自呼。", "讀書瀾翻惜晝短，幾欲挽斷三足烏。", "鼎來說詩劇有味，令我坐享商之瑚。", "斯文所喜未中絕，五字復見李與蘇。", "遺音當從牛鐸證，廢律安取焦桐枯。", "亦知大國功九合，一時盟會收微盧。", "願持狗尾彊貂續，未妨舉手遭揶揄。"]'),
('d1ee790d-3f7c-4418-895b-2facbbd9ed5d','次韻莫養正縣丞獨遊錢塘南北山','張擴','宋','宋诗','song-poetry','','[]','老丞拄笏中了了，坐閱雲陰變昏曉。',192,'全唐诗/poet.song.80000.json','["老丞拄笏中了了，坐閱雲陰變昏曉。", "何爲兩脚苦未停，意在高山知者少。", "昨日春從湖上歸，頗覺沙鷗已馴擾。", "遊人但遲簫皷來，滓穢清虚亦何好。", "君今獨行真得計，自有青螺如髻繞。", "歸來古錦開詩葩，筆下縱横發天巧。", "遨頭舊屬羅浮伯，半夜春風鳴騕褭。", "至今湖山索價高，妙語須君時一掃。", "雖然願君且努力，掛冠歸休未宜早。", "要當千户享封殖，豈但全家荷温飽。", "此時還鄉頭未白，萬錢買山慰潦倒。", "摩挲拄杖不相忘，更伴重巒細窮討。"]'),
('aaf2bd61-dd64-4877-a0d6-3c9293b2b657','讀錢神論偶成','張擴','宋','宋诗','song-poetry','','[]','君不見王衍談天喙三尺，繞床阿堵初未識。',186,'全唐诗/poet.song.80000.json','["君不見王衍談天喙三尺，繞床阿堵初未識。", "又不見阿戎自執紅牙籌，聚錢成癖老不休。", "人生嗜好各殊趣，盗跖孔丘更毁譽。", "不如是非兩置之，萬事欣然隨所遇。", "貴人見錢地上流，富人錢妖聲如牛。", "醉時雖悟落幘語，客至或忘障簏羞。", "謾誇無耳可使鬼，劉濞鄧通皆過計。", "崔烈得名未掩臭，陳萇小黠强稱美。", "我今家徒立四壁，憐渠一箇也不得。", "不願腰纒十萬上揚州，安用呼盧百萬供一擲。", "但要時逢好事人，恰有青銅滿三百。"]'),
('a8772f27-b079-4153-b67f-55bb0bf162f4','次韻富季申著作對雪','張擴','宋','宋诗','song-poetry','','[]','甕中凍蟻欲浮白，主人醉呼嗔惡客。',128,'全唐诗/poet.song.80000.json','["甕中凍蟻欲浮白，主人醉呼嗔惡客。", "到床不省雪作魔，半夜扶頭驚曉色。", "因風初愛横斜好，侵户更憐飄洒密。", "爲梅洗粧却鉛粉，與竹護萌封繭栗。", "瀛州有士漫爲郎，要看諸郎上槐棘。", "不妨病骨倚故絮，且忍饑腸待新麥。", "君今筆陣獨横掃，冷屋無人夜鳴鏑。", "快雪快晴吾弗憂，君詩自有回天力。"]'),
('5c1d7689-dd09-470b-9e0e-25ff3a7e6835','過龍井辯才退居','張擴','宋','宋诗','song-poetry','','["\u897f\u6e56"]','南山北山天接連，西湖環山水涵天。',160,'全唐诗/poet.song.80000.json','["南山北山天接連，西湖環山水涵天。", "佛宫鱗鱗割人境，勝日杖履相周旋。", "久聞龍井未得到，神龍卧靳俗語喧。", "脫身干戈偶不死，步屧十里沙石堅。", "眼明見此屋突兀，修廊廣殿鐘鼓傳。", "笋芽供羮坐取飽，茶乳沃舌聽談禪。", "塔中老人呼不起，至今牆壁尚熾然。", "諸孫其誰嗣衣鉢，但見持律俱精専。", "吾身誤落世纓網，白髪未解憂患纒。", "問龍乞地一席許，作庵共結香火緣。"]'),
('f12894d5-86a4-4b79-a7ad-31b936002e24','題子温姪舫齋','張擴','宋','宋诗','song-poetry','','[]','江湖著身鷗作鄰，平生踏浪不踏塵。',96,'全唐诗/poet.song.80000.json','["江湖著身鷗作鄰，平生踏浪不踏塵。", "晚從闤闠寄行李，旋飾舫齋聊寫真。", "夜闌闕月雲頭湧，風月填窗不成夢。", "團欒十口似浮家，顛倒一生如破冡。", "君看世事風打頭，奔濤濺浪何時休。", "不如問錢多買酒，萬斛與君共拍浮。"]'),
('a16b05bf-96e8-4d76-86e3-4abad668362f','謝人惠團茶','張擴','宋','宋诗','song-poetry','','[]','春陰養芽鍼鋒鋩，沆瀣養膏冰雪香。',112,'全唐诗/poet.song.80000.json','["春陰養芽鍼鋒鋩，沆瀣養膏冰雪香。", "玉斧運風寶月滿，密雲候雨蒼龍翔。", "惠山寒泉第二品，定武烏甆紅錦囊。", "乳花元屬三昧手，竹齋自試魚眼湯。", "老生酸寒極堪笑，藜莧拄腹書撐腸。", "修貢之餘遠分寄，懷璧其罪渠敢當。", "應憐晝睡湯餅惡，爲洗一春蝴蝶狂。"]'),
('a9fb9112-7b01-4b32-9bb8-4f4a7e4b36a0','謝人送炭','張擴','宋','宋诗','song-poetry','','[]','竈煙荼毗霜後林，短椽脫煙烏不黔。',128,'全唐诗/poet.song.80000.json','["竈煙荼毗霜後林，短椽脫煙烏不黔。", "樵童豈惜龜兩手，入市論價輕千金。", "向來幾作溝中斷，漫滅青黄誰過眼。", "焉知負荷鑪錘功，煨燼猶堪借餘暖。", "夜闌吼空風力豪，平明雪山平屋高。", "生柴带葉冷不燄，毁車充薪車脚勞。", "故人十縛起衰朽，生遣寒灰撥紅獸。", "解衣挾纊不足云，那復區區論炙手。"]'),
('282eff73-14cc-4b4c-81ab-9bffc0af8265','秋意','張擴','宋','宋诗','song-poetry','','[]','凉颷吹樹砧聲急，窗户玲瓏秋氣入。',96,'全唐诗/poet.song.80000.json','["凉颷吹樹砧聲急，窗户玲瓏秋氣入。", "井桐彫葉减清陰，漙露無聲金荻泣。", "壁間唧唧候蟲鳴，庭下衰蘭送客情。", "客懷無金酒膽薄，朗月入簾魂魄驚。", "人生萬事今猶昔，不獨炎凉天地隔。", "平明把鏡照衰顔，還有新霜助狼籍。"]'),
('232f303d-36c9-4cbd-82b0-87ded099da18','景蕃還所借詩卷并辱以詩輒次韻','張擴','宋','宋诗','song-poetry','','[]','詩家難傳最上路，汝南雪令排鹽絮。',96,'全唐诗/poet.song.80000.json','["詩家難傳最上路，汝南雪令排鹽絮。", "至今白戰亡此手，我欲重參愧遲暮。", "虎頭文字逼前輩，衮衮屢蒙分尺素。", "天閑老驥日千里，何用鹽車追蹇步。", "向來擊賞楓落句，見不及聞君已誤。", "報之錯刀竟坐癡，他日塵昏磨不去。"]'),
('c3fa09e4-c498-4f83-8681-97fa43ff59cd','景蕃復和再次韻','張擴','宋','宋诗','song-poetry','','[]','詩壇乳臭妨賢路，寄食將軍慚漂絮。',96,'全唐诗/poet.song.80000.json','["詩壇乳臭妨賢路，寄食將軍慚漂絮。", "君今自築五言城，坐遣降俘嘆來暮。", "從來白俗不入眼，并案閨房累蠻素。", "連篇贈我刹那頃，更陋建安誇七步。", "珍藏敢比飛鳥章，字脫無人正訛誤。", "爲君傳寫不得辭，政恐終隨靁電去。"]'),
('810358e5-3c56-46e1-bf2d-1dad0e072c44','過南美軒讀汪彦章倪巨濟詩用壁間韻','張擴','宋','宋诗','song-poetry','','[]','笻杖芒鞋野性馴，偶尋幽步到祗園。',96,'全唐诗/poet.song.80000.json','["笻杖芒鞋野性馴，偶尋幽步到祗園。", "琅玕千本日應長，美影摇風清蔭繁。", "未堪截管變律吕，且乞汗青傳子孫。", "壁間舊有故人題，妙語洒落今仍存。", "那憂積雪折老幹，豫借暖律生枯根。", "我來二子更南北，惟有此君堪與言。"]'),
('fd2fde62-1828-4e6b-97da-5f706b4b9183','允中大夫兄召客賞海棠屬予賦詩','張擴','宋','宋诗','song-poetry','','[]','枝頭桃李半狼籍，浪說春風借顔色。',80,'全唐诗/poet.song.80000.json','["枝頭桃李半狼籍，浪說春風借顔色。", "海棠斬新一樣紅，錦絲欲墮嬌無力。", "主人連日被渠惱，無處分疏更招客。", "重羅作幕裙作圍，麗人行酒客賦詩。", "挽定春光不得放，忍看落紅零亂時。"]'),
('55697481-57de-4828-91df-ce7c77653fd1','次韻大年見貽長篇','張擴','宋','宋诗','song-poetry','','[]','莫誇兒啼賞英物，莫振豺聲露蠭目。',352,'全唐诗/poet.song.80000.json','["莫誇兒啼賞英物，莫振豺聲露蠭目。", "一朝官府生平地，即是高明鬼瞰屋。", "夜郎窮囚罪瀕死，頗費故人解官贖。", "世間萬事真戲耳，變化何殊臂伸縮。", "漫郎紛華老不入，坐掃降魔如破竹。", "曾從處士學礪齒，安用貴人强推轂。", "夜蒙衲被生春温，午饌伊蒲飽園蔌。", "綺羅曵地初不知，海陸窮珍定何族。", "自云百念已灰冷，栩栩胡爲晝摇腹。", "似聞蟻穴得侯封，不借波臣譏斗粟。", "何妨枯骨話王樂，政恐三彭加譴督。", "夢回敢起尋鹿想，謝去已深防蠆毒。", "危幾何處烹五鼎，佳傳誰人米千斛。", "朱軒雖享眼界榮，青史那逃身後戮。", "聊陪洗馬痼煙霞，自逐天隨甘枸菊。", "雖然丈夫有出處，尺蠖之伸未爲曲。", "他年弓旌恐不免，釣渭築巖終夢卜。", "會看鵬翼擊天池，更想於菟嘯風谷。", "此時願君益機警，墮甑欣然了榮辱。", "脫身蟬冕歸去來，吳市空關隱梅福。", "却伴山中赤松遊，儻見海上蟠桃熟。", "吾言有徴勿浪云，龜筮亦從神所告。"]'),
('83dca831-8acd-4414-b9fd-0cba73ca0643','酒官張君造麴以十八仙爲名作詩戱之','張擴','宋','宋诗','song-poetry','','[]','舊聞飲中有八仙，日多鐺杓相周旋。',144,'全唐诗/poet.song.80000.json','["舊聞飲中有八仙，日多鐺杓相周旋。", "今之十八豈其裔，何爲復效枕麴眠。", "癡人但作從事呼，妄起清濁分聖賢。", "那知風味古無有，名字真從天上傳。", "留侯舊與赤松遊，餘韻到今千百年。", "看君風骨頗似祖，日酌九醖追天全。", "我嗟譜系漫難考，流落恐緣濡髪顛。", "窮愁政在禁酒國，未免口角生饞涎。", "出門欲作一斗計，誰乞三百青銅錢。"]'),
('4e1026b6-6609-49bc-bfa3-63295ce7a97d','文之顧景蕃登子温舫齋不遇拈韻賦詩予亦和之','張擴','宋','宋诗','song-poetry','','[]','漫郎不省塵中走，湖海收舟凈無垢。',160,'全唐诗/poet.song.80000.json','["漫郎不省塵中走，湖海收舟凈無垢。", "規摹畫舫作齋館，似要窗間過山岰。", "平生張緒本豪放，人物風流記官柳。", "不應篷底了生涯，定是寓言猶十九。", "顧侯自說虎頭孫，黠不論功癡已久。", "入門浪喜布帆在，興盡中流漫回首。", "更將險語困嘲謔，詩膽故應大如斗。", "我窮政似老侯喜，持竿覓魚不供口。", "愛君馬上醉眼花，萬斛龍驤落盃酒。", "未須腰笏煩易于，且熟他年濟川手。"]'),
('33fcd779-6855-4b11-9d8d-d42a08a44e08','送顧景蕃暫還浙西','張擴','宋','宋诗','song-poetry','','[]','牆頭飛花如雪委，牆根老柳絲垂地。',96,'全唐诗/poet.song.80000.json','["牆頭飛花如雪委，牆根老柳絲垂地。", "春政濃時君不留，山路曉風鳴馬箠。", "濤江入眼浪千尺，想見吳儂問行李。", "田園久荒漫檢校，親舊相逢半悲喜。", "行朝諸公訪人材，故人新賜尚書履。", "袖中有策可則陳，君亦因行聊爾耳。"]'),
('aabe6e5e-4f5b-4671-b002-6b189b7c2071','次韻大年當暑午枕','張擴','宋','宋诗','song-poetry','','[]','道人曾得却暑方，烈日卓午心清凉。',112,'全唐诗/poet.song.80000.json','["道人曾得却暑方，烈日卓午心清凉。", "書齋長物復何有，含風竹簟八尺長。", "睡魔久困世喧閧，乍入寂境如還鄉。", "嗜茶嘗膽汝藥石，煮餅炊飯吾津梁。", "古來至人具法眼，淨穢天女猶皮囊。", "坐禪入定了十劫，睡蛇有口難螫傷。", "要當尋師漸磨洗，想子已聚三月糧。"]'),
('7bff2129-5a71-46a5-a62a-1c1e76bb118d','古律詩戲簡汪彦章學士','張擴','宋','宋诗','song-poetry','','[]','湖邊樂色喧絲筦，湖上春風桃李晚。',96,'全唐诗/poet.song.80000.json','["湖邊樂色喧絲筦，湖上春風桃李晚。", "使君招客試行樂，粉面如花照金琖。", "知君好事已數往，想見清陰集飛繖。", "傾家共尋一日勝，得醉寧論萬金産。", "誰憐有客扄户牖，坐抱窮腸讀書懶。", "登樓追望不堪東，一片飛虹掛愁眼。"]'),
('3fec0761-8148-4b95-ab83-ae192810fdd4','清微軒詩','張擴','宋','宋诗','song-poetry','','[]','君不見楚王宫中多諛臣，雌雄之說徒紛紛。',166,'全唐诗/poet.song.80000.json','["君不見楚王宫中多諛臣，雌雄之說徒紛紛。", "大空槖籥本平施，安有煩冤愁庶人。", "又不見若耶溪上帆如駛，朝南暮北隨人意。", "令行由天不由人，豈爲舟人採薪計。", "君今面山開兩扉，恬養不爲居所移。", "方床曲几淨無暑，有聲南來清且微。", "清似太虛無滓穢，微如少女生妍媚。", "軒中稚竹亦粲然，快與主人便晝睡。", "不須驟吹六律管，不用緩鼓五絃琴。", "會當月夜君家去，却扇扶座開煩襟。"]'),
('5b616c08-2342-446d-a033-4ed916795839','謝范信中鈐轄惠笋炙','張擴','宋','宋诗','song-poetry','','[]','野人敗壁屋數椽，枯腸如龜復如蟬。',112,'全唐诗/poet.song.80000.json','["野人敗壁屋數椽，枯腸如龜復如蟬。", "未憂飽死笑方朔，且要臞形追列仙。", "故園千本籜龍兒，輕靁殷戶争蜿蜒。", "凍泥封根手自斸，一箸可當百味鮮。", "朅來曹南風土惡，虀飯酸嘔羊酪羶。", "君家何從得此品，新馥惠我驚饞涎。", "便當過門乞餘炙，未信羮釡聲轑然。"]'),
('18e2b2d4-e614-4fba-ad01-55392052f6f6','伯寓給事築漫吾亭却寄','張擴','宋','宋诗','song-poetry','','[]','漫郎昔爲補衮客，面如嚴霜心如石。',128,'全唐诗/poet.song.80000.json','["漫郎昔爲補衮客，面如嚴霜心如石。", "手披逆鱗不作難，肯爲俗人借顔色。", "十年收身渺江湖，胸中了然一事無。", "焚香默坐已忘我，酌酒賦詩聊漫吾。", "秋風藕花開十丈，新築危亭枕其上。", "客來口噤不得語，晚節自愛恐招謗。", "别君戃怳不記年，笈中諫紙尚幾番。", "笭箵寄隱亦暫耳，漫乎漫乎誰謂然。"]'),
('9931cb21-167c-482a-b491-da8232b8cb0d','新安程昭文秀才惠子鵝菱角乳梨并鮑清筆','張擴','宋','宋诗','song-poetry','','[]','新安故人哀我貧，尺素自書五朵雲。',96,'全唐诗/poet.song.80000.json','["新安故人哀我貧，尺素自書五朵雲。", "爲憐劉毅遺鵝多，烹食豈慚王右軍。", "烏蓤脫水銳芒角，乳梨包裹飣座珍。", "燒腸饑火得暫温，竊食竈鬼嗟不仁。", "來書習氣徑未掃，十枝尚遣中書君。", "急須整駕詣齋閣，滿請尊酒重論文。"]'),
('38543cdb-35b8-4f40-852f-c93df3efc81f','次韻曾端伯户部初春遣興','張擴','宋','宋诗','song-poetry','','[]','春風入手幾番雨，醖釀春愁推不去。',160,'全唐诗/poet.song.80000.json','["春風入手幾番雨，醖釀春愁推不去。", "琳館道人初未忙，被底掀髯聽粥皷。", "那知春色到桃溪，千樹開花人掩扉。", "路傍垂柳已如許，青眼招春春不違。", "曉來東郊信兩脚，折屐衝泥尚供著。", "枝間啼鳥勸提壺，君省此聲何處惡。", "平生廣平心石堅，未暇徐庾誇清妍。", "句中試下一轉語，突過翰林詩百篇。", "龍鍾似我豈宜說，不獨詩窮官亦拙。", "向來一錯鑄不成，底用辛勤六州鐵。"]'),
('8425a614-9736-4650-a230-45d408fc3cae','老白堂','張擴','宋','宋诗','song-poetry','','[]','君不見三朝魏公拓天手，旌節言歸介眉壽。',134,'全唐诗/poet.song.80000.json','["君不見三朝魏公拓天手，旌節言歸介眉壽。", "築堂自榜醉白名，自借清風洗塵垢。", "又不見峨眉山中謫仙人，玉堂詞翰生風雲。", "每評香山輒自喜，欲向集賢重寫真。", "古人名懸日杲杲，千載貽人不貪寶。", "君今誦味佚老句，乞身投閒不待老。", "草堂寂寂松桂生，溪山四時供醉吟。", "未必翛然便忘世，新詩時亦過雞林。"]'),
('a5eed305-0140-4539-be5a-57b42cab64bf','靈壁石','張擴','宋','宋诗','song-poetry','','[]','十年此地征塵染，誰與山川還舊觀。',128,'全唐诗/poet.song.80000.json','["十年此地征塵染，誰與山川還舊觀。", "九華小樣出君家，要續箇中消息斷。", "此郎與山對立玉，几上重重見陵谷。", "安知可備宫架懸，樂府待之八音足。", "他山豈無石一拳，如琮斷方璧斷圓。", "不如此峰真巧具，六窗七竅俱天然。", "君今落帆錫山近，挈石尋泉丫無恨。", "會須潄石更枕流，世事入門君勿聽。"]'),
('73042c88-613e-47e9-9bd7-f1b30b4a0bc2','讀李長吉集詩','張擴','宋','宋诗','song-poetry','','[]','唐家諸王滕薛親，官府白日生風雲。',144,'全唐诗/poet.song.80000.json','["唐家諸王滕薛親，官府白日生風雲。", "此身豈患財不足，安用盈車載錢緡。", "飄然後出有長吉，冰姿鶴骨真天人。", "錦囊不貯一箇錢，收拾眼中無盡春。", "世儒强作富貴曲，刻畫無鹽恐非真。", "請看卷後將進酒，酩酊一句了伯倫。", "李宗系出玄元孫，玄元稱帝李稱臣。", "玉樓無人可作記，應須此子當此文。", "從來不解進士語，多謝昌黎爲解棼。"]'),
('063733d4-30dd-464e-a2ab-26dc35973639','藥名七夕行','張擴','宋','宋诗','song-poetry','','[]','雲斾萎蕤霞作裾，風静半天河有無。',64,'全唐诗/poet.song.80000.json','["雲斾萎蕤霞作裾，風静半天河有無。", "同槃夜結合歡带，織女新嫁牽牛夫。", "古今此會從容少，百合未諧甘草草。", "預知仔細屬明年，續斷猶勝弓弩絃。"]'),
('cf9eb4a9-0463-4425-b0f3-06be8ec4d7c2','謝賜御書臨晉唐帖三軸','張擴','宋','宋诗','song-poetry','','[]','上帝圖書照東壁，宸毫作字同羲畫。',192,'全唐诗/poet.song.80000.json','["上帝圖書照東壁，宸毫作字同羲畫。", "晉唐舊帖久氣索，數本僅收煨燼厄。", "硬黄小試毛穎功，手蛻千年垂露蹟。", "巧偷豪奪幾蒼黄，晚御清都顔咫尺。", "鍾王行草日失真，神氣頓還三昩力。", "諸天護法宫殿深，九虎守關雷雨隔。", "那知分賜下人間，螻蟻微臣亦懷璧。", "恩均掲榜誇玉堂，事陋登床攫飛白。", "欽惟聖學自天縱，嗜好從來屏聲色。", "青規文字屢策勲，沾丐椒房猶翰墨。", "彤管摛筆侈珍貺，寶唾落牋留小刻。", "從今不愧蔀屋空，會有虹霓光四塞。"]'),
('3328adbe-b1f9-4547-a36d-2d0ae8abacea','挽徽宗皇帝詞五首  其一','張擴','宋','宋诗','song-poetry','','[]','假樂興周治，無爲見舜心。',48,'全唐诗/poet.song.80000.json','["假樂興周治，無爲見舜心。", "七朝傳遠業，十閏紀功深。", "厚澤淪肌骨，隆名秩古今。", "丹成自仙去，黼扆不重臨。"]'),
('570f4f62-4086-4756-8577-568476997a90','挽徽宗皇帝詞五首  其二','張擴','宋','宋诗','song-poetry','','[]','甚盛帝王德，不言天地功。',48,'全唐诗/poet.song.80000.json','["甚盛帝王德，不言天地功。", "皇圖光永泰，聖祚紹元豐。", "化被要荒外，民躋富壽中。", "如椽誰秉筆，炳炳詔無窮。"]'),
('f63916e6-6f6b-4b5c-8e5e-64ae9c4cb2a6','挽徽宗皇帝詞五首  其三','張擴','宋','宋诗','song-poetry','','[]','制作躋堯禹，規摹陋漢唐。',48,'全唐诗/poet.song.80000.json','["制作躋堯禹，規摹陋漢唐。", "方丘排異議，晟府煥新章。", "睦族民歸厚，臨雍國有光。", "奎文連五閣，輪奐儼深藏。"]'),
('b75e648f-3479-4616-b656-55d9cd5cae4c','挽徽宗皇帝詞五首  其四','張擴','宋','宋诗','song-poetry','','[]','內禪超千古，恭聞脫屣輕。',48,'全唐诗/poet.song.80000.json','["內禪超千古，恭聞脫屣輕。", "勲高終不伐，道大自難名。", "玉几音疑在，橋山兆已成。", "九重興舜慕，悲泣見牆羮。"]'),
('b53ff7e0-9d67-4e88-9801-3a18b9521753','挽徽宗皇帝詞五首  其五','張擴','宋','宋诗','song-poetry','','[]','風伯開塵霧，神符八駿游。',48,'全唐诗/poet.song.80000.json','["風伯開塵霧，神符八駿游。", "壽堯方請祝，歸啓已興謳。", "萬里忽清宴，五兵終罷休。", "他年北邙路，王氣接天浮。"]'),
('748268d6-82de-471f-ab38-260931dfda09','挽顯肅皇后詞五首  其一','張擴','宋','宋诗','song-poetry','','[]','珍符開瑞璽，象服備褘褕。',48,'全唐诗/poet.song.80000.json','["珍符開瑞璽，象服備褘褕。", "德盛儀千載，名尊母兩朝。", "流風厚麟趾，賸馥播桃夭。", "羽衛今何處，雲深慘莫招。"]'),
('5ebd4efc-90b7-4b33-8ff1-e9844d9c4e09','挽顯肅皇后詞五首  其二','張擴','宋','宋诗','song-poetry','','[]','儷極承平日，徽音盛一時。',48,'全唐诗/poet.song.80000.json','["儷極承平日，徽音盛一時。", "却奢崇大練，納戒上清規。", "事逐浮雲變，人驚夜壑移。", "三吳謡織女，行路劇傷悲。"]'),
('38e2571f-cb32-4c85-8295-367cd1bf8c8c','挽顯肅皇后詞五首  其三','張擴','宋','宋诗','song-poetry','','[]','寶殿開寧德，彌文更日新。',48,'全唐诗/poet.song.80000.json','["寶殿開寧德，彌文更日新。", "儉勤垂壼則，慈惠配皇仁。", "脫屣堯何聖，補天媧亦神。", "傷心東越路，畫翣暗龍輴。"]'),
('6ebfaf70-c6af-4e04-afdf-9982ab785df6','挽顯肅皇后詞五首  其四','張擴','宋','宋诗','song-poetry','','[]','箴圖高警戒，風雅妙形容。',48,'全唐诗/poet.song.80000.json','["箴圖高警戒，風雅妙形容。", "寶訓聞欽聖，徽名並顯恭。", "宫車陪素仗，園寢祔新封。", "絕勝昭靈后，空歸浣水蹤。"]'),
('5b30492f-db86-476d-83b8-7816a2c880c2','挽顯肅皇后詞五首  其五','張擴','宋','宋诗','song-poetry','','[]','莫狀憂勤意，猶存澣濯衣。',48,'全唐诗/poet.song.80000.json','["莫狀憂勤意，猶存澣濯衣。", "私恩絕外第，遺愛在深闈。", "歲晚望重翟，路長迷六騩。", "蒼梧從舜陟，終陋兩湘妃。"]'),
('e7281131-1048-47b7-88f0-d2101aadc136','挽懿節皇后詞五首  其一','張擴','宋','宋诗','song-poetry','','[]','丰容騰偃月，骨相本天人。',48,'全唐诗/poet.song.80000.json','["丰容騰偃月，骨相本天人。", "潛邸恩輝舊，中闈典冊新。", "夢猶驚鷰璽，光已揜鈎陳。", "不忍瞻行殿，蛛絲網暗塵。"]'),
('1101fb4b-e3e1-4648-becf-1cd72debb7d0','挽懿節皇后詞五首  其二','張擴','宋','宋诗','song-poetry','','[]','作合神明王，中興欲佐周。',48,'全唐诗/poet.song.80000.json','["作合神明王，中興欲佐周。", "友琴懷素志，脫珥謝前修。", "行續姜任懿，名方馬鄧優。", "百年雖電掣，千古仰芳猷。"]'),
('bd92a0df-5eea-4205-94c8-40a6fdcb2bc1','挽懿節皇后詞五首  其三','張擴','宋','宋诗','song-poetry','','[]','內治推炎宋，名參列后賢。',48,'全唐诗/poet.song.80000.json','["內治推炎宋，名參列后賢。", "若爲憂國步，遽報損天年。", "未暢關雎化，空騰煒管傳。", "六宫遵舊訓，女則有遺篇。"]'),
('06437081-168b-402c-a138-82b95ffa1a7d','挽懿節皇后詞五首  其四','張擴','宋','宋诗','song-poetry','','[]','公桑分婦職，春種劭農耕。',48,'全唐诗/poet.song.80000.json','["公桑分婦職，春種劭農耕。", "不到升平日，終乖輔佐情。", "烝嘗開別廟，謚誄紀徽名。", "悽愴鴻溝路，空餘萬歲聲。"]'),
('3f87aee6-565d-463c-8a2e-8fafc437d321','挽懿節皇后詞五首  其五','張擴','宋','宋诗','song-poetry','','[]','萬里歸輼輅，仙遊迹已遐。',48,'全唐诗/poet.song.80000.json','["萬里歸輼輅，仙遊迹已遐。", "猗蘭成斷夢，素柰隕空花。", "隧卜稽山下，輴移浙水涯。", "晚風纒落水，悲咽和哀笳。"]'),
('53af8759-d533-4428-bd46-e3b9b085d43a','悼程西樞母朱夫人二首  其一','張擴','宋','宋诗','song-poetry','','[]','天性敦慈惠，凝然法度中。',48,'全唐诗/poet.song.80000.json','["天性敦慈惠，凝然法度中。", "談玄推道韞，擇配得梁鴻。", "壽嘏無前擬，安榮及令終。", "傷心原上路，哀鐸咽霜風。"]'),
('87b0808c-9a7d-4dfc-9353-823966ba1dcf','悼程西樞母朱夫人二首  其二','張擴','宋','宋诗','song-poetry','','[]','有子登嚴密，人高孟母慈。',48,'全唐诗/poet.song.80000.json','["有子登嚴密，人高孟母慈。", "珍羞五鼎養，象服小君宜。", "未厭斑衣樂，俄嗟泫露悲。", "百年無少憾，千古令名垂。"]'),
('c0cb6893-1a3d-48c4-92db-d127515d72aa','悼主簿弟','張擴','宋','宋诗','song-poetry','','[]','吾家幾兄弟，君自老相依。',48,'全唐诗/poet.song.80000.json','["吾家幾兄弟，君自老相依。", "每憶離亭别，俄傷旅櫬歸。", "新銘聊記遠，舊話總成非。", "舉目蒼茫路，澘然淚滿衣。"]'),
('bd90fb67-e562-4d2f-8bcc-1889ccfb619b','悼次東提刑姪二首  其一','張擴','宋','宋诗','song-poetry','','[]','彊學初無敵，臨民早有聲。',48,'全唐诗/poet.song.80000.json','["彊學初無敵，臨民早有聲。", "暮年猶補郡，餘事及談兵。", "慷慨聞高誼，艱難見老成。", "蓋棺今已矣，百世漫空名。"]'),
('699a9546-c941-4dfc-ac42-0ea49fd78cbd','悼次東提刑姪二首  其二','張擴','宋','宋诗','song-poetry','','[]','妙手剸百節，劇談翻九河。',48,'全唐诗/poet.song.80000.json','["妙手剸百節，劇談翻九河。", "人皆期晚用，君更患才多。", "世路方榛棘，人豪正網羅。", "重泉無日起，天意定如何。"]'),
('fb3bdd5b-bbb1-4952-a170-f52065ff9164','夫人江氏挽詞','張擴','宋','宋诗','song-poetry','','[]','早歲親香火，心通悟宿因。',48,'全唐诗/poet.song.80000.json','["早歲親香火，心通悟宿因。", "宜家稱孝婦，擇配得名人。", "秩秩方貽則，冥冥忽返真。", "獨憑高士筆，諄復誌蒼珉。"]'),
('af1ba6d0-dbdf-4cc6-85cc-414ae89f0698','夫人周氏挽詞','張擴','宋','宋诗','song-poetry','','[]','孌彼名家女，休聲配孟光。',48,'全唐诗/poet.song.80000.json','["孌彼名家女，休聲配孟光。", "齊家先祭祀，盡禮奉姑嫜。", "未竟百年老，空流弈世芳。", "傷心埋玉處，馬鬛表深藏。"]'),
('120b6ff3-3836-4682-8cba-28746b67fce7','悼頤中朝散兄','張擴','宋','宋诗','song-poetry','','[]','韜玉無人識，佩蘭空自芳。',48,'全唐诗/poet.song.80000.json','["韜玉無人識，佩蘭空自芳。", "娛親終一世，好善被諸郎。", "夢短催駒隙，聲哀斷鴈行。", "英魂招不得，松檟護崇岡。"]'),
('eae5ee0f-ee3f-4491-8e5b-d3e36ee945bb','用文之歲暮言懷韻','張擴','宋','宋诗','song-poetry','','[]','歲事潛占雪，風光暗著梅。',48,'全唐诗/poet.song.80000.json','["歲事潛占雪，風光暗著梅。", "有書招隱去，無地避愁來。", "厮役聯裘馬，英豪困草萊。", "誰能知許事，得酒鼾如靁。"]'),
('ce1e4b1c-8e3d-46ee-a3aa-e41a63b19946','文之暇日作詩戲用其韻','張擴','宋','宋诗','song-poetry','','[]','古事費尋檢，近詩關謗傷。',48,'全唐诗/poet.song.80000.json','["古事費尋檢，近詩關謗傷。", "掉頭無好語，結舌自良方。", "風露挾秋意，簾幃生晚凉。", "傳聞市南米，漸可補饑瘡。"]'),
('464a1f89-903d-4e08-8a0c-6c3116bffdee','射亭詩','張擴','宋','宋诗','song-poetry','','[]','采鵠面危亭，鍧然中的聲。',48,'全唐诗/poet.song.80000.json','["采鵠面危亭，鍧然中的聲。", "將軍三箭勇，男子四方名。", "刁斗中原静，車書遠塞平。", "雕弓今罷賜，何日報功成。"]'),
('7be5f416-d4e3-482b-aa5b-0c2e56db0e71','賦向伯恭侍郎薌林','張擴','宋','宋诗','song-poetry','','[]','矯矯子平裔，聲名晚益高。',48,'全唐诗/poet.song.80000.json','["矯矯子平裔，聲名晚益高。", "歸休卜仙隱，題品妙宸豪。", "小徑荒松菊，空庭長艾蒿。", "閉門便午枕，餘事九牛毛。"]'),
('e4b846cf-d037-426a-97c5-f5d8c89bc708','焦復州適道於艱危中與其兄遇於三衢自云嘗有異夢神明之感叙其事屬予賦詩','張擴','宋','宋诗','song-poetry','','[]','南渡不忍說，流離簪與裾。',48,'全唐诗/poet.song.80000.json','["南渡不忍說，流離簪與裾。", "蒼黄一臂失，辛苦萬金書。", "孝友劇調護，神明關起居。", "不須春草句，好夢自蘧蘧。"]'),
('2748d6a5-cd71-46f2-abab-1cf49102db45','題荷亭詩','張擴','宋','宋诗','song-poetry','','[]','風漾綠漪連，新荷照水圓。',48,'全唐诗/poet.song.80000.json','["風漾綠漪連，新荷照水圓。", "清香來洞府，真色現神仙。", "鷺影明如雪，龜巢小似錢。", "夜凉乘月看，人在玉壺天。"]'),
('aed0dc63-e467-4e2e-be3b-765747951f33','瑞華堂秋晚','張擴','宋','宋诗','song-poetry','','[]','山石亂崔嵬，虛堂面石開。',48,'全唐诗/poet.song.80000.json','["山石亂崔嵬，虛堂面石開。", "幽香催檻菊，疏影轉庭槐。", "羽扇驚秋老，衣砧破夢回。", "坐看雲四合，奔電數聲靁。"]'),
('1d0285b0-2dfb-4478-ab94-e1722aab612d','宿温州江心寺詩','張擴','宋','宋诗','song-poetry','','[]','出城何所詣，孤嶼海雲中。',48,'全唐诗/poet.song.80000.json','["出城何所詣，孤嶼海雲中。", "寺影一拳石，潮聲四面風。", "斷煙迷過鳥，密葉墜丹楓。", "咄咄勞生夢，真成一洗空。"]'),
('0f98a0f0-5bd8-4a48-ac9b-b8da8c6506ce','次韻臨江軍向侍郎見寄','張擴','宋','宋诗','song-poetry','','[]','江頭一區宅，宴坐老揚雄。',48,'全唐诗/poet.song.80000.json','["江頭一區宅，宴坐老揚雄。", "久闊書不到，相忘心自通。", "誰令知勇退，我愧未參同。", "定自有見處，不關幡與風。"]'),
('50c0c632-1316-41a6-a20e-f11fa5b0c0bd','次韻徐端明師川清明見訪小集','張擴','宋','宋诗','song-poetry','','[]','撩人春色浩無邊，多病清羸挽不前。',64,'全唐诗/poet.song.80000.json','["撩人春色浩無邊，多病清羸挽不前。", "書舍忽陪金殿客，花時猶記漢宫烟。", "翰林劇飲賦千首，焦遂高談驚四筵。", "更著新聲定場屋，元輕白俗浪争先。"]'),
('2ba6f55a-2638-410d-97de-3f14dc2f31b5','次韻子公舍人姪紙閣用荆公韻二首  其一','張擴','宋','宋诗','song-poetry','','[]','清修是藥别無方，紙閤新糊暫著床。',64,'全唐诗/poet.song.80000.json','["清修是藥别無方，紙閤新糊暫著床。", "定自中扄元潔白，直教平地亦清涼。", "布裘衲被總相稱，暮雪曉風渾不妨。", "似要經營淡生活，忽驚鋒穎露錐嚢。"]'),
('5a20f803-77ce-477f-a91b-918705b1b89b','次韻子公舍人姪紙閣用荆公韻二首  其二','張擴','宋','宋诗','song-poetry','','[]','老楮聲名浹四方，帡幪隱陋到藜床。',64,'全唐诗/poet.song.80000.json','["老楮聲名浹四方，帡幪隱陋到藜床。", "境空生白道所集，氣煖如熏德未涼。", "眼底咄嗟貧亦辦，世間淫巧行終妨。", "只愁費盡螭頭藁，却向危時但括嚢。"]'),
('422d3fe1-2089-40c2-b597-0bb28cdca8b8','再和戲子公  其一','張擴','宋','宋诗','song-poetry','','[]','棋局畫行新觸手，帳文龜殻凈圍床。',64,'全唐诗/poet.song.80000.json','["棋局畫行新觸手，帳文龜殻凈圍床。", "閤材近取復何好，法意防貪未可涼。", "自此鉛華須痛遣，疑於縞素或相妨。", "夜闌天女來求法，君看如何是革嚢。"]'),
('568a36b3-c97a-4345-b3f2-dbda73930921','再和戲子公  其二','張擴','宋','宋诗','song-poetry','','[]','背人阿堵未中方，紙閤文書不礙床。',64,'全唐诗/poet.song.80000.json','["背人阿堵未中方，紙閤文書不礙床。", "正似複褌羞北阮，絕勝斗酒換西涼。", "來詩肯辦十分賞，去轍猶關一水妨。", "對面更看枯淡在，應無兒輩紫羅嚢。"]'),
('cc06467e-532a-42f2-8b66-425a197553a1','子公復和亦次韻  其一','張擴','宋','宋诗','song-poetry','','[]','我慚問舍未知方，君亦依然卧上床。',64,'全唐诗/poet.song.80000.json','["我慚問舍未知方，君亦依然卧上床。", "有紙遮風良不惡，無人炙手自生涼。", "應憐佛屋鐘魚近，不自官居屏障妨。", "相去九齡今幾代，風流未減笏爲囊。"]'),
('0ace9ed2-0856-44e3-a5eb-e68e4bd91865','子公復和亦次韻  其二','張擴','宋','宋诗','song-poetry','','[]','昨日規摹屋一方，今晨詩卷已填床。',64,'全唐诗/poet.song.80000.json','["昨日規摹屋一方，今晨詩卷已填床。", "安知事似蝟毛起，自覺心如水月涼。", "故紙有緣殊未了，紅塵無路略相妨。", "客來煖熱浪自喜，斷却來章真智囊。"]'),
('ef81a7a0-4cbe-4b87-9502-6f2687c44194','聞伯寓被召','張擴','宋','宋诗','song-poetry','','[]','朝廷下詔費捜尋，夢想人豪置赤心。',64,'全唐诗/poet.song.80000.json','["朝廷下詔費捜尋，夢想人豪置赤心。", "讜論故應遺藁在，片言可却四裔侵。", "不應巖野調羮手，猶作田廬抱膝吟。", "自古忠臣由孝子，海隅傾耳聽車音。"]'),
('8561de98-d388-43ae-8c52-01a9a9dd904a','送李去病駕部成都府路轉運判官','張擴','宋','宋诗','song-poetry','','[]','昔年鴈塔看先登，我亦行間託姓名。',64,'全唐诗/poet.song.80000.json','["昔年鴈塔看先登，我亦行間託姓名。", "半世紛紜驚似夢，一官潦倒信平生。", "含香暫借郎闈寵，仗節俄分晝錦榮。", "見說餽糧如火急，揚鞭馬上試經營。"]'),
('2b1c88a3-4f07-416d-ac40-9212cfbf630f','送楊元老屯田潼川等路轉運判官','張擴','宋','宋诗','song-poetry','','[]','醬瓿遺文過五經，有孫千載振彫零。',64,'全唐诗/poet.song.80000.json','["醬瓿遺文過五經，有孫千載振彫零。", "寧聞淡墨魁春榜，會看中臺應列星。", "日下忽頒天語好，眼中先著蜀山青。", "歸塗更挾兩詩客，舐筆磨鉛那得停。"]'),
('2b4cfb3d-b9f1-44df-ab52-8609e77db230','景蕃暫如無錫不暇相尋於雲間詩來問訊甚殷勤會予續至江上遂及邂逅走筆奉呈','張擴','宋','宋诗','song-poetry','','[]','故人行李劇匆匆，猶向重湖遣信通。',64,'全唐诗/poet.song.80000.json','["故人行李劇匆匆，猶向重湖遣信通。", "七字論懷如對面，片帆先我渡垂虹。", "家田收秫連雲外，野蟹供螯入手中。", "猶及訪君江上去，夜窗燈火耿秋風。"]'),
('393995cc-e371-4102-a325-83d954387755','别後一日予獨遊惠山寺酌泉烹茶而去時景蕃補葺舊隱將自德興奉親而歸以詩追寄之','張擴','宋','宋诗','song-poetry','','[]','缾罌絡繹送醍醐，總是僧家飲啜餘。',64,'全唐诗/poet.song.80000.json','["缾罌絡繹送醍醐，總是僧家飲啜餘。", "向上誰高康谷品，流傳恐誤古人書。", "暫來刮眼驚尤物，深羨誅茅葺舊居。", "却恐文饒漸多事，他年乘傳定何如。"]'),
('257dd0af-248a-4a3f-9a52-d32ea877ded4','寄顧景蕃','張擴','宋','宋诗','song-poetry','','[]','别時猶記鼻辛酸，升合妨人未得還。',64,'全唐诗/poet.song.80000.json','["别時猶記鼻辛酸，升合妨人未得還。", "衲被生春經歲換，羽書奔電痛時艱。", "聞君尚富珠千斛，許我時窺豹一斑。", "莫厭僑居坐窮僻，絕勝戎馬閙郷關。"]'),
('b8cd1947-a114-4b7e-bbb4-0dbee1b754e8','顧景蕃以詩乞西漢書於子公子公以奏議唐鑑遺之戲次其韻','張擴','宋','宋诗','song-poetry','','[]','腹中圖史自紛綸，況有新文似過秦。',64,'全唐诗/poet.song.80000.json','["腹中圖史自紛綸，況有新文似過秦。", "猶訪汲書真好事，謬憐野鶩定癡人。", "補亡疑是君過計，就讀未妨吾卜鄰。", "他日兩家俱外府，斷編遺簡得終身。"]'),
('d614ffd0-11d9-49e3-b3a0-133908af55b5','次韻顧子美陪方仲兄遊允仲花園後篇簡允仲  其一','張擴','宋','宋诗','song-poetry','','[]','君看樹頭桃李開，化工渾在百花栽。',64,'全唐诗/poet.song.80000.json','["君看樹頭桃李開，化工渾在百花栽。", "日遲未覺堂堂去，路穩何妨得得來。", "定是撥忙聊慰眼，仍須痛飲莫論盃。", "明朝風雨便狼藉，孤負客愁腸九回。"]'),
('d0db79f5-b355-4c50-9780-4972f85e9812','次韻顧子美陪方仲兄遊允仲花園後篇簡允仲  其二','張擴','宋','宋诗','song-poetry','','[]','怪底主人襟抱開，小園千本定深栽。',64,'全唐诗/poet.song.80000.json','["怪底主人襟抱開，小園千本定深栽。", "不須羯鼓催花發，却要提壺喚酒來。", "可但撥忙聊慰眼，會應痛飲莫論盃。", "詩人有戒君知否，漸老逢春能幾回。"]'),
('cc21db7e-e3c6-45b9-9379-85c8a5a27528','過澱山湖','張擴','宋','宋诗','song-poetry','','[]','昨日過湖風打頭，葦蒲深處泊官舟。',64,'全唐诗/poet.song.80000.json','["昨日過湖風打頭，葦蒲深處泊官舟。", "近人烏鳥語聲碎，瀕海風烟日夜浮。", "午飯腥鹹半鮭菜，客床顛倒一皮裘。", "平生浪說在家好，晚向波濤未肯休。"]'),
('b58783b0-85c3-4424-8bfd-c80553711261','次韻汝陰姜丞見示','張擴','宋','宋诗','song-poetry','','[]','場屋聲名二十年，老猶學易誦韋編。',64,'全唐诗/poet.song.80000.json','["場屋聲名二十年，老猶學易誦韋編。", "作官聊復下簿尉，得酒或時中聖賢。", "每愧青衫同拜起，間從廣坐得周旋。", "來詩强欲相推挽，短綆無堪浪汲泉。"]'),
('260a0a1c-c245-4231-9d8c-c14de24086be','留别汪彦章符寶','張擴','宋','宋诗','song-poetry','','[]','蚤歲相親翰墨場，不堪遲暮屢參商。',64,'全唐诗/poet.song.80000.json','["蚤歲相親翰墨場，不堪遲暮屢參商。", "無錢可辦一日醉，有目漫同千里光。", "聞道新詩多格律，寧從尊酒細斟量。", "江南舊隱鄰雞犬，何日青燈更對床。"]'),
('a43a4087-1ff0-4626-95b2-e732c1d7f01f','聽宣麻','張擴','宋','宋诗','song-poetry','','[]','十年中國暗征塵，終挽天河凈楚氛。',64,'全唐诗/poet.song.80000.json','["十年中國暗征塵，終挽天河凈楚氛。", "謾說星辰猶孛彗，不妨豪傑會風雲。", "江頭露布傳俘馘，殿下絲綸看策勲。", "從此削平真細事，只憂無地錄將軍。"]'),
('75f354bc-bfe1-4b5a-9320-58f594fec9ab','得海陵掾吕居仁書','張擴','宋','宋诗','song-poetry','','[]','故人温飽竟何如，忽寄郵筒滿紙書。',64,'全唐诗/poet.song.80000.json','["故人温飽竟何如，忽寄郵筒滿紙書。", "頗愧中年猶吏隱，相望千里未情疏。", "官曹清簡庭無訟，淮海豐穰食有魚。", "見說參禪新了了，幾時爲我痛爬梳。"]'),
('f33a5643-b7e2-4de6-96c1-c9ceb548bcfc','聞余元隆被命白衣校正逸書','張擴','宋','宋诗','song-poetry','','[]','余郎風姿舊臞儒，酒錢不足詩有餘。',64,'全唐诗/poet.song.80000.json','["余郎風姿舊臞儒，酒錢不足詩有餘。", "江湖垂老漫居士，館殿忽詔行秘書。", "從來摸索識沈謝，安用科舉輕嚴徐。", "須君更平脱鞾氣，步穩即到承明廬。"]'),
('503e083d-52d0-4bd9-ad08-fc5976dc3421','招王大初教授飯','張擴','宋','宋诗','song-poetry','','[]','聞名早愧昧平生，遲暮相看眼更明。',64,'全唐诗/poet.song.80000.json','["聞名早愧昧平生，遲暮相看眼更明。", "滿室氛埃不關意，百年文字要尋盟。", "關河晚闕平安報，風露日催摇落聲。", "樽酒從予會傾倒，莫同兒輩但平平。"]'),
('d17176b5-03ad-4885-a4cc-eb4e756f4120','暮春舟中懷顧景蕃諸友會心堂折花幾至紛紜因以問之','張擴','宋','宋诗','song-poetry','','[]','流光急急卷春歸，寬我都無十日期。',64,'全唐诗/poet.song.80000.json','["流光急急卷春歸，寬我都無十日期。", "短楫輕舟餘客夢，斜風横雨半花時。", "坐懷同社二三子，賸有一番酬唱詩。", "誰向海棠花下去，不妨重看挽殘枝。"]'),
('3ecc025f-f593-43cf-bd5e-15f77c013dee','曹南官舍懷諸兄弟','張擴','宋','宋诗','song-poetry','','[]','舍南舍北百花春，不奈揚雄四壁貧。',64,'全唐诗/poet.song.80000.json','["舍南舍北百花春，不奈揚雄四壁貧。", "與世周旋寧作我，罷官休去亦由人。", "有家那辦錄傖鬼，無用猶堪託社神。", "凖擬他年風雨夜，論詩酌酒話酸辛。"]'),
('63069fae-2f0b-4455-8fae-fa121964cc56','次韻晁待制喜富季申遷校書','張擴','宋','宋诗','song-poetry','','[]','鄭公勲閥似汾陽，人物君看同舍郎。',64,'全唐诗/poet.song.80000.json','["鄭公勲閥似汾陽，人物君看同舍郎。", "坐廢衣冠誰論薦，中興文字亦生光。", "未妨俗子輕薰沐，元得詩翁妙主張。", "聞說平戎遺策在，何時目擊陣堂堂。"]'),
('478ee83a-a930-422e-a735-af4e0633c477','華亭秋日','張擴','宋','宋诗','song-poetry','','[]','陰雲薄薄漏秋輝，曉露含光濕翠微。',64,'全唐诗/poet.song.80000.json','["陰雲薄薄漏秋輝，曉露含光濕翠微。", "旁舍擊牛嘗社酒，荒城搗練給征衣。", "凈如掃跡蚊無幾，多不論錢蟹正肥。", "定是水鄉差可樂，不應潦倒未成歸。"]'),
('8dcc16d9-8d9f-4166-8934-06cfce45e088','吳江舟中','張擴','宋','宋诗','song-poetry','','[]','數峰雨後蔚藍青，一水秋來鏡面平。',64,'全唐诗/poet.song.80000.json','["數峰雨後蔚藍青，一水秋來鏡面平。", "大舶魚鹽通遠近，居人菱芡足經營。", "雲頭闕月爲誰好，蘋末涼風時自生。", "老矣宦游無少味，欲尋張翰問蓴羮。"]'),
('21d98486-99ea-48dd-9c5c-476eded02b41','書鴈蕩山靈巖寺壁','張擴','宋','宋诗','song-poetry','','[]','畫裏兒時見一斑，朅來老病倦躋攀。',64,'全唐诗/poet.song.80000.json','["畫裏兒時見一斑，朅來老病倦躋攀。", "諸峰拔地上雲雨，萬壑出泉鳴佩環。", "圖牒未聞從古有，鬼神定自破天慳。", "道人笑我殺風景，不辦淹留半日閒。"]'),
('57439540-59c3-425b-b27d-4234f0f856c9','次韻徐師川謝送温柑','張擴','宋','宋诗','song-poetry','','[]','剥啄誰人晝款扉，開緘詞翰見精微。',64,'全唐诗/poet.song.80000.json','["剥啄誰人晝款扉，開緘詞翰見精微。", "不應更覓二王帖，但要親傳六祖衣。", "陋我分柑慳百顆，煩君託意贈當歸。", "吏曹政急簿書縛，忽奉新詩得解圍。"]'),
('8989b500-a444-4102-ad9f-28e4da6fc72e','次韻吕居仁主簿過韓存中侍郎所居','張擴','宋','宋诗','song-poetry','','[]','文章典雅似班固，人物風流如謝安。',64,'全唐诗/poet.song.80000.json','["文章典雅似班固，人物風流如謝安。", "老去謾餘公論在，退休渾覺壯心闌。", "松窗有月和書照，雲屋無氊禦客寒。", "冷淡且尋詩作活，要看雷電敕仙官。"]'),
('ebd2c19f-dd5c-453c-a870-885cb9b55ad8','和李元叔正字書懷崇字韻奉還所借詩卷','張擴','宋','宋诗','song-poetry','','[]','杜陵句法今誰到，君自門墻數仞崇。',64,'全唐诗/poet.song.80000.json','["杜陵句法今誰到，君自門墻數仞崇。", "未許前人得高處，間於五字見新功。", "淹留書館殘燈火，孤負淮山舊桂叢。", "眼看封侯談笑覓，絕勝潦倒坐詩窮。"]'),
('bcabc126-2f57-440b-a601-042a666e4e48','歸來軒二首  其一','張擴','宋','宋诗','song-poetry','','[]','當年鞍馬踐文場，客舍虀鹽話故鄉。',64,'全唐诗/poet.song.80000.json','["當年鞍馬踐文場，客舍虀鹽話故鄉。", "不謂休休歸亦早，未應栩栩夢猶狂。", "輞川花木歲時好，蓮社交遊氣味長。", "便合從君就閒去，藜羮麥飯自充腸。"]'),
('dc19bde6-ddd7-4d12-bdbd-13c761bbee9b','歸來軒二首  其二','張擴','宋','宋诗','song-poetry','','[]','不愛虚名式擅場，却收餘燄入寒鄉。',64,'全唐诗/poet.song.80000.json','["不愛虚名式擅場，却收餘燄入寒鄉。", "於魚得計絕人事，翻手爲雲小子狂。", "閲世已除三宿戀，論詩兼倍百家長。", "西風舉扇誰多事，君自無塵點肺腸。"]'),
('0d1a179c-f1c9-4733-a828-1e6fd9f0165d','次韻括蒼太守黄侍御種竹  其一','張擴','宋','宋诗','song-poetry','','[]','先生鐵面石爲肝，不著繁華眼底看。',64,'全唐诗/poet.song.80000.json','["先生鐵面石爲肝，不著繁華眼底看。", "近學仙翁誇種玉，未多楚客解紉蘭。", "穿窗月影蛟蛇亂，掠枕秋聲風雨寒。", "誰信孤根會埋沒，賦詩新有老方干。"]'),
('1fa24230-4c0e-438d-b997-2872847e6e57','次韻括蒼太守黄侍御種竹  其二','張擴','宋','宋诗','song-poetry','','[]','世上風花暫鬬妍，轉頭誰作一錢看。',64,'全唐诗/poet.song.80000.json','["世上風花暫鬬妍，轉頭誰作一錢看。", "此君抱節真如玉，有客同心臭似蘭。", "密葉自憐秋日薄，孫枝已挾曉霜寒。", "蔓柔草惡宜誅屏，恐向班行犯比干。"]'),
('7a9f072e-d243-46a7-ac84-3fb161d57534','送喻迪孺郎中知遂寧府','張擴','宋','宋诗','song-poetry','','[]','平時場屋漫聲名，晚下瞿唐信此生。',64,'全唐诗/poet.song.80000.json','["平時場屋漫聲名，晚下瞿唐信此生。", "萬里不應頻去國，一麾聊復爲専城。", "送春杯酒侵行色，上峽家山慰客情。", "坐遣官曹頓牢落，說詩誰復似匡衡。"]'),
('9ba2ed4c-775e-47ec-802c-e4b54b2e4a2d','次韻昌時寺丞姪避暑','張擴','宋','宋诗','song-poetry','','[]','眼看平地欲流金，暫借僧園數畝陰。',64,'全唐诗/poet.song.80000.json','["眼看平地欲流金，暫借僧園數畝陰。", "束带市朝誰刺促，閉門松檜自幽深。", "客來棋局時招隱，飯罷茶甌快洗心。", "便静乞閒吾有味，墻東詩老許同襟。"]'),
('e232831c-c566-44ec-982a-01c6e11be626','紹興已未七月六日被旨禱雨風水洞七日清晨詣祠下是晚大雨通夕留宿慈嚴寺中八日始還城','張擴','宋','宋诗','song-poetry','','[]','晚謁叢祠意已通，妙香來自禁城中。',64,'全唐诗/poet.song.80000.json','["晚謁叢祠意已通，妙香來自禁城中。", "老龍聊辦一泓費，闔境自歌終歲功。", "暑溽不應留枕簟，秋聲忽已到梧桐。", "明朝上馬五十里，更乞靈君吹面風。"]'),
('96b57714-a2f2-4c11-b537-3bd4f179cf99','次韻程伯寓司業見寄道舊','張擴','宋','宋诗','song-poetry','','[]','雞黍新盟竟未尋，杯盤舊話更關心。',64,'全唐诗/poet.song.80000.json','["雞黍新盟竟未尋，杯盤舊話更關心。", "時危閒喜尺書到，老去惟憂多病侵。", "閭巷小兒俱富貴，山林處士獨呻吟。", "君今雅意在流水，誰是子期知此音。"]'),
('8e227e7b-e943-4748-b3ed-e2c47a504b4e','嘲鵲','張擴','宋','宋诗','song-poetry','','[]','抵玉誰家解汝嗔，定應饒舌誑癡人。',64,'全唐诗/poet.song.80000.json','["抵玉誰家解汝嗔，定應饒舌誑癡人。", "平生作室自拘忌，晚歲填河良苦辛。", "風急未妨翎翮健，日長無奈語音頻。", "君看屋上烏元好，何用開門延竇申。"]'),
('45d5230e-ae61-4022-888e-411a16dad756','悼余彦敷府判','張擴','宋','宋诗','song-poetry','','[]','圭璧温然席上珍，廣朝通籍照簪紳。',64,'全唐诗/poet.song.80000.json','["圭璧温然席上珍，廣朝通籍照簪紳。", "論文巳許詩無敵，試吏還驚筆有神。", "少日功名聊措意，暮年州縣漫勞人。", "武林舊話終成夢，旅櫬空歸淚滿巾。"]'),
('a8e4c025-9f1a-487c-b2d7-ca72cd8e62c8','悼叔玠兄','張擴','宋','宋诗','song-poetry','','[]','獨抱荆珍價莫酬，眼看閭巷覓封侯。',64,'全唐诗/poet.song.80000.json','["獨抱荆珍價莫酬，眼看閭巷覓封侯。", "時開黄卷都忘老，晚著青衫已倦遊。", "不說向空書咄咄，但聞作記戒休休。", "故應手澤未埋沒，合付六丁雷電收。"]'),
('cfac3b34-216d-4d49-b905-883c62048920','悼余元夫朝請','張擴','宋','宋诗','song-poetry','','[]','廣席談經舊長雄，豁然襟韻古人風。',64,'全唐诗/poet.song.80000.json','["廣席談經舊長雄，豁然襟韻古人風。", "弓刀晚試百僚底，部曲默馴三尺中。", "幕府未聞收劇孟，佳城俄已愴滕公。", "不堪離亂死英傑，所在紛紜真發蒙。"]'),
('92b79997-4087-4b52-91cb-382f80d63131','悼子平姪','張擴','宋','宋诗','song-poetry','','[]','白帢寧從細柳君，欲提尺箠凈烟塵。',64,'全唐诗/poet.song.80000.json','["白帢寧從細柳君，欲提尺箠凈烟塵。", "聲名便自當敵國，露布復誰推傔人。", "夜半憂時長抱膝，生平急義幾傾囷。", "追傷萬事蓋棺了，木笏青衫負此身。"]'),
('2b77f25e-45e6-43c9-b3a4-804b751e4f71','次韻秦秘監山中觀梅二首  其一','張擴','宋','宋诗','song-poetry','','[]','天上新驂寶輅回，看花仍趁雪英開。',64,'全唐诗/poet.song.80000.json','["天上新驂寶輅回，看花仍趁雪英開。", "折歸忍負金蕉葉，笑插誰臨玉鏡臺。", "女堞未須翻角調，錦囊先喜助詩材。", "少蓬自是調羮手，葉底應尋舊雨來。"]'),
('622dadb3-4c32-44a0-9d6d-f3b9253fbf86','次韻秦秘監山中觀梅二首  其二','張擴','宋','宋诗','song-poetry','','[]','莫遣寒林一片飛，要看縞練粲仙衣。',64,'全唐诗/poet.song.80000.json','["莫遣寒林一片飛，要看縞練粲仙衣。", "故煩詩伯來傳令，爲勒風師少霽威。", "水部五言誰舉似，孤山一徑久湮微。", "總輸桃杏快塗抹，占定春光不放歸。"]'),
('256ad694-c923-4e6c-a807-164eeb3441a2','次韻春雪','張擴','宋','宋诗','song-poetry','','[]','春雪欺人轉更豪，力如彊弩射吳潮。',64,'全唐诗/poet.song.80000.json','["春雪欺人轉更豪，力如彊弩射吳潮。", "郢人有恨翻新曲，蜀客無襦憶舊謡。", "戶外莫誇盈尺好，沙頭已作淺痕消。", "詩成忍凍話年少，愁殺衰翁不自聊。"]'),
('be02d29b-5cb8-4238-abf8-a8c9f83bd283','送賀子忱吏部福建漕','張擴','宋','宋诗','song-poetry','','[]','矯矯中年勇退身，尋盟省戶定緣貧。',64,'全唐诗/poet.song.80000.json','["矯矯中年勇退身，尋盟省戶定緣貧。", "風流未用老三徑，談笑猶堪漕七閩。", "丹荔壓枝收白曬，乳芽登焙薦青春。", "不應例作粗官看，下語須防筆有神。"]'),
('aad538bf-595b-4199-b3f5-fa1ec353cdc1','送許子禮吏部湖南漕','張擴','宋','宋诗','song-poetry','','[]','家傳康濟妙才猷，祗合懷鉛近冕旒。',64,'全唐诗/poet.song.80000.json','["家傳康濟妙才猷，祗合懷鉛近冕旒。", "漫有姓名連省戶，不妨旌節案南州。", "兵儲自古難爲策，民瘼於今豈待求。", "小試書生肥國手，未多地上見錢流。"]'),
('b445461f-cec6-4f95-b0b8-b8d22771c0d2','欲出京寄稚子','張擴','宋','宋诗','song-poetry','','[]','去時短袖怯風寒，春以爲期秋未還。',64,'全唐诗/poet.song.80000.json','["去時短袖怯風寒，春以爲期秋未還。", "苦語經年渾不記，窮愁到處漫相關。", "路從驛底一雙堠，家在江南第一山。", "人事不應頻錯迕，速尋樽酒爲開顔。"]'),
('3522aa43-8339-45cb-b89d-e42021fbecd4','寄題虎丘宜上人枝巢軒詩','張擴','宋','宋诗','song-poetry','','[]','久聞戒凈若冰淵，壞衲團蒲不記年。',64,'全唐诗/poet.song.80000.json','["久聞戒凈若冰淵，壞衲團蒲不記年。", "身外一枝聊爾耳，眼中三界自超然。", "可藏妙喜化城國，何異壺公謫處天。", "相見繞床獅子座，未妨居士病談禪。"]'),
('7c34d583-b590-4723-b66e-d7069122a06c','寄題黟縣舒先生十柳軒詩二首  其一','張擴','宋','宋诗','song-poetry','','[]','當年宫殿記風流，濯濯青春破客愁。',64,'全唐诗/poet.song.80000.json','["當年宫殿記風流，濯濯青春破客愁。", "晚覺世間全少味，自從柳下覓歸休。", "嵇康嗜鍜太多事，陶令醉眠終自由。", "想見夕陽風輭處，亂蟬無數咽新秋。"]'),
('1d0926f1-2bf3-4b94-85ef-ec9ffb78f5b9','寄題黟縣舒先生十柳軒詩二首  其二','張擴','宋','宋诗','song-poetry','','[]','十柳五柳復何爲，今人古人心要知。',64,'全唐诗/poet.song.80000.json','["十柳五柳復何爲，今人古人心要知。", "百年實錄先生傳，五字格言彭澤詩。", "近聞收秫頗狼藉，誰與結社相娛嬉。", "我亦江湖漫浪者，尚堪束带向羣兒。"]'),
('78e2c5f5-7724-4b2b-a5b9-cef54f784b74','次韻朱新仲學士元日會飲館中同舍家','張擴','宋','宋诗','song-poetry','','[]','華堂小集壽佳辰，好雪縈風上舞茵。',64,'全唐诗/poet.song.80000.json','["華堂小集壽佳辰，好雪縈風上舞茵。", "珠琲相酬元富貴，綺羅不設自清真。", "近從朱墨生官府，便覺方壺隔世塵。", "縱許一斑窺妙句，亦應寡和愧陽春。"]'),
('da8c23eb-be7e-444a-a83b-c3b57e5dc0a0','寄李天祚屯田','張擴','宋','宋诗','song-poetry','','[]','巷北巷南車殷靁，憐渠襟抱向誰開。',64,'全唐诗/poet.song.80000.json','["巷北巷南車殷靁，憐渠襟抱向誰開。", "苦無好夢絕江去，合有短書逢鴈回。", "省戶淹留驚白髪，朝廷緩急要真材。", "他年炙手會不免，早賦柴桑歸去來。"]'),
('993b5648-fcbb-4011-a708-1c37408c3efa','春深遣興','張擴','宋','宋诗','song-poetry','','[]','深院小亭花藥香，春來無處避風光。',64,'全唐诗/poet.song.80000.json','["深院小亭花藥香，春來無處避風光。", "畦蔬自種兩席許，溪水忽高三尺彊。", "冷淡不妨詩作活，狂歌時以酒爲鄉。", "故人南北今誰在，紙尾寒暄未可忘。"]'),
('ef342877-d11f-4e19-a8a3-039cece69da7','次韻譚少卿勝仲懷歸','張擴','宋','宋诗','song-poetry','','[]','底用封侯老據鞍，如君家世自儒冠。',64,'全唐诗/poet.song.80000.json','["底用封侯老據鞍，如君家世自儒冠。", "初無嫵媚追時好，但有孤高到歲寒。", "夢入向來招隱處，詩成有味付誰看。", "援毫欲和愧遲澀，八節推舟窘上灘。"]'),
('13582dc1-952b-43dc-893b-19825736fa58','寄大年耆年二姪','張擴','宋','宋诗','song-poetry','','[]','漫天白雨欲催詩，恰似連床細柳時。',64,'全唐诗/poet.song.80000.json','["漫天白雨欲催詩，恰似連床細柳時。", "近悔論文多敗績，不關避謗要尋醫。", "才如伯仲世無敵，學有本原人未知。", "例著布袍隨舉子，滿聽危論上丹墀。"]'),
('e2a1f356-01f4-4762-95fd-5af7916ae2a4','文之雪霰落硯詩戱用其韻','張擴','宋','宋诗','song-poetry','','[]','玄璧無塵中作泓，偏宜凈几集飛霙。',64,'全唐诗/poet.song.80000.json','["玄璧無塵中作泓，偏宜凈几集飛霙。", "柳花可染巳無跡，鵠羽不黔如幻成。", "小試桑根猶耿介，結爲冰面更晶明。", "癡兒呵凍爲渠賦，費盡壺中墨客卿。"]'),
('7aec8c15-4760-4ea3-9208-cacc67f17081','樓西樞出撫關陜鄭亨仲以秘監充參謀館中咸分韻爲餞得綸字','張擴','宋','宋诗','song-poetry','','[]','關河宣慰尚儒臣，賓客仍收席上珍。',64,'全唐诗/poet.song.80000.json','["關河宣慰尚儒臣，賓客仍收席上珍。", "便有威名如敵國，更分籌畫累同人。", "連城簪笏官寮舊，夾道壺簞詔墨新。", "歸日毛錐應好在，却從丹禁演絲綸。"]'),
('717808f6-cd68-4e84-a898-d384f1c796c4','謁廣濟軍向工曹仲吉','張擴','宋','宋诗','song-poetry','','[]','水曹筆力若新硎，冷屋無人詩自鳴。',64,'全唐诗/poet.song.80000.json','["水曹筆力若新硎，冷屋無人詩自鳴。", "取别未容長草草，相看豈合但平平。", "百年王謝見人物，少日機雲真弟兄。", "且向陶丘問消息，他時湖海莫寒盟。"]'),
('3217318c-4f86-428a-919b-1799bd9203fc','留别梅和勝侍郎','張擴','宋','宋诗','song-poetry','','[]','平日寄聲天一方，那知歲晚屢登堂。',64,'全唐诗/poet.song.80000.json','["平日寄聲天一方，那知歲晚屢登堂。", "百年已負幾罇酒，一夜各添新鬢霜。", "塵裏著身空歲月，筆間應俗漫文章。", "門庭未覺千里遠，會有書來細作行。"]'),
('591ec62f-c9a8-43bb-8346-a173664085e5','次韻張無隅送烏髭方與人并寄以詩','張擴','宋','宋诗','song-poetry','','[]','肘後仙方舊著名，知君學道得長生。',64,'全唐诗/poet.song.80000.json','["肘後仙方舊著名，知君學道得長生。", "燒丹自秘砂銀訣，染白聊分草木英。", "兩鬢尚須并檢校，二毛應覺頓神明。", "他年莫向玄齡問，李緯猶堪老作卿。"]'),
('212026e5-634f-4c67-a8a7-45bb8e9c7f95','送彦材姪還鄉','張擴','宋','宋诗','song-poetry','','[]','朔風吹雪冷侵衣，過我山城歲暮時。',64,'全唐诗/poet.song.80000.json','["朔風吹雪冷侵衣，過我山城歲暮時。", "每歎吏曹長縮手，會從樽酒得伸眉。", "笑談亹亹未更僕，行李匆匆還語離。", "莫厭吾家窮事業，囊中好在幾毛錐。"]'),
('0537f253-16cd-4e10-80f2-a955ee143bc8','簷冰','張擴','宋','宋诗','song-poetry','','[]','歷歷排簷定琢成，小庵睡起眼初明。',64,'全唐诗/poet.song.80000.json','["歷歷排簷定琢成，小庵睡起眼初明。", "葯翁收乳得鵝管，天女墜釵懸水晶。", "脱手不供時把玩，怯風終作淚縱横。", "老頑不辦劉义句，聽盡寒堦斷續聲。"]'),
('5cc0c4d0-8754-43c3-80a5-076c91b79b9d','筍','張擴','宋','宋诗','song-poetry','','[]','披籜游龍破地皮，浪將頭角長孫枝。',64,'全唐诗/poet.song.80000.json','["披籜游龍破地皮，浪將頭角長孫枝。", "渾疑鐵騎旌戈曉，如趁玉班宫殿時。", "羊酪蓴羮真謾語，河魨荻筍彊相宜。", "無人會得叢林趣，盡屬此君惟我知。"]'),
('e1f4f11f-be14-4788-ae7b-ab216e2adb24','再次筍韻','張擴','宋','宋诗','song-poetry','','[]','羽獵誰尋狐貉皮，空林失箭已千枝。',64,'全唐诗/poet.song.80000.json','["羽獵誰尋狐貉皮，空林失箭已千枝。", "遥聆春晚斧斤響，不到歲寒霜雪時。", "喜有齋熏延上座，愧無椽管付師宜。", "平生漫作漢宫妾，十指許長君未知。"]'),
('582decae-f9b2-4ba6-843a-5e02b24af9af','次韻子温偶書','張擴','宋','宋诗','song-poetry','','[]','門外溪光倒碧山，憐君終不厭身閒。',64,'全唐诗/poet.song.80000.json','["門外溪光倒碧山，憐君終不厭身閒。", "直須掃跡利名裏，却要策勲文字間。", "洗耳時傾高士論，轉喉莫犯貴人顔。", "百年總是一抔土，且乞餘生隱市關。"]'),
('643f0226-97c3-48df-a45c-759f7ae9795c','晝寢','張擴','宋','宋诗','song-poetry','','[]','翠簟輕紈腹果然，午風吹夢入湖邊。',64,'全唐诗/poet.song.80000.json','["翠簟輕紈腹果然，午風吹夢入湖邊。", "竹奴不語専新寵，水厄無功罷宿烟。", "却要降魔時讀易，未須盤膝彊磨甎。", "誰人妙解老韶訣，心印傳來不記年。"]'),
('e2e6b263-b7e9-413b-9826-c0512430d4ae','天柱峰','張擴','宋','宋诗','song-poetry','','[]','神人斷鼇立極處，一柱至今餘尺度。',32,'全唐诗/poet.song.80000.json','["神人斷鼇立極處，一柱至今餘尺度。", "摩挲歲月不可窮，會見女媧曾手補。"]'),
('501f31cb-8db5-468a-b22f-6791c88cf802','展旗峰','張擴','宋','宋诗','song-poetry','','[]','何年隕石化蚩尤，彷彿光芒動九斿。',32,'全唐诗/poet.song.80000.json','["何年隕石化蚩尤，彷彿光芒動九斿。", "厭亂無人識天意，濃雲若霧沒高秋。"]'),
('6f2aa844-bccd-4be9-ae30-31be166bd7dc','大龍湫','張擴','宋','宋诗','song-poetry','','[]','巉巖石壁倚天開，何處蒼龍噀雨來。',32,'全唐诗/poet.song.80000.json','["巉巖石壁倚天開，何處蒼龍噀雨來。", "海上秋田半焦槁，不應澗谷但空靁。"]'),
('9326e828-59e7-4861-a2c3-0336f07ed7fb','石門瀑布','張擴','宋','宋诗','song-poetry','','[]','胸中頓有兩龍湫，晚向塵寰得勝遊。',32,'全唐诗/poet.song.80000.json','["胸中頓有兩龍湫，晚向塵寰得勝遊。", "定是伏龍思遠客，賸分一派洗窮愁。"]'),
('0595b4ce-6c92-47c1-9fb8-e79a22447cd7','天聰洞','張擴','宋','宋诗','song-poetry','','[]','危梯百級面天聰，路逼青冥似可通。',32,'全唐诗/poet.song.80000.json','["危梯百級面天聰，路逼青冥似可通。", "著脚未平身已墮，神仙窗戶漫玲瓏。"]'),
('32405b91-c5eb-4e8a-b2f4-1c667c78f957','漫成','張擴','宋','宋诗','song-poetry','','[]','人聲乍寂鳥聲樂，書舍旁通僧舍幽。',32,'全唐诗/poet.song.80000.json','["人聲乍寂鳥聲樂，書舍旁通僧舍幽。", "行盡人間磽确處，吾廬自好更何求。"]'),
('3e522c21-42dc-49e9-8de1-83b308ee5bfc','暮春絕句  其一','張擴','宋','宋诗','song-poetry','','[]','飄盡杏園紅白株，祗留芍藥殿春餘。',32,'全唐诗/poet.song.80000.json','["飄盡杏園紅白株，祗留芍藥殿春餘。", "不堪風雨夜來惡，地上又多枝上疏。"]'),
('82fa2fbc-b180-43b4-a5ae-822d268df420','暮春絕句  其二','張擴','宋','宋诗','song-poetry','','[]','地上殷紅錦作衣，遊蜂百匝繞空枝。',32,'全唐诗/poet.song.80000.json','["地上殷紅錦作衣，遊蜂百匝繞空枝。", "滿園綠暗鶯聲老，正是一年春盡時。"]'),
('b5b5bef6-a395-4fd4-9a37-3158ca958034','暮春絕句  其三','張擴','宋','宋诗','song-poetry','','[]','背人春日去堂堂，無賴春風有底忙。',32,'全唐诗/poet.song.80000.json','["背人春日去堂堂，無賴春風有底忙。", "便好單衣裁白紵，青天露坐試新涼。"]'),
('2c57db94-3396-4ecd-add6-1140c8928007','次韻寧徽言學士立春六絕  其一','張擴','宋','宋诗','song-poetry','','[]','仙家庭院立春朝，不記仙翁幾種桃。',32,'全唐诗/poet.song.80000.json','["仙家庭院立春朝，不記仙翁幾種桃。", "共祝風光還上苑，鈞天絲管換弓刀。"]'),
('7e8c33ad-0803-4dad-9736-278f5d58a050','次韻寧徽言學士立春六絕  其二','張擴','宋','宋诗','song-poetry','','[]','剪綵沾酥頃刻間，開花不受雪摧殘。',32,'全唐诗/poet.song.80000.json','["剪綵沾酥頃刻間，開花不受雪摧殘。", "誰人試手争春巧，定是仙娥下廣寒。"]'),
('c8c383ab-a9a3-4fd1-ac69-ba8c6c85b171','次韻寧徽言學士立春六絕  其三','張擴','宋','宋诗','song-poetry','','[]','古縣鞭牛吏謹時，老農分喜上龐眉。',32,'全唐诗/poet.song.80000.json','["古縣鞭牛吏謹時，老農分喜上龐眉。", "東皇一例扶衰朽，不獨故園桃李枝。"]'),
('d9cda436-c3d4-443d-8c8f-6b34792552d1','次韻寧徽言學士立春六絕  其四','張擴','宋','宋诗','song-poetry','','[]','青絲行菜手纖纖，琖面鵝黄照舞衫。',32,'全唐诗/poet.song.80000.json','["青絲行菜手纖纖，琖面鵝黄照舞衫。", "蕭寺館君歸未得，杜鵑應合口如緘。"]'),
('233eae8b-3475-4a7a-973a-6438e9d3874c','次韻寧徽言學士立春六絕  其五','張擴','宋','宋诗','song-poetry','','[]','麗句從君筆底翻，旁觀但合把降幡。',32,'全唐诗/poet.song.80000.json','["麗句從君筆底翻，旁觀但合把降幡。", "承明何日供春帖，字字堪回玉色温。"]'),
('ab387db3-46e6-4a1d-97d5-97577fbd9a38','次韻寧徽言學士立春六絕  其六','張擴','宋','宋诗','song-poetry','','[]','野人破衲度窮冬，枕上餘寒散曉風。',32,'全唐诗/poet.song.80000.json','["野人破衲度窮冬，枕上餘寒散曉風。", "春事苦無關我處，茶烟藥臼了龜蒙。"]'),
('dc8440e3-5f12-4cab-8723-fc7729334b24','次韻石倅喜江令禱雨有應三絕句  其一','張擴','宋','宋诗','song-poetry','','[]','忱詞新沐管城枯，夜啓天門玉鏁魚。',32,'全唐诗/poet.song.80000.json','["忱詞新沐管城枯，夜啓天門玉鏁魚。", "借得豐年三尺雨，此郎那解世間書。"]'),
('8384f4cd-1294-4eee-a2b3-d88c8e4f8f36','次韻石倅喜江令禱雨有應三絕句  其二','張擴','宋','宋诗','song-poetry','','[]','蟄龍水底未全枯，睡穩終慚點額魚。',32,'全唐诗/poet.song.80000.json','["蟄龍水底未全枯，睡穩終慚點額魚。", "聊爲蒼生一伸肘，陰功何待玉函書。"]'),
('f32aa12e-a23d-45b0-9932-d16f583ddd7c','次韻石倅喜江令禱雨有應三絕句  其三','張擴','宋','宋诗','song-poetry','','[]','藜莧捜腸老欲枯，年來冷釡已生魚。',32,'全唐诗/poet.song.80000.json','["藜莧捜腸老欲枯，年來冷釡已生魚。", "三錢斗米待明日，預辦平原乞米書。"]'),
('7cc867b6-e2ca-4736-9c5f-c832e4279690','山居四首  其一','張擴','宋','宋诗','song-poetry','','[]','春泥滑滑封行路，春水溶溶沒野蔬。',32,'全唐诗/poet.song.80000.json','["春泥滑滑封行路，春水溶溶沒野蔬。", "獨坐不愁無酒飲，林間山鳥自提壺。"]'),
('eca81c00-35a4-4c8d-9cc4-64ca59bcddfc','山居四首  其二','張擴','宋','宋诗','song-poetry','','[]','温風習習送蠶老，曉日曈曈催麥黄。',32,'全唐诗/poet.song.80000.json','["温風習習送蠶老，曉日曈曈催麥黄。", "新笋已添千箇竹，綠萌初遍數畦秧。"]'),
('a6042d6c-06ca-464c-aa08-36a670a1ec20','山居四首  其三','張擴','宋','宋诗','song-poetry','','[]','山腰老檜結纓絡，石眼飛泉鳴珮璫。',32,'全唐诗/poet.song.80000.json','["山腰老檜結纓絡，石眼飛泉鳴珮璫。", "午夢悠悠誰喚覺，竹風時借枕衾涼。"]'),
('7b13952e-cff1-4eaf-a6c6-36cebbfdccad','山居四首  其四','張擴','宋','宋诗','song-poetry','','[]','誅茅結屋方丈闊，買酒澆腸升斗慳。',32,'全唐诗/poet.song.80000.json','["誅茅結屋方丈闊，買酒澆腸升斗慳。", "古寺隔林人閴寂，祗傳鐘梵到山間。"]'),
('9b4865b4-9fe0-4c08-80ce-c496aa5b062c','題枕流軒詩四首  其一','張擴','宋','宋诗','song-poetry','','[]','世間無路不榛荆，且枕清流巧避名。',32,'全唐诗/poet.song.80000.json','["世間無路不榛荆，且枕清流巧避名。", "俗客若來休舉似，恐渠笑倒斷冠纓。"]'),
('52b2d0ea-fd41-4ff3-a8dc-7b7d28269dab','題枕流軒詩四首  其二','張擴','宋','宋诗','song-poetry','','[]','誰酌貪泉計巳疏，但知辛苦立廉隅。',32,'全唐诗/poet.song.80000.json','["誰酌貪泉計巳疏，但知辛苦立廉隅。", "君今樂水自智者，未用休官乞鑑湖。"]'),
('8a60ea9a-c2a7-4ae2-b205-82f4aded0e0a','題枕流軒詩四首  其三','張擴','宋','宋诗','song-poetry','','[]','坐有談玄墨客卿，家無銅臭孔方兄。',32,'全唐诗/poet.song.81000.json','["坐有談玄墨客卿，家無銅臭孔方兄。", "夢餘更聽滄浪水，洗盡微塵見太清。"]'),
('32b1349a-cd4c-4a7d-ac50-d4ee2fd37fa1','題枕流軒詩四首  其四','張擴','宋','宋诗','song-poetry','','[]','詩老詩如冰雪味，後來和者得分甘。',32,'全唐诗/poet.song.81000.json','["詩老詩如冰雪味，後來和者得分甘。", "從今客耳亦清凈，只合高吟當劇談。"]'),
('397afe54-6691-4f82-ac51-0f37f77a05ba','舫齋','張擴','宋','宋诗','song-poetry','','[]','曾得操舟三昩功，浮家不借一帆風。',32,'全唐诗/poet.song.81000.json','["曾得操舟三昩功，浮家不借一帆風。", "鱸魚如雪酒如玉，宛在五湖春水中。"]'),
('0b3b3424-7be9-4666-9b09-27fa4dd72658','與客争棋客有所負坐人以目無解圍者客怒甚而去作詩戱之','張擴','宋','宋诗','song-poetry','','[]','不論别墅自心降，風急西南勢轉忙。',32,'全唐诗/poet.song.81000.json','["不論别墅自心降，風急西南勢轉忙。", "那辨旁呼白鸚鵡，坐看豪奪紫羅囊。"]'),
('b76a7f4d-0106-42ba-85ac-dc250c21ce16','用文之韻賦巖桂  其一','張擴','宋','宋诗','song-poetry','','[]','葉底倒懸香作團，鵝黄新染色初乾。',32,'全唐诗/poet.song.81000.json','["葉底倒懸香作團，鵝黄新染色初乾。", "晚秋風露易摇落，合屬幽人仔細看。"]'),
('54a48b91-95b3-456b-9740-8621f1e6d6df','用文之韻賦巖桂  其二','張擴','宋','宋诗','song-poetry','','[]','昔年曾賦道邊花，歲月侵尋鬢已華。',32,'全唐诗/poet.song.81000.json','["昔年曾賦道邊花，歲月侵尋鬢已華。", "衰病不堪無好語，却憑三嗅作詩誇。"]'),
('67d23291-45de-431f-9a71-3f3c4c727852','次韻允中大夫兄秉燭看海棠','張擴','宋','宋诗','song-poetry','','[]','從公燭下看花枝，直到海棠花睡時。',32,'全唐诗/poet.song.81000.json','["從公燭下看花枝，直到海棠花睡時。", "恰似玉人春枕穩，温風吹酒上凝脂。"]'),
('cca0aa80-571b-4ded-874d-3904ee76e1d7','次韻謝李簿送白牡丹','張擴','宋','宋诗','song-poetry','','[]','擎玉花頭取次妍，鞓紅從此不論錢。',32,'全唐诗/poet.song.81000.json','["擎玉花頭取次妍，鞓紅從此不論錢。", "如何未入明皇夢，已醉高吟李謫仙。"]'),
('a6b9ba84-876b-44ce-99a1-bec270f5fe6d','清香','張擴','宋','宋诗','song-poetry','','[]','北苑珍膏玉不如，清香入體世間無。',32,'全唐诗/poet.song.81000.json','["北苑珍膏玉不如，清香入體世間無。", "若將龍麝污天質，終恐薰蕕臭味殊。"]'),
('d5ffb367-33dd-4eca-8d97-fb504198f333','宣城乳梨味珍或謂性寒飬生所忌輙勸疏之予因爲作詩歎其不遇','張擴','宋','宋诗','song-poetry','','[]','開花曾作雪繽紛，花去還供飣座珍。',32,'全唐诗/poet.song.81000.json','["開花曾作雪繽紛，花去還供飣座珍。", "誰向醫門書下考，便防蒸食墮癡人。"]'),
('c1e3193d-ef74-47d9-989e-8de090c059bf','次韻子温惠雙井茶二首  其一','張擴','宋','宋诗','song-poetry','','[]','雙井昆仍分不疏，渴中曾起病相如。',32,'全唐诗/poet.song.81000.json','["雙井昆仍分不疏，渴中曾起病相如。", "策勲未有涪翁語，浪說繙經到石渠。"]'),
('eca35f09-6abf-4daa-aaa3-5aa481ba94e6','次韻子温惠雙井茶二首  其二','張擴','宋','宋诗','song-poetry','','[]','不減建溪官焙香，匏樽汲水自煎湯。',32,'全唐诗/poet.song.81000.json','["不減建溪官焙香，匏樽汲水自煎湯。", "未應重爲粗官屈，定自詩情合得嘗。"]'),
