('c6c231bf-f84e-4b42-8951-36b73946c4b9','均茶','張擴','宋','宋诗','song-poetry','','[]','密雲驚散阿香雷，坐客分嘗雪一杯。',32,'全唐诗/poet.song.81000.json','["密雲驚散阿香雷，坐客分嘗雪一杯。", "可是陳平長割肉，全勝管仲自分財。"]'),
('6f1a5cfc-0186-4def-aa2b-ba3cc57c6c04','羅茶','張擴','宋','宋诗','song-poetry','','[]','新剪鵝溪樣如月，中有瓊糜落飛屑。',32,'全唐诗/poet.song.81000.json','["新剪鵝溪樣如月，中有瓊糜落飛屑。", "何年解后紫霞仙，肘後親傳餐玉訣。"]'),
('c1de0ab0-6a9f-4573-b2a8-db789e7b1a70','碾茶','張擴','宋','宋诗','song-poetry','','[]','何意蒼龍解碎身，豈知幻相等微塵。',32,'全唐诗/poet.song.81000.json','["何意蒼龍解碎身，豈知幻相等微塵。", "莫言椎鈍如幽冀，碎璧相如竟負秦。"]'),
('a88b1468-74e4-4e70-9395-34d027fe50a4','水簾谷','張擴','宋','宋诗','song-poetry','','[]','洞中宫闕玉層層，山瀑供簾似織成。',32,'全唐诗/poet.song.81000.json','["洞中宫闕玉層層，山瀑供簾似織成。", "素額長垂雲爲掃，瓊鈎欲掛月還生。"]'),
('0236de6f-d38a-4ece-9449-e70164b46381','拂雲橋','張擴','宋','宋诗','song-poetry','','[]','誰重淇園百世孫，青青枝葉暗連雲。',32,'全唐诗/poet.song.81000.json','["誰重淇園百世孫，青青枝葉暗連雲。", "能詩外監亦清苦，結屋鄰橋配此君。"]'),
('f3567a7d-0178-4827-9a4b-b17f94c26e5f','汲泉','張擴','宋','宋诗','song-poetry','','[]','古寺僧囊見水經，未貪飲菊學長生。',32,'全唐诗/poet.song.81000.json','["古寺僧囊見水經，未貪飲菊學長生。", "櫂船且向南零汲，欲試高人識鑒精。"]'),
('c4474b89-c4bd-43cc-b704-02bb7a3a10f6','澹竹','張擴','宋','宋诗','song-poetry','','[]','誰解香根一種寒，試嘗炎帝作朝餐。',32,'全唐诗/poet.song.81000.json','["誰解香根一種寒，試嘗炎帝作朝餐。", "余生倘遇袢襟渴，一任清涼露肺肝。"]'),
('cd72f467-edd1-4b45-95b5-7e96d3057bd5','漫成三絕句  其一','張擴','宋','宋诗','song-poetry','','[]','蝸涎行窗篆詰屈，荷葉瀉露珠淋浪。',32,'全唐诗/poet.song.81000.json','["蝸涎行窗篆詰屈，荷葉瀉露珠淋浪。", "朝來危坐笏拄頰，亂雲横山如許長。"]'),
('cb7023f5-cd77-4b1e-b2d6-209ba3186c04','漫成三絕句  其二','張擴','宋','宋诗','song-poetry','','[]','銀盃厭世已仙去，春草催詩尋夢來。',32,'全唐诗/poet.song.81000.json','["銀盃厭世已仙去，春草催詩尋夢來。", "日暮砧聲擣衣急，夜涼月色挽船回。"]'),
('d34b00a7-adae-43f0-9086-189ebbadd315','漫成三絕句  其三','張擴','宋','宋诗','song-poetry','','[]','三館贅疣終罷廢，叢祠甲乙例推遷。',32,'全唐诗/poet.song.81000.json','["三館贅疣終罷廢，叢祠甲乙例推遷。", "斗升似綫當復續，冠带如讎莫近前。"]'),
('4095b5b1-28d6-4aa4-a15d-e27ad13d8cde','戲成二毫筆絕句','張擴','宋','宋诗','song-poetry','','[]','包羞曾借虎皮蒙，筆陣仍推兔作鋒。',32,'全唐诗/poet.song.81000.json','["包羞曾借虎皮蒙，筆陣仍推兔作鋒。", "未用吹毛强分别，即今同受管城封。"]'),
('be6b3088-715e-4d41-a057-1e09fc648615','送均父作江守','張擴','宋','宋诗','song-poetry','','[]','平時衮衮向諸公，投老猶推作郡公。',32,'全唐诗/poet.song.81000.json','["平時衮衮向諸公，投老猶推作郡公。", "未覺朝廷疏汲黯，極知州郡要文翁。"]'),
('839f1fd1-f125-4936-8c99-920fa892cc18','山礬花','張擴','宋','宋诗','song-poetry','','[]','秋風刻縠先黄染，七里尋香不辭遠。',65,'全唐诗/poet.song.81000.json','["秋風刻縠先黄染，七里尋香不辭遠。", "荒溪日暮下牛羊，滿路幽香誰掛眼。", "世間草木久紛然，妖紅嫚綠徒爭先。", "何當伴君過一世，細看四面秋香骨懸。"]'),
('caf2ea41-cb21-4123-845d-66d31bbe7fa8','詩一首','張擴','宋','宋诗','song-poetry','','[]','范侯渥漥種，出水已權奇。',24,'全唐诗/poet.song.81000.json','["范侯渥漥種，出水已權奇。", "失身肉馬羣，俯首枯豆萁。"]'),
('b4bf1113-7a74-408f-8e36-4a1fa6cf061e','次韻曾大卿用東坡先生韻賦蠟梅','張擴','宋','宋诗','song-poetry','','[]','湘潭有客善種花，曉移根墢來君家。',128,'全唐诗/poet.song.81000.json','["湘潭有客善種花，曉移根墢來君家。", "天公着意爲刻蠟，幻出新苞亦尤物。", "至遊老僊舊相知，少年惜花多賦詩。", "而今更挽金蕉葉，與花一處成三絕。", "夜闌寶帳攢遠山，釵頭餘蒼薰醉眠。", "明朝紅紫麾不去，妖艷妨人覓佳句。", "始信清臞自可人，此語囑誰當囑君。", "請爲百花作檀越，得意不妨時擊鉢。"]'),
('b6b1dfb3-fc1a-4370-a289-7782386d57e7','再次前韻','張擴','宋','宋诗','song-poetry','','[]','梅花聲名降百花，蠟梅後出亦世家。',131,'全唐诗/poet.song.81000.json','["梅花聲名降百花，蠟梅後出亦世家。", "真香不多護以蠟，玄官風流無長物。", "瀛洲閣老聖得知，不解藏鋒屢作詩。", "君不見大蘇曾賦黄千葉，歲晚無膠續絃絕。", "君今頗陋飯顆山，枕上冥搜那得眠。", "想應不妨花歸去，開處韓郎有新句。", "淺黄官樣苦撩人，此事從來合付君。", "我亦評花太僭越，不問吞針與囓鉢。"]'),
('f39c090b-fd78-4bd5-9cfc-788440fc4bdb','蠟梅近出或謂藥中一種不結子非梅類戲作數語爲解嘲云','張擴','宋','宋诗','song-poetry','','[]','梅花孤高少輩行，蠟梅晚出輒爭長。',99,'全唐诗/poet.song.81000.json','["梅花孤高少輩行，蠟梅晚出輒爭長。", "素粧落額豈不好，淺黄拂殺更官樣。", "檀心半迎寒日吐，暗香坐待初月上。", "春風不是苦靳惜，未辦開花大如掌。", "君不見桃李開花到結果，削梗鑽核終奇禍。", "蠟梅沾蠟如幻成，渠要調羹身後名。"]'),
('c9fc8f93-7f6b-4a0b-bc75-2499c00989df','博古堂','張擴','宋','宋诗','song-poetry','','[]','古人嗜書書不足，家貧無錢就市讀。',176,'全唐诗/poet.song.81000.json','["古人嗜書書不足，家貧無錢就市讀。", "今人收書書填屋，紅牙垂籤手未觸。", "別駕平生師古人，傳癖書淫九經簏。", "盧仝撐腸五千卷，鄴侯插架三萬軸。", "河東安世工補亡，伏日郝隆便曬腹。", "少時場屋學有餘，行輩見推行秘書。", "援毫急趁蠶食葉，袖手冷窺獺祭魚。", "十年未持紫荷橐，校讎合在天祿閣。", "投身簿領聊爾耳，飽看五車誇濩落。", "近者聞說新堂成，芭蕉急雨作秋聲。", "請君掃榻近燈火，莫歌長檠歌短檠。"]'),
('bd92f449-7865-489f-9fba-ff5ee4bdd1fb','舟行江陰道中','張擴','宋','宋诗','song-poetry','','[]','雨後侵篙一尺渾，敗蒲衰柳亂填門。',64,'全唐诗/poet.song.81000.json','["雨後侵篙一尺渾，敗蒲衰柳亂填門。", "夢聞斷角送餘嚮，起看新潮到舊痕。", "處處魚鹽成市井，家家罾笱長兒孫。", "更傳下詔寬民力，斗米三錢何足論。"]'),
('d1b4d1d8-1e5c-4573-98c1-67f09636c8a1','擬寒山寺  其一','釋懷深','宋','宋诗','song-poetry','','[]','我愛寒山子，身貧心自如。',48,'全唐诗/poet.song.81000.json','["我愛寒山子，身貧心自如。", "吟詩無韻度，燒火有工夫。", "弊垢衣慵洗，鬅鬙髪懶梳。", "相逢但長嘯，肉眼豈知渠。"]'),
('987854fa-2db9-4125-a8ba-d92d4827400d','擬寒山寺  其二','釋懷深','宋','宋诗','song-poetry','','[]','拾得詩清苦，風騷道自存。',48,'全唐诗/poet.song.81000.json','["拾得詩清苦，風騷道自存。", "看雲欹怪石，步月出松門。", "識取心中佛，休磨鏡上痕。", "時時多漏泄，塵世少知恩。"]'),
('b4137c8d-b91c-4f58-a61b-4dc979ae7f86','擬寒山寺  其三','釋懷深','宋','宋诗','song-poetry','','[]','寒山三百編，言淡而有味。',48,'全唐诗/poet.song.81000.json','["寒山三百編，言淡而有味。", "論心無隱情，警世多逆耳。", "下士聞之嗔，上土讀之喜。", "翻笑老閭丘，對面如千里。"]'),
('3dbaae3b-db4d-48fb-8328-6eef086eb88d','擬寒山寺  其四','釋懷深','宋','宋诗','song-poetry','','[]','吾詩少風騷，急欲治人病。',48,'全唐诗/poet.song.81000.json','["吾詩少風騷，急欲治人病。", "譬如萬靈丸，服者無不應。", "良藥多苦口，忠言須逆聽。", "勸君勉強服，生死殊不定。"]'),
('fbb3e7f1-3046-445d-806e-4ffcac1b54b3','擬寒山寺  其五','釋懷深','宋','宋诗','song-poetry','','[]','佛以真實口，說法無虛謬。',48,'全唐诗/poet.song.81000.json','["佛以真實口，說法無虛謬。", "人天常誦持，龍神知護祐。", "施食放生命，決定報長壽。", "過酒與僧尼，後世必無手。"]'),
('43213066-7a0e-4e53-8673-5a17658420cc','擬寒山寺  其六','釋懷深','宋','宋诗','song-poetry','','[]','在家聞見熟，意謂合食肉。',48,'全唐诗/poet.song.81000.json','["在家聞見熟，意謂合食肉。", "一蟻不忍殺，何況烹六畜。", "願君青眼開，試將黄卷讀。", "要聞知見香，熏汝腥羶腹。"]'),
('99f7a8c1-c4b3-4512-b475-21778cc200a7','擬寒山寺  其七','釋懷深','宋','宋诗','song-poetry','','[]','世上多殺生，遂有刀兵劫。',48,'全唐诗/poet.song.81000.json','["世上多殺生，遂有刀兵劫。", "負命殺汝身，欠財焚汝宅。", "離散汝妻子，曾破他巢穴。", "影響各相似，洗耳聽佛說。"]'),
('135f6125-0a00-4608-a508-4a6548048aeb','擬寒山寺  其八','釋懷深','宋','宋诗','song-poetry','','[]','偶然家計富，享用便過度。',48,'全唐诗/poet.song.81000.json','["偶然家計富，享用便過度。", "豬厭思食羊，魚厭思食兔。", "朝昏但醉飽，錐刀圖積聚。", "不畋鶉在宎，此理早須悟。"]'),
('b468d4c6-2c26-477e-a50a-21cebe6f7104','擬寒山寺  其九','釋懷深','宋','宋诗','song-poetry','','[]','何曾食萬錢，顔子飲一瓢。',48,'全唐诗/poet.song.81000.json','["何曾食萬錢，顔子飲一瓢。", "賢者心念道，愚人志在庖。", "賢愚趣不同，何啻雲泥遙。", "豢養恐非福，可信如昭昭。"]'),
('7b3e2394-921c-4efb-91e1-7db0e39128bb','擬寒山寺  其一○','釋懷深','宋','宋诗','song-poetry','','[]','世間一等人，諂事諸神鬼。',48,'全唐诗/poet.song.81000.json','["世間一等人，諂事諸神鬼。", "殺命欲邀福，皇天無此理。", "種棘不生禾，身曲影難直。", "孔子有箴誡，可信如金石。"]'),
('dc17a212-e8f3-42ce-baac-8d3f0f1d2ead','擬寒山寺  其一一','釋懷深','宋','宋诗','song-poetry','','[]','人生平爲福，有餘返爲害。',48,'全唐诗/poet.song.81000.json','["人生平爲福，有餘返爲害。", "莊周燭理明，可作貪者戒。", "富漢喜食肉，貧家多吃菜。", "吃菜比食肉，且無身後債。"]'),
('8ac160e6-ab67-45ae-99a2-5927a0452a90','擬寒山寺  其一二','釋懷深','宋','宋诗','song-poetry','','[]','漁者不能獵，獵者不能漁。',48,'全唐诗/poet.song.81000.json','["漁者不能獵，獵者不能漁。", "貴人錢爲網，水陸皆可圖。", "畜生肉嘗遍，諸佛心轉疏。", "黄泉途路滑，失脚恐難扶。"]'),
('c6180018-ac81-4d42-a5ef-62c62989eb1f','擬寒山寺  其一三','釋懷深','宋','宋诗','song-poetry','','[]','富人聚族多，外匯肉論秤買。',49,'全唐诗/poet.song.81000.json','["富人聚族多，外匯肉論秤買。", "腥羶衆口分，罪業一身載。", "既失慈悲心，恣情爲殺害。", "忽然死到來，去還畜生債。"]'),
('3131b098-6931-4f64-b781-d3a44752184e','擬寒山寺  其一四','釋懷深','宋','宋诗','song-poetry','','[]','祝壽作生日，親朋互相慶。',48,'全唐诗/poet.song.81000.json','["祝壽作生日，親朋互相慶。", "未燒一爐香，且殺百個命。", "奴僕各醉飽，歌舞亂觀聽。", "如此望長年，爲汝慚諸聖。"]'),
('7584d358-1350-48b3-9816-e63db066d546','擬寒山寺  其一五','釋懷深','宋','宋诗','song-poetry','','[]','日食半斤肉，十年百秤。',47,'全唐诗/poet.song.81000.json','["日食半斤肉，十年百秤。", "且限六十年，不知幾個命。", "肉塊高如山，業坑深似井。", "前路黑漫漫，勸君宜猛省。"]'),
('608efebf-0dc6-426e-ae58-ff58ab262778','擬寒山寺  其一六','釋懷深','宋','宋诗','song-poetry','','[]','有酒方開顔，無肉不舉筯。',48,'全唐诗/poet.song.81000.json','["有酒方開顔，無肉不舉筯。", "顛倒自戕賊，擬將血肉補。", "棄卻囊中金，反收路傍土。", "不見富貴家，未死神先去。"]'),
('1b919e99-f338-444c-8fe9-f96e406034cf','擬寒山寺  其一七','釋懷深','宋','宋诗','song-poetry','','[]','人生稍富足，著意營口腹。',49,'全唐诗/poet.song.81000.json','["人生稍富足，著意營口腹。", "買魚尋鱖魚，買肉要羊肉。", "諦觀異類身，無非親眷屬。", "一些當舉筯時，仁人宜自燭。"]'),
('e1115fc7-90ae-4d7f-9ca6-fa6a7ef8bde1','擬寒山寺  其一八','釋懷深','宋','宋诗','song-poetry','','[]','忽聞賊殺人，吞聲眉已皺。',48,'全唐诗/poet.song.81000.json','["忽聞賊殺人，吞聲眉已皺。", "不知杯中羹，甘肥自何有。", "汝身既怕死，物命亦愛壽。", "彼此莫相殺，且要無身後。"]'),
('510498a7-adab-4c31-8a4b-5020f2b2886c','擬寒山寺  其一九','釋懷深','宋','宋诗','song-poetry','','[]','忍人喜啖膾，砧几膏血灑。',48,'全唐诗/poet.song.81000.json','["忍人喜啖膾，砧几膏血灑。", "想見魚痛時，正似人遭剮。", "咀嚼稱珍奇，惻隱略無也。", "影響恐非遙，不在九泉下。"]'),
('c4dc2562-39ee-4139-b02a-290d43f6dff1','擬寒山寺  其二○','釋懷深','宋','宋诗','song-poetry','','[]','肉食未必珍，蔬食未必惡。',48,'全唐诗/poet.song.81000.json','["肉食未必珍，蔬食未必惡。", "若知妄想根，始笑舌頭錯。", "此身喻行厠，臭穢相勾絡。", "打破飯袋子，光明常陰速。"]'),
('006d9997-e24a-4b55-b2d0-5eb25c5daf9a','擬寒山寺  其二一','釋懷深','宋','宋诗','song-poetry','','[]','買肉須要肥，買魚須要活。',48,'全唐诗/poet.song.81000.json','["買肉須要肥，買魚須要活。", "買酒須要美，買田須要闊。", "買婢須要峭，買奴須要黠。", "若教買香燒，一毛不肯拔。"]'),
('fd0ea3cb-be0d-4fd4-bf0f-6231315b8ece','擬寒山寺  其二二','釋懷深','宋','宋诗','song-poetry','','[]','美食意生貪，粗食心起怒。',48,'全唐诗/poet.song.81000.json','["美食意生貪，粗食心起怒。", "喃喃嗜飽滿，殊不知來處。", "人生一飯間，貪嗔癡悉具。", "智者善思惟，莫爲餔啜悮。"]'),
('1b2c3dad-8879-44f3-af35-6593df314b6e','擬寒山寺  其二三','釋懷深','宋','宋诗','song-poetry','','[]','人生貴無求，樂善而知足。',48,'全唐诗/poet.song.81000.json','["人生貴無求，樂善而知足。", "安步以當車，晚食以當肉。", "藜羹傲鼎食，草茵欺繡褥。", "須知高明家，鬼神瞰瞞天。"]'),
('18b53345-33a2-41bf-baa0-8f8d3828312d','擬寒山寺  其二四','釋懷深','宋','宋诗','song-poetry','','[]','有個聰明漢，家中五慾全。',48,'全唐诗/poet.song.81000.json','["有個聰明漢，家中五慾全。", "喫得肉已飽，來尋僧說禪。", "心口自違背，佛祖望齊肩。", "不知有底急，平白要瞞天。"]'),
('1665ecc3-0b24-4e89-9a43-38fa4f8f7aac','擬寒山寺  其二五','釋懷深','宋','宋诗','song-poetry','','[]','冷笑富家翁，營生忙似鑽。',49,'全唐诗/poet.song.81000.json','["冷笑富家翁，營生忙似鑽。", "囷裏米生生蟲，庫中錢爛貫。", "白日把秤稱，夜間點燈算。", "形骸如傀儡，莫教麻量取。"]'),
('9cc93dff-8359-431c-97cd-306168f8b3fa','擬寒山寺  其二六','釋懷深','宋','宋诗','song-poetry','','[]','福輕似鴻毛，禍重如厚地。',48,'全唐诗/poet.song.81000.json','["福輕似鴻毛，禍重如厚地。", "避禍而修福，百中無一二。", "黄雀死彈丸，錦鱗喪香餌。", "箴誡甚分明，願君宜早計。"]'),
('1b7f3b33-28b4-4d42-82c0-aeaab457138e','擬寒山寺  其二七','釋懷深','宋','宋诗','song-poetry','','[]','大富長者家，具足諸煩惱。',48,'全唐诗/poet.song.81000.json','["大富長者家，具足諸煩惱。", "福多作業多，福少作業少。", "爭如貧道人，一裘一紙襖。", "也不怕死生，也不憂賊盜。"]'),
('e18dc337-86fc-481a-8d5b-05e841bcd8f4','擬寒山寺  其二八','釋懷深','宋','宋诗','song-poetry','','[]','我口常喫菜，你腹常飽肉。',48,'全唐诗/poet.song.81000.json','["我口常喫菜，你腹常飽肉。", "看你肥如瓠，笑我瘦如竹。", "我瘦且無冤，汝肥恐非福。", "斯言雖逆耳，請君徐徐讀。"]'),
('21a40d5e-30e1-4c15-8974-7524d5d63893','擬寒山寺  其二九','釋懷深','宋','宋诗','song-poetry','','[]','好生惡死心，人畜無差別。',48,'全唐诗/poet.song.81000.json','["好生惡死心，人畜無差別。", "刀砧纔見前，愁苦不容說。", "鶉詩頗哀鳴，牛拜彌慘切。", "嗟吁人不悟，一至身殂滅。"]'),
('404b0dce-e6a2-424b-a644-07e7bd2dc57c','擬寒山寺  其三○','釋懷深','宋','宋诗','song-poetry','','[]','刀上有少蜜，小兒爭欲舐。',48,'全唐诗/poet.song.81000.json','["刀上有少蜜，小兒爭欲舐。", "花底藏毒蛇，老翁不瞥地。", "割舌與傷身，皆從貪愛起。", "世上聰明人，往往皆如是。"]'),
('b300fd8d-64b2-4b8f-b5fa-55fbd6e9de99','擬寒山寺  其三一','釋懷深','宋','宋诗','song-poetry','','[]','有人好臧否，信口亂比況。',48,'全唐诗/poet.song.81000.json','["有人好臧否，信口亂比況。", "張三小有才，李四大無當。", "終日品藻人，不知是虛誑。", "自己一靈物，拋在糞堆上。"]'),
('d2782991-31a1-42aa-aa44-b947b52a1600','擬寒山寺  其三二','釋懷深','宋','宋诗','song-poetry','','[]','甡萍託水，流轉諸愛河。',47,'全唐诗/poet.song.81000.json','["甡萍託水，流轉諸愛河。", "鼓激無明風，出入生死波。", "一念若知歇，諸魔必倒戈。", "急須登覺岸，勸子莫蹉跎。"]'),
('65cf54d6-9350-4c9c-931f-7bc63fc5b12f','擬寒山寺  其三三','釋懷深','宋','宋诗','song-poetry','','[]','肥魚死砧機，過在貪香餌。',48,'全唐诗/poet.song.81000.json','["肥魚死砧機，過在貪香餌。", "蚌蛤不吞鈎，亦遭人所嗜。", "有身則有苦，無身則無累。", "跳出業波瀾，始到安樂地。"]'),
('b183c2d1-0454-44b9-9c6b-cf08b5b34387','擬寒山寺  其三四','釋懷深','宋','宋诗','song-poetry','','[]','人生貪愛重，所欲未嘗周。',48,'全唐诗/poet.song.81000.json','["人生貪愛重，所欲未嘗周。", "一飯飽足矣，萬鐘心未休。", "黑業埋頭做，紅裙判命求。", "鬢毛已侵雪，猶自不知羞。"]'),
('b641d026-b33c-496e-aa50-59e157911718','擬寒山寺  其三五','釋懷深','宋','宋诗','song-poetry','','[]','一朝失一朝，一瞬老一瞬。',48,'全唐诗/poet.song.81000.json','["一朝失一朝，一瞬老一瞬。", "去生漸漸遠，去死漸漸近。", "願君倒指數，光陰有幾寸。", "驀被死魔牽，前頭多悶悶。"]'),
('2c541215-1398-418d-aa11-d6a8e4737ff0','擬寒山寺  其三六','釋懷深','宋','宋诗','song-poetry','','[]','黄犬被人殺，哀號告訴人。',48,'全唐诗/poet.song.81000.json','["黄犬被人殺，哀號告訴人。", "汝不辨犬語，犬必怨汝身。", "惡根今日種，苦果異時新。", "酬償恐未已，早以戒香熏。"]'),
('bb201555-09ae-4f72-817e-5987f4d649a1','擬寒山寺  其三七','釋懷深','宋','宋诗','song-poetry','','[]','黄犬見人喜，未喚先掉尾。',48,'全唐诗/poet.song.81000.json','["黄犬見人喜，未喚先掉尾。", "長年護汝家，深夜不敢睡。", "無罪忽見烹，此理恐未是。", "細推犬有功，卻嘆人無義。"]'),
('a64d1830-ca7e-466c-a422-3f53f45a3ce5','擬寒山寺  其三八','釋懷深','宋','宋诗','song-poetry','','[]','因果耳不聞，說話多差錯。',48,'全唐诗/poet.song.81000.json','["因果耳不聞，說話多差錯。", "畜生若不殺，世上無處着。", "此語乃魔語，誘人入鼎鑊。", "不知羊與人，互換相酬酢。"]'),
('b12daf23-507d-4c2a-832d-6fac20bd5506','擬寒山寺  其三九','釋懷深','宋','宋诗','song-poetry','','[]','今生你殺羊，後世羊殺你。',48,'全唐诗/poet.song.81000.json','["今生你殺羊，後世羊殺你。", "兩角還兩角，一尾償一尾。", "假使百千劫，影響無差理。", "見你氣崢嶸，無人敢啟齒。"]'),
('6c4bb00d-8988-46c0-91db-269c852c2578','擬寒山寺  其四○','釋懷深','宋','宋诗','song-poetry','','[]','君看砧上魚，忍痛不能語。',48,'全唐诗/poet.song.81000.json','["君看砧上魚，忍痛不能語。", "身雖遭斬斫，心猶念男女。", "人既有妻兒，魚豈無子母。", "若懷這個心，如何可下筯。"]'),
('c368c791-f4ec-40b9-8bf4-bc416c95d72f','擬寒山寺  其四一','釋懷深','宋','宋诗','song-poetry','','[]','貴人惜性命，奉養欲長生。',48,'全唐诗/poet.song.81000.json','["貴人惜性命，奉養欲長生。", "空心鹿茸酒，補氣腰子羹。", "湯藥不離口，卑濕豈敢行。", "饒君善將理，難與死魔爭。"]'),
('d49baa1c-4bde-449a-bddb-6f3e1ac02dd4','擬寒山寺  其四二','釋懷深','宋','宋诗','song-poetry','','[]','人生貴無業，不貴多伎能。',48,'全唐诗/poet.song.81000.json','["人生貴無業，不貴多伎能。", "伎能人看好，業能災汝形。", "文章妙天下，氣宇吞滄溟。", "此身若一失，六趣且飄零。"]'),
('01aa12c9-9f7b-443b-aae9-2bbde1995a12','擬寒山寺  其四三','釋懷深','宋','宋诗','song-poetry','','[]','豬羊養一羣，雞鵝不知數。',48,'全唐诗/poet.song.81000.json','["豬羊養一羣，雞鵝不知數。", "準擬賓客來，旋殺供鋼筯。", "烹羊豬已驚，割雞鵝已懼。", "從頭吃至尾，不知何以故。"]'),
('fb06fea0-9ec1-4188-a6dc-dd0dd9de3110','擬寒山寺  其四四','釋懷深','宋','宋诗','song-poetry','','[]','嗟乎崔道紀，酒狂啖龍子。',48,'全唐诗/poet.song.81000.json','["嗟乎崔道紀，酒狂啖龍子。", "天網信不漏，響應若彈指。", "既失黑頭相，便作黄泉鬼。", "憐君學仲尼，曾無子產志。"]'),
('7ac60bd7-d66f-4d46-8d1c-ed3af8f49108','擬寒山寺  其四五','釋懷深','宋','宋诗','song-poetry','','[]','貧民餓欲倒，富漢米不糶。',48,'全唐诗/poet.song.81000.json','["貧民餓欲倒，富漢米不糶。", "米爛化爲蟲，猶嫌價利小。", "價利更若高，溝壑皆餓殍。", "人生萌此心，鬼神暗裏笑。"]'),
('8cfb9b24-a8cc-43f2-bb44-8cc03beea52b','擬寒山寺  其四六','釋懷深','宋','宋诗','song-poetry','','[]','世人無智慧，區區營口體。',48,'全唐诗/poet.song.81000.json','["世人無智慧，區區營口體。", "啜茶怕損脾，食蔬恐耗氣。", "二毛今半百，千金買一醉。", "算來黠是癡，嗟君開眼睡。"]'),
('edeb2b5d-2e9f-453e-858e-4bd2ea132b87','擬寒山寺  其四七','釋懷深','宋','宋诗','song-poetry','','[]','老翁急營生，貪饕不可化。',48,'全唐诗/poet.song.81000.json','["老翁急營生，貪饕不可化。", "一截已入土，百事放不下。", "經卷無暇看，數珠未曾把。", "死去見閻王，必定遭唾罵。"]'),
('0b5aa807-e064-43b0-bb17-1376e6d258b3','擬寒山寺  其四八','釋懷深','宋','宋诗','song-poetry','','[]','貧賤關前業，休嗟命未亨。',48,'全唐诗/poet.song.81000.json','["貧賤關前業，休嗟命未亨。", "田園不種樹，花果何由生。", "千沉兩條路，看你如何行。", "願君牢着脚，前面有深坑。"]'),
('2af0390c-e22f-48b9-bca9-14793cd087df','擬寒山寺  其四九','釋懷深','宋','宋诗','song-poetry','','[]','人生如春花，能得幾時好。',48,'全唐诗/poet.song.81000.json','["人生如春花，能得幾時好。", "朝吹與暮洗，朱顔變枯槁。", "花落有時生，人老不復少。", "萬事只令休，莫惹閑煩惱。"]'),
('1c6e1746-a4a0-485c-9289-65a0b57a2225','擬寒山寺  其五○','釋懷深','宋','宋诗','song-poetry','','[]','富漢欺貧漢，南鄰瞞北鄰。',48,'全唐诗/poet.song.81000.json','["富漢欺貧漢，南鄰瞞北鄰。", "斗秤有兩樣，言語無一真。", "大秤買他物，小斗糶與人。", "眼下得便宜，暗中多鬼神。"]'),
('9bd007b2-18f8-4b68-b94c-17291108eafe','擬寒山寺  其五一','釋懷深','宋','宋诗','song-poetry','','[]','人生重道德，不重多金銀。',48,'全唐诗/poet.song.81000.json','["人生重道德，不重多金銀。", "金銀潤汝屋，道德光汝身。", "金銀生盜賊，道德息貪嗔。", "尋思富漢子，不如貧道人。"]'),
('1c849ca9-d90e-4afd-97eb-9509eac5e74d','擬寒山寺  其五二','釋懷深','宋','宋诗','song-poetry','','[]','健啖衆生肉，癡心要作過。',48,'全唐诗/poet.song.81000.json','["健啖衆生肉，癡心要作過。", "白髪五六十，紅裙七八個。", "歌舞中笑談，錦繡中坐臥。", "苦海前頭深，莫教船子破。"]'),
('bf77aecb-e7d5-48cc-9d46-f0e38f481fc2','擬寒山寺  其五三','釋懷深','宋','宋诗','song-poetry','','[]','天高聽甚卑，神幽察甚厚。',48,'全唐诗/poet.song.81000.json','["天高聽甚卑，神幽察甚厚。", "埋蠶蠶變尸，燒蟻蟻成漏。", "呵吹一氣間，冷暖各成就。", "惡從汝心生，還從汝心受。"]'),
('abf68799-1d6b-4557-941c-532544d45264','擬寒山寺  其五四','釋懷深','宋','宋诗','song-poetry','','[]','池中養卻魚，岸上養卻鴨。',48,'全唐诗/poet.song.81000.json','["池中養卻魚，岸上養卻鴨。", "瘦者喂教肥，肥者便要殺。", "不思身債重，只要口甘滑。", "臘月三十日，看你成忉怛。"]'),
('d3e59473-83c5-46b0-b603-0897af4a3447','擬寒山寺  其五五','釋懷深','宋','宋诗','song-poetry','','[]','世上聰明人，必欲聞其過。',48,'全唐诗/poet.song.81000.json','["世上聰明人，必欲聞其過。", "不知是業牽，卻云合恁麽。", "因果鏡中容，容豈非是我。", "陰報最分明，不論官職大。"]'),
('c407230f-7b35-4627-8ee1-97b32b0a074c','擬寒山寺  其五六','釋懷深','宋','宋诗','song-poetry','','[]','口如無底谷，餔啖何時足。',48,'全唐诗/poet.song.81000.json','["口如無底谷，餔啖何時足。", "力未能長蔬，心且戒四肉。", "腥羶念有間，慈悲種漸熟。", "人生彈指間，少恣在明腹。"]'),
('ada0ee39-1d6f-406d-a52f-1f544e8002cf','擬寒山寺  其五七','釋懷深','宋','宋诗','song-poetry','','[]','世人黠是癡，忘身多爲口。',48,'全唐诗/poet.song.81000.json','["世人黠是癡，忘身多爲口。", "拚命喫河魨，忍臭餐石首。", "年年江浙間，藥殺十八九。", "自云直一死，佛亦不可救。"]'),
('ef136ac8-8f38-4129-b6a7-4d844b97aac7','擬寒山寺  其五八','釋懷深','宋','宋诗','song-poetry','','[]','自能持不殺，隨處多放生。',48,'全唐诗/poet.song.81000.json','["自能持不殺，隨處多放生。", "如人犯刑憲，墮落枷鎖坑。", "忽然身得脫，驚喜且悲鳴。", "含生皆怕死，何欲苦相烹。"]'),
('394babc6-e6c3-475c-afd1-775be42087c2','擬寒山寺  其五九','釋懷深','宋','宋诗','song-poetry','','[]','前世殺害多，今報夭折苦。',48,'全唐诗/poet.song.81000.json','["前世殺害多，今報夭折苦。", "方矜面如花，已見身歸土。", "哭倒白頭親，怨殺朱唇婦。", "因果鏡中形，毫髪無差悮。"]'),
('993eefd8-e82b-4085-9892-4d085986edcd','擬寒山寺  其六○','釋懷深','宋','宋诗','song-poetry','','[]','人間官法中，畜生殺無罪。',48,'全唐诗/poet.song.81000.json','["人間官法中，畜生殺無罪。", "朝烹與暮割，恬然不知悔。", "世法雖不理，冤債何時已。", "不見遂安公，五犬逼而死。"]'),
('c3820dc3-0d49-4c66-ac61-30ac3a3f3bf0','擬寒山寺  其六一','釋懷深','宋','宋诗','song-poetry','','[]','前世食肉多，今報疾病苦。',48,'全唐诗/poet.song.81000.json','["前世食肉多，今報疾病苦。", "針艾遍支體，呻吟徹朝暮。", "變醫雖有術，夙業豈能去。", "願君祈懺摩，刳心聽佛語。"]'),
('2e472b90-7e1c-49cf-b2f8-c82e876630cd','擬寒山寺  其六二','釋懷深','宋','宋诗','song-poetry','','[]','守口要如瓶，語言當自保。',48,'全唐诗/poet.song.81000.json','["守口要如瓶，語言當自保。", "多知多是非，少出少煩惱。", "東平樂爲善，司馬只稱好。", "相逢但寒溫，萬事皆默了。"]'),
('6cee3b38-30e2-486e-a357-3943cedf56f7','擬寒山寺  其六三','釋懷深','宋','宋诗','song-poetry','','[]','浮生類俳憂，但可付一笑。',48,'全唐诗/poet.song.81000.json','["浮生類俳憂，但可付一笑。", "做人復做馬，喫飯今喫草。", "富貴變貧窮，醜陋卻美好。", "不識主人公，去來三惡道。"]'),
('ad2cef33-9191-405a-8195-5010f056389d','擬寒山寺  其六四','釋懷深','宋','宋诗','song-poetry','','[]','人云我聰明，識盡天下理。',48,'全唐诗/poet.song.81000.json','["人云我聰明，識盡天下理。", "逐日弄精魂，長年鑽故紙。", "自家一個心，殊不知落地。", "及乎死到來，看你無巴鼻。"]'),
('e51db910-855e-4b99-8956-30328f585347','擬寒山寺  其六五','釋懷深','宋','宋诗','song-poetry','','[]','世人怕說死，說着死便諱。',48,'全唐诗/poet.song.81000.json','["世人怕說死，說着死便諱。", "及期死到來，老眼先垂淚。", "戀妻復戀妾，見神並見鬼。", "不入祖師門，癡迷直到底。"]'),
('649e8008-c7e6-438a-a5fa-a073abe6fa12','擬寒山寺  其六六','釋懷深','宋','宋诗','song-poetry','','[]','六十休造屋，七十莫置衣。',48,'全唐诗/poet.song.81000.json','["六十休造屋，七十莫置衣。", "縱然得受用，能得幾多時。", "身心要早歇，準擬與死期。", "正如人遠出，預辨者便宜。"]'),
('46757fca-624b-4b8b-925c-4462e0ce54b4','擬寒山寺  其六七','釋懷深','宋','宋诗','song-poetry','','[]','野鹿貪嗜草，忽中獵師箭。',48,'全唐诗/poet.song.81000.json','["野鹿貪嗜草，忽中獵師箭。", "老鼠翻飯盆，已落狸奴便。", "禍從貪上起，苦自愛中現。", "貪愛若不生，災害自然遠。"]'),
('9a65ca3e-32f5-42ea-ba4d-bb97e19c07fd','擬寒山寺  其六八','釋懷深','宋','宋诗','song-poetry','','[]','道力與福力，平時似亂真。',48,'全唐诗/poet.song.81000.json','["道力與福力，平時似亂真。", "福力有盛衰，道力無富貧。", "人生不學道，只種輪迴因。", "君看天福盡，滿眼生埃塵。"]'),
('ca4df540-14e1-443f-b54b-e137c95d9b1b','擬寒山寺  其六九','釋懷深','宋','宋诗','song-poetry','','[]','不貪以爲寶，日用無欠少。',48,'全唐诗/poet.song.81000.json','["不貪以爲寶，日用無欠少。", "一裘聊御寒，百味無過飽。", "堪嗟塵世人，經營長擾擾。", "衣底摩尼珠，光明都昧了。"]'),
('e3c55074-b655-4d58-a893-f4af8a559893','擬寒山寺  其七○','釋懷深','宋','宋诗','song-poetry','','[]','善惡生汝心，汝心宜早戢。',48,'全唐诗/poet.song.81000.json','["善惡生汝心，汝心宜早戢。", "鵝烹語告人，狗死魂猶泣。", "警誡甚分明，愚耳終不入。", "苦果一朝熟，恐君悔不及。"]'),
('832ef21a-f44b-4644-bafe-b3858d35060b','擬寒山寺  其七一','釋懷深','宋','宋诗','song-poetry','','[]','老翁死卻兒，晝夜搥胸哭。',48,'全唐诗/poet.song.81000.json','["老翁死卻兒，晝夜搥胸哭。", "痛心徹骨髓，叫云我孤獨。", "何不返思量，恣啖豬羊肉。", "羊豈不思兒，猪亦有眷屬。"]'),
('8f247a31-e3d7-42db-a528-d6c0819d31cd','擬寒山寺  其七二','釋懷深','宋','宋诗','song-poetry','','[]','惡人罵善人，善人總不對。',48,'全唐诗/poet.song.81000.json','["惡人罵善人，善人總不對。", "善人若還罵，彼此一智慧。", "不對心清涼，罵者口熱沸。", "正如人唾天，遷從己身墜。"]'),
('847e8e53-f676-4cae-b688-2f3863faf331','擬寒山寺  其七三','釋懷深','宋','宋诗','song-poetry','','[]','莫憂家未富，家富鬼神惡。',48,'全唐诗/poet.song.81000.json','["莫憂家未富，家富鬼神惡。", "莫憂官未穹，官穹朝市妬。", "多求災禍根，知足安樂處。", "君看權勢家，晝夜如騎虎。"]'),
('80d40a81-64d0-4ccf-9020-bb09fef71e62','擬寒山寺  其七四','釋懷深','宋','宋诗','song-poetry','','[]','一日日知衰，一年年覺老。',48,'全唐诗/poet.song.81000.json','["一日日知衰，一年年覺老。", "唯有貪愛心，頑然如壯少。", "臨行念子孫，垂死顧財寶。", "世間此等人，可哀不可吊。"]'),
('7939743a-c6be-4a2c-9d76-d8a6c952fada','擬寒山寺  其七五','釋懷深','宋','宋诗','song-poetry','','[]','衆生方寸間，貪量如海闊。',96,'全唐诗/poet.song.81000.json','["衆生方寸間，貪量如海闊。", "保持一個身，擬作千年活。", "金玉已滿堂，更欲相攘奪。", "至死少一官，令人冷笑發。", "小人妬君子，百計求全毀。", "自己醜惡聲，不知滿人耳。", "譬如蜣螂蟲，輥臭爲香美。", "卻笑鸞與鳳，不與己爲類。"]'),
('660cc05c-9438-4d79-a4cb-d9a6d1143c59','擬寒山寺  其七六','釋懷深','宋','宋诗','song-poetry','','[]','人身如假借，其勢豈能久。',48,'全唐诗/poet.song.81000.json','["人身如假借，其勢豈能久。", "鏡中兒時面，轉眄成老醜。", "安得閑日月，與人鬬棋酒。", "不能求放心，處處隨物走。"]'),
('c8ab2c23-3b57-40be-996a-08cbdbd02286','擬寒山寺  其七七','釋懷深','宋','宋诗','song-poetry','','[]','人身有一疾，呻吟徹眠夢。',48,'全唐诗/poet.song.81000.json','["人身有一疾，呻吟徹眠夢。", "買藥與呼醫，告佛仍設供。", "諸佛雖不語，愍汝顛倒重。", "殺羊食其心，何不念他痛。"]'),
('d5de75cd-b32b-4c3d-91a1-6334fff01bfd','擬寒山寺  其七八','釋懷深','宋','宋诗','song-poetry','','[]','世人無慈悲，恣情爲殺害。',48,'全唐诗/poet.song.81000.json','["世人無慈悲，恣情爲殺害。", "喫肉如大蟲，唯誇牙齒快。", "不念衆生苦，暢我個皮袋。", "皮袋暫時肥，須臾卻敗壞。"]'),
('3a426ec7-f120-4f83-af6b-b832d6bac72c','擬寒山寺  其七九','釋懷深','宋','宋诗','song-poetry','','[]','世事多不平，平者唯有死。',48,'全唐诗/poet.song.81000.json','["世事多不平，平者唯有死。", "死若更不平，貧漢何時已。", "朱樓高插雲，金带光照地。", "無常一日來，閻王誰管你。"]'),
('85d9b045-7415-4947-9db4-9595cbdb38c0','擬寒山寺  其八○','釋懷深','宋','宋诗','song-poetry','','[]','若以諍止諍，其諍轉不已。',48,'全唐诗/poet.song.81000.json','["若以諍止諍，其諍轉不已。", "唯忍能止諍，是法中尊貴。", "不見老瞿曇，妙相三十二。", "魔軍刀劍來，只以無心對。"]'),
('936f1807-ed16-4b38-9d06-124a7676727b','擬寒山寺  其八一','釋懷深','宋','宋诗','song-poetry','','[]','富甚足憂煩，貧甚多饑餓。',48,'全唐诗/poet.song.81000.json','["富甚足憂煩，貧甚多饑餓。", "要於貧富間，知足隨緣過。", "人生不知足，貪財是貪禍。", "黑暗功德天，尋常一處坐。"]'),
('d142486a-80bc-4200-b255-e2c3eb1afd2d','擬寒山寺  其八二','釋懷深','宋','宋诗','song-poetry','','[]','嗔火焚和氣，令人相貌惡。',48,'全唐诗/poet.song.81000.json','["嗔火焚和氣，令人相貌惡。", "修羅纔現前，菩薩都走卻。", "養就三毒軀，恣爲五慾樂。", "智者善思惟，早服慈悲藥。"]'),
('cd5926ab-6e3c-41d4-9f28-0d8de47ff4eb','擬寒山寺  其八三','釋懷深','宋','宋诗','song-poetry','','[]','心王不自明，便被六賊擾。',48,'全唐诗/poet.song.81000.json','["心王不自明，便被六賊擾。", "見色已昏迷，聞香即顛倒。", "功德與法財，盡底遭劫了。", "只因無慧力，貧窮三惡道。"]'),
('f75b77d9-f3cc-4854-a872-4e0fa40d6e04','擬寒山寺  其八四','釋懷深','宋','宋诗','song-poetry','','[]','世人皮底黠，肚裏沒頭癡。',48,'全唐诗/poet.song.81000.json','["世人皮底黠，肚裏沒頭癡。", "只取眼前樂，不憂身後非。", "眼前樂不久，身後苦多時。", "願君早爲計，後悔恐難追。"]'),
('f0a82ca0-8fd8-4d7d-845f-d334042100a7','擬寒山寺  其八五','釋懷深','宋','宋诗','song-poetry','','[]','求名趨於朝，求利入於市。',48,'全唐诗/poet.song.81000.json','["求名趨於朝，求利入於市。", "古今朝市間，相爭如鼎沸。", "不如歸山林，揩磨自心地。", "心地若分明，名利如唾涕。"]'),
('45414424-34c6-477a-a5b0-389b48a9b788','擬寒山寺  其八六','釋懷深','宋','宋诗','song-poetry','','[]','人身苟無業，生死何足疑。',48,'全唐诗/poet.song.81000.json','["人身苟無業，生死何足疑。", "生也不須戀，一亦不須悲。", "一身真逆旅，萬事皆兒嬉。", "請來綠巖畔，與君歌紫芝。"]'),
('5d64920c-d1ee-43d4-844f-ffd8619a2cf3','擬寒山寺  其八七','釋懷深','宋','宋诗','song-poetry','','[]','因果如影響，毫髮無差錯。',48,'全唐诗/poet.song.81000.json','["因果如影響，毫髮無差錯。", "啖炙僧腸穿，指熊樵臂落。", "獸面心有仁，人面心有惡。", "天地終不容，立見身消爍。"]'),
('085464ae-ef4f-4116-9f5f-ae835b4bb179','擬寒山寺  其八八','釋懷深','宋','宋诗','song-poetry','','[]','靜看營巢燕，銜泥日千轉。',48,'全唐诗/poet.song.81000.json','["靜看營巢燕，銜泥日千轉。", "一棲貧家梁，一宿王者殿。", "寄託暫時間，何暇分貴賤。", "人生達此理，沒齒無欣怨。"]'),
('4e4e5085-7714-4823-b271-1f69f61abaa2','擬寒山寺  其八九','釋懷深','宋','宋诗','song-poetry','','[]','貴人何所憂，所憂唯是老。',48,'全唐诗/poet.song.81000.json','["貴人何所憂，所憂唯是老。", "既老何所憂，憂見無常到。", "逢人問方術，閉門弄丹竈。", "此心若不歇，至死亦顛倒。"]'),
('b663656b-70cf-4892-a4be-37cf1d7d9fa8','擬寒山寺  其九○','釋懷深','宋','宋诗','song-poetry','','[]','可畏是輪迴，念念無停住。',48,'全唐诗/poet.song.81000.json','["可畏是輪迴，念念無停住。", "纔見出頭來，又見翻然去。", "換面與改頭，爲男或作女。", "不識主人翁，來去多辛苦。"]'),
('e9c26f85-62d8-400e-b8a4-985ba5e35a45','擬寒山寺  其九一','釋懷深','宋','宋诗','song-poetry','','[]','蠶忙貪作繭，蜂忙貪候蜜。',96,'全唐诗/poet.song.81000.json','["蠶忙貪作繭，蜂忙貪候蜜。", "繭成自己寒，蜜就別人食。", "世上憂家翁，辛苦無暫息。", "也似二蟲癡，於身無所得。", "三四小孩兒，爭拈百草嬉。", "懷中有梨栗，衣上汙塵泥。", "也似年高者，貪迷聲色時。", "世間無老少，總是一般癡。"]'),
('4957cf4c-b3db-45e0-8e59-408d80bfa122','擬寒山寺  其九二','釋懷深','宋','宋诗','song-poetry','','[]','貪嗔汝鑊湯，愚癡汝地獄。',48,'全唐诗/poet.song.81000.json','["貪嗔汝鑊湯，愚癡汝地獄。", "劍樹及刀山，汝心皆具足。", "要以智慧水，洗此無明毒。", "凡聖路無多，正如手翻覆。"]'),
('c06c2da1-3d5d-4a89-926f-0f8fc5622fc6','擬寒山寺  其九三','釋懷深','宋','宋诗','song-poetry','','[]','譬如臨明鏡，面目各相對。',48,'全唐诗/poet.song.81000.json','["譬如臨明鏡，面目各相對。", "好者默自欣，醜者默自愧。", "唯鏡兩無情，光明常一體。", "若人心似鏡，成佛在彈指。"]'),
('8b83719a-c0f5-412b-bc3b-9c72e8da5004','擬寒山寺  其九四','釋懷深','宋','宋诗','song-poetry','','[]','厚葬非孝心，死者必遭辱。',48,'全唐诗/poet.song.81000.json','["厚葬非孝心，死者必遭辱。", "君看離亂時，何墓不伐斸。", "黄金衆賊分，白日孤鬼哭。", "最愛老莊周，天地爲棺木。"]'),
('1dc5da11-6111-4238-b6fe-502bc9104f6c','擬寒山寺  其九五','釋懷深','宋','宋诗','song-poetry','','[]','屋可蔽風雨，何苦鬬華麗。',48,'全唐诗/poet.song.81000.json','["屋可蔽風雨，何苦鬬華麗。", "堯舜乃聖君，光宅天下被。", "茅茨未嘗剪，土階亦不砌。", "不知爾何人，鱗鱗居大第。"]'),
('2492314b-bf13-40fd-93ee-140e1d71f021','擬寒山寺  其九六','釋懷深','宋','宋诗','song-poetry','','[]','出家要省緣，省緣易入道。',48,'全唐诗/poet.song.81000.json','["出家要省緣，省緣易入道。", "如何無事人，摟攬閑煩惱。", "奔走富貴門，莊嚴房舍好。", "不知被物使，區區真到老。"]'),
('94f6ac07-a74f-4015-b058-8708409cde2b','擬寒山寺  其九七','釋懷深','宋','宋诗','song-poetry','','[]','傷嗟富貴家，殺害無虛日。',48,'全唐诗/poet.song.81000.json','["傷嗟富貴家，殺害無虛日。", "食羊割奶膀，烙鱉呼卒律。", "物有千般痛，汝無一念恤。", "福力忽然終，黄連猶是蜜。"]'),
('06e49f2e-d4fb-4859-9f9f-ae442c324fc0','擬寒山寺  其九八','釋懷深','宋','宋诗','song-poetry','','[]','浮生七十歲，二萬五千日。',48,'全唐诗/poet.song.81000.json','["浮生七十歲，二萬五千日。", "睡眠與疾病，光陰強半失。", "火急便回頭，寸陰誠可惜。", "嗟吁世人人，班白猶放逸。"]'),
('a2323695-8de6-47e1-926d-8b672275ae3f','擬寒山寺  其九九','釋懷深','宋','宋诗','song-poetry','','[]','世上貪饕漢，因財日夜煎。',48,'全唐诗/poet.song.81000.json','["世上貪饕漢，因財日夜煎。", "天公借與汝，看守七十年。", "譬如良田穀，春種秋方圓。", "不見張車子，生來便有錢。"]'),
('85ff70e8-8ff4-4c94-a3f2-085af5ad6993','擬寒山寺  其一○○','釋懷深','宋','宋诗','song-poetry','','[]','有福莫享盡，福盡身貧窮。',48,'全唐诗/poet.song.81000.json','["有福莫享盡，福盡身貧窮。", "有勢莫使盡，勢盡冤相逢。", "福兮常自惜，勢兮常自恭。", "人生驕與侈，有始多無終。"]'),
('06462e84-fc78-4a10-8637-3e89f09b8004','擬寒山寺  其一○一','釋懷深','宋','宋诗','song-poetry','','[]','自料七十歲，可期不可期。',48,'全唐诗/poet.song.81000.json','["自料七十歲，可期不可期。", "況今五六十，形骸日漸衰。", "正如春暮後，青多紅少時。", "去住呼吸間，佛言真不欺。"]'),
('475c3f1e-ce12-4631-9b3b-76fd39fec878','擬寒山寺  其一○二','釋懷深','宋','宋诗','song-poetry','','[]','我者被人罵，佯聾不分說。',48,'全唐诗/poet.song.81000.json','["我者被人罵，佯聾不分說。", "譬如火燒空，不救自然滅。", "嗔火亦如是，有物遭他爇。", "我心等虛空，聽你翻唇舌。"]'),
('b9fc9173-f502-4b34-a2c7-6cf891dd4740','擬寒山寺  其一○三','釋懷深','宋','宋诗','song-poetry','','[]','四大是假合，何況四大外。',48,'全唐诗/poet.song.81000.json','["四大是假合，何況四大外。", "假者是色身，外者是財賄。", "可憐世上人，說與終不會。", "相爭一文錢，費卻多少氣。"]'),
('94ab63d7-6831-4898-842f-15363a3b35fe','擬寒山寺  其一○四','釋懷深','宋','宋诗','song-poetry','','[]','人生被愛使，奔走如奴僕。',48,'全唐诗/poet.song.81000.json','["人生被愛使，奔走如奴僕。", "愛官被官牽，愛財被財畜。", "晝夜不曾閑，身心一暫足。", "佛云恩愛奴，斯言真可錄。"]'),
('bc85fd3e-9d9a-4353-a69b-01700ede1dee','擬寒山寺  其一○五','釋懷深','宋','宋诗','song-poetry','','[]','世人多放逸，極力事侈靡。',48,'全唐诗/poet.song.81000.json','["世人多放逸，極力事侈靡。", "樂極悲哀來，福盡貧窮至。", "天福尚有盡，世福豈一已。", "人多議論乖，享得是我底。"]'),
('8fa718ca-dcad-49ad-a061-fac71c4b73c8','擬寒山寺  其一○六','釋懷深','宋','宋诗','song-poetry','','[]','世人貪積財，受盡種種苦。',47,'全唐诗/poet.song.81000.json','["世人貪積財，受盡種種苦。", "求時多辛勤，守時足憂怖。", "散時哭休，死時戀不去。", "輪迴六趣中，只因爲物悮。"]'),
('bd7b114a-dd71-4935-83f8-c16cfb395694','擬寒山寺  其一○七','釋懷深','宋','宋诗','song-poetry','','[]','有恩念念報，報則合天道。',48,'全唐诗/poet.song.81000.json','["有恩念念報，報則合天道。", "有冤念念解，解則無煩惱。", "一身類浮雲，百年同過鳥。", "若以冤報冤，萬劫無由了。"]'),
('619d5dd0-ff6b-4499-a2de-1fedd75de470','擬寒山寺  其一○八','釋懷深','宋','宋诗','song-poetry','','[]','名湯並利火，古今燒殺人。',48,'全唐诗/poet.song.81000.json','["名湯並利火，古今燒殺人。", "只貪炙手熱，應笑甑生塵。", "虎口都忘險，龍鱗不怕嗔。", "利名心未足，衰老已及身。"]'),
('7a29d391-96f6-47d0-86ae-1706254f44d2','擬寒山寺  其一○九','釋懷深','宋','宋诗','song-poetry','','[]','可憐一等人，不善又不惡。',48,'全唐诗/poet.song.81000.json','["可憐一等人，不善又不惡。", "一邊說參禪，一邊取娛樂。", "貴得生死間，都不受寂寞。", "此云癡種子，要覓揚州鶴。"]'),
('8b14d865-0c4b-40b7-bb35-61d7ba8e9d1e','擬寒山寺  其一一○','釋懷深','宋','宋诗','song-poetry','','[]','人如食蘗蟲，通身總是苦。',48,'全唐诗/poet.song.81000.json','["人如食蘗蟲，通身總是苦。", "喫苦尚不休，抵死鑽頭做。", "古人知此味，念念求退步。", "樂道山林間，榮枯誰管汝。"]'),
('3a4728c1-c0fa-465f-904c-ce0ee7bab7a7','擬寒山寺  其一一一','釋懷深','宋','宋诗','song-poetry','','[]','有求皆是苦，衆生須要求。',49,'全唐诗/poet.song.81000.json','["有求皆是苦，衆生須要求。", "因名忘性命，爲手掌起戈矛。", "不足無時足，知休真下休。", "死生呼吸至，無人替汝愁。"]'),
('12370fcd-6f8f-43e2-82a2-546e97ac4614','擬寒山寺  其一一二','釋懷深','宋','宋诗','song-poetry','','[]','世上聰明公，癡心自蔽蒙。',48,'全唐诗/poet.song.81000.json','["世上聰明公，癡心自蔽蒙。", "步步常行有，口口只說空。", "既空無嗜慾，既空無窮通。", "因何臨財色，身心如轉蓬。"]'),
('66734830-cf63-4043-a57f-8064b52026a8','擬寒山寺  其一一三','釋懷深','宋','宋诗','song-poetry','','[]','衆生黠是癡，積惡望無過。',48,'全唐诗/poet.song.81000.json','["衆生黠是癡，積惡望無過。", "譬如顛倒人，尋覓無熱火。", "火則決定熱，惡則必招禍。", "勸君慎所積，有花終結果。"]'),
('80025a94-60c6-41cd-a087-af1bf97e6471','擬寒山寺  其一一四','釋懷深','宋','宋诗','song-poetry','','[]','一念染心生，撞入胞胎去。',48,'全唐诗/poet.song.81000.json','["一念染心生，撞入胞胎去。", "父精與母血，妄認爲住處。", "種子既不凈，臭氣相薫污。", "業風吹出來，萬苦從頭做。"]'),
('5ca85297-7295-4083-8f7d-4b82fb90ed55','擬寒山寺  其一一五','釋懷深','宋','宋诗','song-poetry','','[]','出家要清閑，卻被人使喚。',48,'全唐诗/poet.song.81000.json','["出家要清閑，卻被人使喚。", "門徒數百家，追陪日忙亂。", "施利得十千，人情費七貫。", "彼此沒便宜，他年難打算。"]'),
('1bb96546-ff3c-4087-bcfe-b8ac197fa353','擬寒山寺  其一一六','釋懷深','宋','宋诗','song-poetry','','[]','更有一般僧，因果殊不顧。',48,'全唐诗/poet.song.81000.json','["更有一般僧，因果殊不顧。", "心裏似屠沽，口中呵佛祖。", "心口不相應，佛祖豈容侮。", "投子與趙州，肯踏名利路。"]'),
('b191cd58-c37f-40dd-90a1-8b8bcd296c38','擬寒山寺  其一一七','釋懷深','宋','宋诗','song-poetry','','[]','池中一土墩，魚日繞墩轉。',48,'全唐诗/poet.song.81000.json','["池中一土墩，魚日繞墩轉。", "人觀咫尺間，魚謂千里遠。", "正如躁進人，分寸變眉面。", "要在張三前，還落李四便。"]'),
('7d5e223c-e197-4f7e-bbcd-4ccc37cf143d','擬寒山寺  其一一八','釋懷深','宋','宋诗','song-poetry','','[]','勸君莫嗜酒，嗜酒多過咎。',48,'全唐诗/poet.song.81000.json','["勸君莫嗜酒，嗜酒多過咎。", "不唯損汝福，亦乃夭汝壽。", "獨飲醉一夫，共飯飽十口。", "人生福幾何，饑貧恐在後。"]'),
('64f1f8c0-1072-492b-b97b-5592e10328f2','擬寒山寺  其一一九','釋懷深','宋','宋诗','song-poetry','','[]','世間一等漢，做盡百家冤。',48,'全唐诗/poet.song.81000.json','["世間一等漢，做盡百家冤。", "錐刀急利祿，尺寸競田園。", "世上若無死，塵中應更喧。", "勸君衣带上，分明書此言。"]'),
('9156ae2f-a6e5-43c5-a38c-284a1cf8349d','擬寒山寺  其一二○','釋懷深','宋','宋诗','song-poetry','','[]','僧家乃野人，何苦事迎迓。',48,'全唐诗/poet.song.81000.json','["僧家乃野人，何苦事迎迓。", "佛法變人情，真實成虛假。", "不見老趙州，禪床猶懶下。", "但願大王知，誰管都衙罵。"]'),
('f3a904f3-a41b-4e28-909e-22281b949738','擬寒山寺  其一二一','釋懷深','宋','宋诗','song-poetry','','[]','區區求富貴，求得一何用。',48,'全唐诗/poet.song.81000.json','["區區求富貴，求得一何用。", "前遮並後擁，假合成戲弄。", "正如夢南柯，妄認位貌重。", "忽然睡眼醒，始笑乾培奉。"]'),
('3a2f1c8e-d2fd-4885-a631-7c2078343cd3','擬寒山寺  其一二二','釋懷深','宋','宋诗','song-poetry','','[]','勸汝諦觀身，此身真可惡。',48,'全唐诗/poet.song.81000.json','["勸汝諦觀身，此身真可惡。", "上下九個孔，臭穢常流注。", "內外四條蛇，輕躁不停住。", "智者善思惟，莫被皮囊悮。"]'),
('5eff2cd2-bda2-4f7d-ba75-ca53ad18e747','擬寒山寺  其一二三','釋懷深','宋','宋诗','song-poetry','','[]','女色多瞞人，人惑總不見。',48,'全唐诗/poet.song.81000.json','["女色多瞞人，人惑總不見。", "龍麝暗薰衣，脂粉厚塗面。", "人呼爲牡丹，佛說是花箭。", "射人入骨髓，死而不知怨。"]'),
('7659b1c3-7b70-4a97-bf36-9f412dd46023','擬寒山寺  其一二四','釋懷深','宋','宋诗','song-poetry','','[]','人生如下棋，機巧未嘗已。',48,'全唐诗/poet.song.81000.json','["人生如下棋，機巧未嘗已。", "劫劫只圖生，忙忙惟怕死。", "路頭既錯了，心眼亦虛棄。", "不薦這一着，對面若千里。"]'),
('3012880c-97ba-493a-b665-e275152cdcec','擬寒山寺  其一二五','釋懷深','宋','宋诗','song-poetry','','[]','白日鬧喧喧，夜間靜悄悄。',49,'全唐诗/poet.song.81000.json','["白日鬧喧喧，夜間靜悄悄。", "夜夜間與白日，且道誰欠少。", "饑時覓飯噇，困便尋床倒。", "不省這個意，區區直到老。"]'),
('5de1d2c9-f2f2-410a-a55b-6cb489c93d75','擬寒山寺  其一二六','釋懷深','宋','宋诗','song-poetry','','[]','往事莫追尋，未來莫希望。',48,'全唐诗/poet.song.81000.json','["往事莫追尋，未來莫希望。", "見在休執着，自然心坦蕩。", "有心終不堪，無念以爲上。", "君看太虛空，何嘗有遮障。"]'),
('bac21dc6-60f5-44e0-b3bb-8de79dabbe97','擬寒山寺  其一二七','釋懷深','宋','宋诗','song-poetry','','[]','莫嫌門戶少，轉富轉心勞。',48,'全唐诗/poet.song.81000.json','["莫嫌門戶少，轉富轉心勞。", "夜怕奸偷至，時防風火燒。", "名高招謗重，財積致讒饒。", "外物多爲累，令人思許巢。"]'),
('a32ec26b-dc85-4f74-8cbc-555628b5ddb3','擬寒山寺  其一二八','釋懷深','宋','宋诗','song-poetry','','[]','麝爲香而死，龜以靈故焦。',48,'全唐诗/poet.song.81000.json','["麝爲香而死，龜以靈故焦。", "既爲世所用，憂患無門逃。", "名高謗之本，財聚禍之苗。", "三怨粗能免，世無孫叔敖。"]'),
('0b8b739b-1fb0-447f-a584-d255838f73ca','擬寒山寺  其一二九','釋懷深','宋','宋诗','song-poetry','','[]','日暮片雲愁，邊廷戰未休。',48,'全唐诗/poet.song.81000.json','["日暮片雲愁，邊廷戰未休。", "萬人齊拚命，一將獨封侯。", "孫武子兵法，田將軍火牛。", "算來成底事，總是百冤頭。"]'),
('c0f2baca-8116-40bb-9dfa-f1e5048c20c8','擬寒山寺  其一三○','釋懷深','宋','宋诗','song-poetry','','[]','合嗔不須嗔，合喜不須喜。',48,'全唐诗/poet.song.81000.json','["合嗔不須嗔，合喜不須喜。", "喜時風自吹，嗔時火自熾。", "風火非外來，皆從自心起。", "不見四禪天，三災都不至。"]'),
('149b35ce-2275-4e54-9f87-7db371ba99c9','擬寒山寺  其一三一','釋懷深','宋','宋诗','song-poetry','','[]','不栽一株桑，不種一粒粟。',48,'全唐诗/poet.song.81000.json','["不栽一株桑，不種一粒粟。", "口體每輕肥，倉庫常滿足。", "蓬門漏不蔽，你居大華屋。", "常懷知愧心，少恣無明慾。"]'),
('8ff86663-06eb-4c62-9364-ab3fb1c9cafa','擬寒山寺  其一三二','釋懷深','宋','宋诗','song-poetry','','[]','一鼠變蝙蝠，羣鼠相慶賀。',48,'全唐诗/poet.song.81000.json','["一鼠變蝙蝠，羣鼠相慶賀。", "飛鳴覺身輕，自喜脫貓禍。", "日中不見物，夜裏長忍餓。", "不如做鼠時，窟裏飽眠臥。"]'),
('8dd5e1ea-7522-427b-aa5f-90eb5c896d81','擬寒山寺  其一三三','釋懷深','宋','宋诗','song-poetry','','[]','貧窮難作福，富貴易造罪。',48,'全唐诗/poet.song.81000.json','["貧窮難作福，富貴易造罪。", "有力無道心，有心無財賄。", "有福有道心，百中無一二。", "不見老瞿曇，福慧二嚴美。"]'),
('31e2ea93-05f9-47c9-bfc4-f57c04ad3852','擬寒山寺  其一三四','釋懷深','宋','宋诗','song-poetry','','[]','佛爲大醫王，留經治衆病。',48,'全唐诗/poet.song.81000.json','["佛爲大醫王，留經治衆病。", "衆生雖讀經，展轉不相應。", "病是貪嗔癡，掃除愛凈盡。", "貪嗔癡不除，無緣了真性。"]'),
('8dcd82fb-0719-496a-9dbc-4ccd831f2725','擬寒山寺  其一三五','釋懷深','宋','宋诗','song-poetry','','[]','貪夫如撲滿，不慮滿時禍。',48,'全唐诗/poet.song.81000.json','["貪夫如撲滿，不慮滿時禍。", "未盈猶可存，已滿終歸破。", "君看石齊奴，不義蓄財貨。", "喫劍爲綠珠，至死不知過。"]'),
('ecb8fb67-0929-40e2-9abb-72b02723713e','擬寒山寺  其一三六','釋懷深','宋','宋诗','song-poetry','','[]','奸漢瞞淳漢，淳漢總不知。',48,'全唐诗/poet.song.81000.json','["奸漢瞞淳漢，淳漢總不知。", "奸漢作驢子，卻被淳漢騎。", "當時誇好手，今日落便宜。", "圖他些子利，披卻畜生皮。"]'),
('6289bc71-570a-4501-9f21-d2e81efca41a','擬寒山寺  其一三七','釋懷深','宋','宋诗','song-poetry','','[]','君看轉輪王，七寶光中坐。',48,'全唐诗/poet.song.81000.json','["君看轉輪王，七寶光中坐。", "一朝福力盡，頭上花冠破。", "正如箭射空，勢盡還退墮。", "升沉無數劫，只因迷者個。"]'),
('a7bf28e2-6ef0-439d-ab24-7ac175d9cb18','擬寒山寺  其一三八','釋懷深','宋','宋诗','song-poetry','','[]','不必揚人惡，切忌伐己善。',48,'全唐诗/poet.song.81000.json','["不必揚人惡，切忌伐己善。", "行人口似碑，好醜悉皆見。", "祿厚恐禍生，言深慮交淺。", "不如省事休，彼此無欣怨。"]'),
('b8998441-9c56-4b4b-9ba1-d0b024602075','擬寒山寺  其一三九','釋懷深','宋','宋诗','song-poetry','','[]','君看草頭露，日出還消去。',48,'全唐诗/poet.song.81000.json','["君看草頭露，日出還消去。", "也似世間人，閻浮暫時住。", "愚人尚不知，紛爭求貴富。", "只應明眼人，未能笑得汝。"]'),
('eab661f5-7421-4a4d-800a-5f8895e7c08c','擬寒山寺  其一四○','釋懷深','宋','宋诗','song-poetry','','[]','人生不滿百，常懷千歲憂。',48,'全唐诗/poet.song.81000.json','["人生不滿百，常懷千歲憂。", "猶嫌金玉少，更爲子孫求。", "白日曉還黑，綠楊春復秋。", "無過富與貴，不奈水東流。"]');
